  "description": "A cyberpunk-themed AI terminal interface featuring Frost Blade, Eternal Core, and Land Vessel engines powered by Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useEffect, useState } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import { Landing } from './pages/Landing';
import { Chat } from './pages/Chat';
import { RecentChat } from './pages/RecentChat';
import { ThemeContext } from './constants';

const AppContent: React.FC = () => {
  return (
    <Routes>
      <Route path="/" element={<Landing />} />
      <Route path="/terminal" element={<Chat />} />
      <Route path="/recent_chat" element={<RecentChat />} />
    </Routes>
  );
};

export default function App() {
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as 'dark' | 'light' || 'dark';
    setTheme(savedTheme);
    if (savedTheme === 'dark') {
      document.documentElement.classList.add('dark');
      document.documentElement.setAttribute('data-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      document.documentElement.setAttribute('data-theme', 'light');
    }
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    if (newTheme === 'dark') {
      document.documentElement.classList.add('dark');
      document.documentElement.setAttribute('data-theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      document.documentElement.setAttribute('data-theme', 'light');
    }
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <Router>
        <AppContent />
      </Router>
    </ThemeContext.Provider>
  );
}

export enum EngineType {
  FROST_BLADE = 'frost_blade', // Fast -> gemini-3-flash-preview
  ETERNAL_CORE = 'eternal_core', // Deep -> gemini-3-pro-preview
  LAND_VESSEL = 'land_vessel', // Stable Module -> gemini-3-flash-preview (custom instruction)
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  engine?: EngineType;
}

export interface ThemeContextType {
  theme: 'dark' | 'light';
  toggleTheme: () => void;
}

import { createContext } from 'react';
import { ThemeContextType, EngineType } from './types';

export const ThemeContext = createContext<ThemeContextType>({
  theme: 'dark',
  toggleTheme: () => {},
});

export const ENGINE_CONFIG = {
  [EngineType.FROST_BLADE]: {
    name: '寒霜之刃 (Fast)',
    model: 'gemini-3-flash-preview',
    description: '轻量、迅捷',
  },
  [EngineType.ETERNAL_CORE]: {
    name: '永冬核心 (Pro)',
    model: 'gemini-3-pro-preview',
    description: '深邃、强力',
  },
  [EngineType.LAND_VESSEL]: {
    name: '陆上行舟 (Module)',
    model: 'gemini-3-flash-preview', // Using Flash for reliability/speed but conceptually different
    description: '稳健、长效',
  },
};

export const INITIAL_SYSTEM_INSTRUCTION = "You are Cai Bao (菜包), a terminal-based AI assistant. Your responses should be helpful, concise, and fit the cyberpunk/terminal aesthetic where appropriate.";

export const LANDING_TYPEWRITER_TEXT = "检测到寒霜信号...模组重载中...系统已就绪 ❄️";

import { GoogleGenAI } from "@google/genai";
import { EngineType } from '../types';
import { ENGINE_CONFIG, INITIAL_SYSTEM_INSTRUCTION } from '../constants';

// Initialize the client. API Key is expected to be in environment variables.
// If process.env.API_KEY is not set, this will fail gracefully when called.
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const streamChatResponse = async (
  message: string,
  engine: EngineType,
  history: { role: 'user' | 'model'; parts: { text: string }[] }[]
) => {
  const modelName = ENGINE_CONFIG[engine].model;

  // Custom system instruction adjustment based on engine "personality"
  let systemInstruction = INITIAL_SYSTEM_INSTRUCTION;
  if (engine === EngineType.ETERNAL_CORE) {
    systemInstruction += " You are in Eternal Core mode: providing deep, detailed, and highly reasoned answers.";
  } else if (engine === EngineType.LAND_VESSEL) {
    systemInstruction += " You are in Land Vessel mode: prioritize stability, robustness, and practical, safe advice.";
  } else {
    systemInstruction += " You are in Frost Blade mode: be quick, precise, and efficient.";
  }

  try {
    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction: systemInstruction,
      },
      history: history,
    });

    const result = await chat.sendMessageStream({ message });
    return result;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import { ChatMessage } from '../types';

const STORAGE_KEY = 'caibao_history';

export const getHistory = (): ChatMessage[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    console.error("Failed to parse history", e);
    return [];
  }
};

export const addMessageToHistory = (message: ChatMessage) => {
  const history = getHistory();
  history.push(message);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
};

export const clearHistory = () => {
  localStorage.removeItem(STORAGE_KEY);
};

import React, { useEffect, useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { ThemeContext } from '../constants';
