export const Landing: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [displayText, setDisplayText] = useState('');

  useEffect(() => {
    let index = 0;
    const timer = setInterval(() => {
      if (index < LANDING_TYPEWRITER_TEXT.length) {
        setDisplayText((prev) => prev + LANDING_TYPEWRITER_TEXT.charAt(index));
        index++;
      } else {
        clearInterval(timer);
      }
    }, 60);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="relative w-full h-screen flex flex-col justify-center items-center overflow-hidden font-sans bg-bg-body text-text-primary transition-colors duration-300">
       {/* Grid Background */}
