      {/* Theme Toggle */}
      <button 
        onClick={toggleTheme}
        className="absolute top-5 right-8 bg-none border-none text-text-secondary text-2xl cursor-pointer z-10 hover:text-accent transition-colors duration-300"
        title="切换主题"
      >
        <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
      </button>

      <div className="container relative z-10 text-center animate-[fadeInUp_1s_ease-out]">
        <h1 className="text-7xl md:text-8xl lg:text-9xl mb-2 font-semibold tracking-widest bg-clip-text text-transparent bg-gradient-to-br from-white to-accent dark:from-white dark:to-accent filter drop-shadow-[0_0_25px_rgba(88,166,255,0.4)] dark:filter-none light:drop-shadow-[0_5px_10px_rgba(0,0,0,0.1)]">
