          className="inline-block px-12 py-4 text-xl bg-[rgba(88,166,255,0.05)] dark:bg-[rgba(88,166,255,0.05)] light:bg-[#f6f8fa] text-accent border border-accent rounded hover:bg-accent hover:text-bg-body dark:hover:text-bg-body light:hover:text-white shadow-none hover:shadow-neon transition-all duration-300 tracking-wider no-underline"
