import React, { useState, useEffect, useRef, useContext } from 'react';
import { Link } from 'react-router-dom';
import { EngineType, ChatMessage } from '../types';
import { ThemeContext, ENGINE_CONFIG } from '../constants';
import { streamChatResponse } from '../services/geminiService';
import { addMessageToHistory } from '../services/storageService';
import { GenerateContentResponse } from '@google/genai';

export const Chat: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [engine, setEngine] = useState<EngineType>(EngineType.FROST_BLADE);
  const [messages, setMessages] = useState<ChatMessage[]>([{
    id: 'init',
    role: 'model',
    content: '系统就绪。',
    timestamp: Date.now()
  }]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logic
  const scrollToBottom = (behavior: ScrollBehavior = 'smooth') => {
    messagesEndRef.current?.scrollIntoView({ behavior, block: 'end' });
  };

  const smartScrollToBottom = () => {
    if (!chatContainerRef.current) return;
    const { scrollHeight, scrollTop, clientHeight } = chatContainerRef.current;
    // Threshold to determine if user is near bottom
    const threshold = 150; 
    const isNearBottom = scrollHeight - scrollTop - clientHeight <= threshold;

    if (isNearBottom) {
      chatContainerRef.current.scrollTop = scrollHeight;
    }
  };

  useEffect(() => {
    // Initial scroll
    scrollToBottom('auto');
  }, []);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsgText = input.trim();
    setInput('');

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: userMsgText,
      timestamp: Date.now(),
      engine
    };

    setMessages(prev => [...prev, userMsg]);
    addMessageToHistory(userMsg);

    // Force scroll on user send
    setTimeout(() => scrollToBottom(), 100);

    setIsLoading(true);
    const botMsgId = (Date.now() + 1).toString();

    // Optimistic bot message (empty initially)
    setMessages(prev => [...prev, {
      id: botMsgId,
      role: 'model',
      content: '', // Will stream into this
      timestamp: Date.now(),
      engine
    }]);

    try {
      // Prepare history for API (excluding the current user message to avoid duplication if API handles it, 
      // but Gemini chat history usually needs past turns. We'll filter current state)
      const apiHistory = messages.filter(m => m.id !== 'init').map(m => ({
        role: m.role,
        parts: [{ text: m.content }]
      }));

      const stream = await streamChatResponse(userMsgText, engine, apiHistory);

      let fullContent = '';

      for await (const chunk of stream) {
        const contentChunk = (chunk as GenerateContentResponse).text || '';
        fullContent += contentChunk;

        setMessages(prev => prev.map(msg => 
          msg.id === botMsgId 
            ? { ...msg, content: fullContent } 
            : msg
        ));
        smartScrollToBottom();
      }

      // Save complete bot message
      addMessageToHistory({
        id: botMsgId,
        role: 'model',
        content: fullContent,
        timestamp: Date.now(),
        engine
      });

    } catch (error) {
      console.error(error);
      setMessages(prev => prev.map(msg => 
        msg.id === botMsgId 
          ? { ...msg, content: '系统繁忙，请检查 API 密钥或稍后再试。' } 
          : msg
      ));
      addMessageToHistory({
        id: botMsgId,
        role: 'model',
        content: 'System Error: Connection failed.',
        timestamp: Date.now(),
        engine
      });
    } finally {
      setIsLoading(false);
      smartScrollToBottom();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-screen bg-bg-body text-text-primary transition-colors duration-300 font-sans">
      {/* Top Bar */}
      <div className="absolute top-0 left-0 w-full px-8 py-3 flex justify-between items-center bg-header-bg/95 backdrop-blur-md z-10 border-b border-border transition-colors duration-300">
        <div className="flex items-center gap-5">
          <div className="font-semibold text-xl tracking-wider text-text-primary">菜 包</div>
          <div className="relative group">
            <select 
              value={engine} 
              onChange={(e) => setEngine(e.target.value as EngineType)}
              className="appearance-none bg-transparent border border-accent text-accent py-2 pl-4 pr-8 rounded font-sans text-sm cursor-pointer hover:shadow-neon hover:bg-accent/5 transition-all duration-300 focus:outline-none"
              style={{
                backgroundImage: `url("data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23${theme === 'light' ? '0969da' : '58a6ff'}%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E")`,
                backgroundRepeat: 'no-repeat',
                backgroundPosition: 'right 10px center',
                backgroundSize: '10px'
              }}
            >
              {Object.entries(ENGINE_CONFIG).map(([key, config]) => (
                <option key={key} value={key} className="bg-bg-body text-text-primary">
                  {config.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={toggleTheme} className="w-10 h-10 flex items-center justify-center text-text-secondary hover:text-accent transition-colors text-lg" title="切换主题">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <Link to="/recent_chat" className="w-10 h-10 flex items-center justify-center text-text-secondary hover:text-accent transition-colors text-lg" title="系统交互日志">
            <i className="fas fa-history"></i>
          </Link>
        </div>
      </div>

      {/* Chat Messages */}
      <div className="w-full max-w-[900px] flex flex-col h-full mx-auto pt-[70px] box-border">
        <div 
          ref={chatContainerRef}
          className="flex-1 overflow-y-auto p-5 flex flex-col gap-5 scroll-smooth"
        >
          {messages.map((msg) => (
            <div key={msg.id} className={`flex gap-4 max-w-[85%] ${msg.role === 'user' ? 'self-end flex-row-reverse' : ''}`}>
              <div className={`w-[38px] h-[38px] rounded flex items-center justify-center shrink-0 ${
                msg.role === 'model' 
                  ? 'bg-bg-input border border-border text-accent' 
                  : 'bg-accent text-accent-bg'
              }`}>
                <i className={`fas ${msg.role === 'model' ? 'fa-terminal' : 'fa-user'}`}></i>
              </div>
              <div className={`p-3 px-5 rounded-lg leading-relaxed break-words text-[0.95rem] ${
                msg.role === 'model'
                  ? 'bg-bg-chat border border-border min-h-[20px]'
                  : 'bg-accent text-accent-bg font-medium'
              }`}>
                {msg.content}
                {msg.role === 'model' && msg.content === '' && isLoading && (
                  <span className="typing-cursor"></span>
                )}
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} className="h-px w-full"></div>
        </div>

        {/* Input Area */}
        <div className="p-5 bg-bg-body transition-colors duration-300">
          <div className="bg-bg-input border border-border rounded px-4 py-2 flex items-center transition-colors duration-300 focus-within:border-accent">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="您好，请向菜包提问..." 
              className="flex-1 bg-transparent border-none text-text-primary p-3 outline-none font-sans"
              autoComplete="off"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className={`bg-none border-none text-text-secondary cursor-pointer text-lg hover:text-accent disabled:opacity-50 disabled:cursor-not-allowed`}
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { ThemeContext } from '../constants';
import { getHistory, clearHistory } from '../services/storageService';
import { ChatMessage } from '../types';

export const RecentChat: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [history, setHistory] = useState<ChatMessage[]>([]);

  useEffect(() => {
    setHistory(getHistory().reverse());
  }, []);

  const handleClear = () => {
    if (window.confirm("确定清除所有日志吗？")) {
      clearHistory();
      setHistory([]);
    }
  };

  const formatMessage = (msg: ChatMessage) => {
    const roleSpan = msg.role === 'user' 
      ? `<span class="text-accent font-bold">用户:</span>` 
      : `<span class="text-[#3fb950] font-bold">菜包:</span>`;
    return { __html: `${roleSpan} ${msg.content}` };
  };

  return (
    <div className="flex flex-col items-center min-h-screen bg-bg-body text-text-main p-5 font-sans transition-colors duration-300">
      <header className="w-full max-w-[850px] pb-5 flex justify-between items-center border-b border-border mb-8 transition-colors duration-300">
        <h1 className="m-0 text-2xl font-semibold text-text-primary">系统交互日志</h1>
        <div className="flex items-center gap-3">
          <button 
            onClick={toggleTheme}
            className="w-[38px] h-[38px] flex items-center justify-center bg-transparent border border-border text-text-secondary rounded hover:text-accent hover:border-accent transition-all duration-200 cursor-pointer text-lg"
            title="切换主题"
          >
             <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <button 
            onClick={handleClear}
            className="h-[38px] px-5 flex items-center justify-center bg-[rgba(248,81,73,0.05)] border border-accent-red text-accent-red rounded hover:bg-accent-red hover:text-white hover:shadow-[0_0_10px_rgba(248,81,73,0.3)] transition-all duration-200 cursor-pointer text-sm"
          >
            <i className="fas fa-trash mr-2"></i>清除记录
          </button>
          <Link 
            to="/terminal" 
            className="w-[38px] h-[38px] flex items-center justify-center bg-transparent border border-border text-text-secondary rounded hover:text-accent hover:border-accent transition-all duration-200 cursor-pointer text-lg no-underline"
            title="返回终端"
          >
            <i className="fas fa-arrow-left"></i>
          </Link>
        </div>
      </header>

      <div className="w-full max-w-[850px]">
        {history.length === 0 ? (
          <div className="text-center text-text-secondary italic">暂无交互记录</div>
        ) : (
          history.map((msg, index) => (
            <div 
              key={msg.id + index}
              className={`bg-bg-chat border border-border mb-3 p-4 rounded text-sm font-mono leading-relaxed whitespace-pre-wrap transition-colors duration-300 border-l-4 ${
                msg.role === 'user' ? 'border-l-accent' : 'border-l-[#3fb950]'
              }`}
            >
               <div dangerouslySetInnerHTML={formatMessage(msg)} />
               <div className="text-xs text-text-secondary mt-2 opacity-50">
                 {new Date(msg.timestamp).toLocaleString()} {msg.engine ? `[${msg.engine}]` : ''}
               </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

