import React, { useState, useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION } from '../constants';
import { GenerateContentResponse } from '@google/genai';

export const Office: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'model', content: string}[]>([
    { role: 'model', content: '您好，灵境办公助手已就绪。请上传会议录音或输入指令。' }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: OFFICE_SYSTEM_INSTRUCTION },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.content }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        const text = (chunk as GenerateContentResponse).text || '';
        fullText += text;
        setMessages(prev => {
          const newArr = [...prev];
          newArr[newArr.length - 1].content = fullText;
          return newArr;
        });
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', content: '网络连接异常，请重试。' }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const QuickAction = ({ icon, label, prompt }: { icon: string, label: string, prompt: string }) => (
    <button 
      onClick={() => { setInput(prompt); }}
      className="flex flex-col items-center justify-center p-4 bg-white rounded-xl shadow-card hover:shadow-soft transition-all duration-200 border border-gray-100 hover:border-office-primary/30"
    >
      <div className="w-10 h-10 rounded-full bg-office-accent flex items-center justify-center text-office-primary mb-2 text-lg">
        <i className={`fas ${icon}`}></i>
      </div>
      <span className="text-xs text-office-text font-medium">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-office-bg font-sans text-office-text">
      {/* Header */}
      <div className="bg-white px-6 py-4 flex justify-between items-center shadow-sm z-10">
        <div className="flex items-center gap-4">
          <Link to="/" className="text-gray-400 hover:text-office-primary transition-colors"><i className="fas fa-th-large"></i></Link>
          <h1 className="text-lg font-bold tracking-wide">灵境 <span className="text-office-primary font-light">| 办公</span></h1>
        </div>
        <div className="w-8 h-8 rounded-full bg-office-primary text-white flex items-center justify-center text-xs">OA</div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col max-w-4xl w-full mx-auto p-4 overflow-hidden">

        {/* Quick Actions Panel */}
        {messages.length < 3 && (
          <div className="grid grid-cols-4 gap-4 mb-6 animate-[fadeInUp_0.5s_ease-out]">
            <QuickAction icon="fa-microphone-alt" label="会议转写" prompt="请模拟一段会议录音的转写，并整理成结构化的会议纪要，包含待办事项。" />
            <QuickAction icon="fa-file-powerpoint" label="一键PPT" prompt="请为我生成一份关于“2025年AI应用趋势”的PPT大纲，共5页，包含视觉建议。" />
            <QuickAction icon="fa-tasks" label="任务编排" prompt="我有以下任务：周三交报告，明天下午开会，周五团建。请帮我生成本周日程表。" />
            <QuickAction icon="fa-calendar-check" label="日程同步" prompt="检查我的日历冲突..." />
          </div>
        )}

        {/* Chat Area */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto mb-4 space-y-4 pr-2">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-office-primary text-white rounded-br-none' 
                  : 'bg-white text-gray-700 border border-gray-100 rounded-bl-none'
              }`}>
                {msg.role === 'model' && !msg.content ? <span className="typing-cursor"></span> : <div className="whitespace-pre-wrap">{msg.content}</div>}
              </div>
            </div>
          ))}
        </div>

        {/* Input */}
        <div className="bg-white p-2 rounded-2xl shadow-soft border border-gray-100 flex items-center gap-2">
          <button className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-office-primary rounded-full hover:bg-gray-50 transition-colors">
            <i className="fas fa-plus"></i>
          </button>
          <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="输入指令或上传文件..."
            className="flex-1 bg-transparent border-none outline-none text-sm p-2"
            disabled={isProcessing}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isProcessing}
            className={`px-6 py-2 rounded-xl text-sm font-medium transition-all ${
              input.trim() ? 'bg-office-primary text-white shadow-md' : 'bg-gray-100 text-gray-400'
            }`}
          >
            发送
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
