import React, { useState, useEffect, useRef, useContext } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { EngineType, ChatMessage, SquadMember } from '../types';
import { ThemeContext, ENGINE_CONFIG } from '../constants';
import { streamChatResponse } from '../services/geminiService';
import { addMessageToHistory } from '../services/storageService';
import { GenerateContentResponse } from '@google/genai';

export const Chat: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const location = useLocation();
  const [engine, setEngine] = useState<EngineType>(EngineType.FROST_BLADE);

  // State for Squad Persona
  const [squadMember, setSquadMember] = useState<SquadMember | null>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Removed forced dark mode to respect global theme

  // Initialize from location state
  useEffect(() => {
    const state = location.state as { initialEngine?: EngineType; squadMember?: SquadMember };

    if (state?.squadMember) {
      setSquadMember(state.squadMember);
      setEngine(state.squadMember.engine);
      setMessages([{
        id: 'init',
        role: 'model',
        content: `已建立加密连接。我是 ${state.squadMember.codename}。请指示。`,
        timestamp: Date.now(),
        senderName: state.squadMember.codename
      }]);
    } else if (state?.initialEngine) {
      setEngine(state.initialEngine);
      setMessages([{
        id: 'init',
        role: 'model',
        content: `系统就绪。引擎已锁定: ${ENGINE_CONFIG[state.initialEngine].name}。`,
        timestamp: Date.now()
      }]);
    } else {
      setMessages([{
        id: 'init',
        role: 'model',
        content: '系统就绪。',
        timestamp: Date.now()
      }]);
    }
  }, [location.state]);

  // Auto-scroll logic
  const scrollToBottom = (behavior: ScrollBehavior = 'smooth') => {
    messagesEndRef.current?.scrollIntoView({ behavior, block: 'end' });
  };

  const smartScrollToBottom = () => {
    if (!chatContainerRef.current) return;
    const { scrollHeight, scrollTop, clientHeight } = chatContainerRef.current;
    const threshold = 150; 
    const isNearBottom = scrollHeight - scrollTop - clientHeight <= threshold;

    if (isNearBottom) {
      chatContainerRef.current.scrollTop = scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom('auto');
  }, [messages.length]); // Scroll on message add

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMsgText = input.trim();
    setInput('');

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: userMsgText,
      timestamp: Date.now(),
      engine
    };

    setMessages(prev => [...prev, userMsg]);
    addMessageToHistory(userMsg);

    setTimeout(() => scrollToBottom(), 100);

    setIsLoading(true);
    const botMsgId = (Date.now() + 1).toString();

    // Optimistic bot message
    setMessages(prev => [...prev, {
      id: botMsgId,
      role: 'model',
      content: '',
      timestamp: Date.now(),
      engine,
      senderName: squadMember ? squadMember.codename : undefined
    }]);

    try {
      const apiHistory = messages.filter(m => m.id !== 'init').map(m => ({
        role: m.role,
        parts: [{ text: m.content }]
      }));

      // Pass custom system instruction if in Squad mode
      const stream = await streamChatResponse(
        userMsgText, 
        engine, 
        apiHistory, 
        squadMember?.systemInstruction
      );

      let fullContent = '';

      for await (const chunk of stream) {
        const contentChunk = (chunk as GenerateContentResponse).text || '';
        fullContent += contentChunk;

        setMessages(prev => prev.map(msg => 
          msg.id === botMsgId 
            ? { ...msg, content: fullContent } 
            : msg
        ));
        smartScrollToBottom();
      }

      addMessageToHistory({
        id: botMsgId,
        role: 'model',
        content: fullContent,
        timestamp: Date.now(),
        engine,
        senderName: squadMember ? squadMember.codename : undefined
      });

    } catch (error) {
      console.error(error);
      setMessages(prev => prev.map(msg => 
        msg.id === botMsgId 
          ? { ...msg, content: '连接断开。信号丢失。' } 
          : msg
      ));
    } finally {
      setIsLoading(false);
      smartScrollToBottom();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Determine accent color style based on squad member
  const headerStyle = squadMember ? { borderColor: squadMember.themeColor } : {};
  const iconStyle = squadMember ? { color: squadMember.themeColor } : {};

  return (
    <div className="flex flex-col h-screen bg-cb-bg text-cb-text transition-colors duration-300 font-sans">
      {/* Top Bar */}
      <div 
        className="absolute top-0 left-0 w-full px-8 py-3 flex justify-between items-center bg-cb-bg-body/95 backdrop-blur-md z-10 border-b border-cb-border transition-colors duration-300"
        style={squadMember ? { borderBottomColor: `${squadMember.themeColor}50` } : {}}
      >
        <div className="flex items-center gap-5">
           <Link 
            to="/caibao" 
            className="w-8 h-8 flex items-center justify-center text-cb-sub hover:text-cb-accent transition-colors"
            title="返回菜包首页"
          >
            <i className="fas fa-chevron-left"></i>
          </Link>

          {squadMember ? (
            <div className="flex items-center gap-3">
               <span className="font-bold text-xl tracking-wider" style={{ color: squadMember.themeColor }}>
                 {squadMember.codename}
               </span>
               <span className="text-xs border px-1 rounded uppercase font-mono" style={{ borderColor: squadMember.themeColor, color: squadMember.themeColor }}>
                 SECURE CHANNEL
               </span>
            </div>
          ) : (
            <>
              <div className="font-semibold text-xl tracking-wider text-cb-text">菜 包</div>
              <div className="relative group">
                <select 
                  value={engine} 
                  onChange={(e) => setEngine(e.target.value as EngineType)}
                  className="appearance-none bg-transparent border border-cb-accent text-cb-accent py-2 pl-4 pr-8 rounded font-sans text-sm cursor-pointer hover:shadow-neon hover:bg-cb-accent/5 transition-all duration-300 focus:outline-none"
                  style={{
                    backgroundImage: `url("data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23${theme === 'light' ? '0969da' : '58a6ff'}%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E")`,
                    backgroundRepeat: 'no-repeat',
                    backgroundPosition: 'right 10px center',
                    backgroundSize: '10px'
                  }}
                >
                  {Object.entries(ENGINE_CONFIG).map(([key, config]) => (
                    <option key={key} value={key} className="bg-cb-bg text-cb-text">
                      {config.name}
                    </option>
                  ))}
                </select>
              </div>
            </>
          )}
        </div>

        <div className="flex items-center gap-2">
           {/* If in Squad mode, link back to Dark Star dashboard */}
          {squadMember && (
             <Link to="/dark_star" className="w-10 h-10 flex items-center justify-center text-cb-sub hover:text-[#a855f7] transition-colors text-lg" title="暗星小队">
                <i className="fas fa-star"></i>
             </Link>
          )}
          <button onClick={toggleTheme} className="w-10 h-10 flex items-center justify-center text-cb-sub hover:text-cb-accent transition-colors text-lg" title="切换主题">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <Link to="/recent_chat" className="w-10 h-10 flex items-center justify-center text-cb-sub hover:text-cb-accent transition-colors text-lg" title="系统交互日志">
            <i className="fas fa-history"></i>
          </Link>
        </div>
      </div>

      {/* Chat Messages */}
      <div className="w-full max-w-[900px] flex flex-col h-full mx-auto pt-[70px] box-border">
        <div 
          ref={chatContainerRef}
          className="flex-1 overflow-y-auto p-5 flex flex-col gap-5 scroll-smooth"
        >
          {messages.map((msg) => (
            <div key={msg.id} className={`flex gap-4 max-w-[85%] ${msg.role === 'user' ? 'self-end flex-row-reverse' : ''}`}>
              <div className={`w-[38px] h-[38px] rounded flex items-center justify-center shrink-0 ${
                msg.role === 'model' 
                  ? 'bg-cb-input border border-cb-border' 
                  : 'bg-cb-accent text-cb-accentBg'
              }`}
               style={msg.role === 'model' && squadMember ? { borderColor: squadMember.themeColor, color: squadMember.themeColor } : (msg.role === 'model' ? {color: 'var(--cb-accent-color)'} : {})}
              >
                <i className={`fas ${
                  msg.role === 'model' 
                    ? (squadMember ? squadMember.icon : 'fa-terminal') 
                    : 'fa-user'
                }`}></i>
              </div>
              <div className={`p-3 px-5 rounded-lg leading-relaxed break-words text-[0.95rem] ${
                msg.role === 'model'
                  ? 'bg-cb-chat border border-cb-border min-h-[20px]'
                  : 'bg-cb-accent text-cb-accentBg font-medium'
              }`}
              style={msg.role === 'model' && squadMember ? { borderLeft: `3px solid ${squadMember.themeColor}` } : {}}
              >
                {msg.senderName && (
                  <div className="text-xs font-bold mb-1 opacity-70" style={{color: squadMember?.themeColor}}>{msg.senderName}</div>
                )}
                {msg.content}
                {msg.role === 'model' && msg.content === '' && isLoading && (
                  <span className="typing-cursor"></span>
                )}
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} className="h-px w-full"></div>
        </div>

        {/* Input Area */}
        <div className="p-5 bg-cb-bg transition-colors duration-300">
          <div 
            className="bg-cb-input border border-cb-border rounded px-4 py-2 flex items-center transition-colors duration-300 focus-within:border-cb-accent"
            style={squadMember ? { borderColor: `${squadMember.themeColor}50` } : {}}
          >
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={squadMember ? `发送加密指令给 ${squadMember.codename}...` : "您好，请向菜包提问..."}
              className="flex-1 bg-transparent border-none text-cb-text p-3 outline-none font-sans"
              autoComplete="off"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className={`bg-none border-none text-cb-sub cursor-pointer text-lg hover:text-cb-accent disabled:opacity-50 disabled:cursor-not-allowed`}
              style={squadMember ? { color: squadMember.themeColor } : {}}
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

