export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [radarData, setRadarData] = useState(INITIAL_RADAR);
  const [selectedNode, setSelectedNode] = useState<KnowledgeNode | null>(null);

  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Theme Icon ---
  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  // --- AI Analysis ---
  const handleAnalyze = async () => {
    if (!input.trim() || isAnalyzing) return;
    setIsAnalyzing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const model = ai.models.generateContent;

      const response = await model({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.response?.text();
      if (text) {
        const data = JSON.parse(text);

        // Update Analysis Display
        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        // Update Radar
        if (data.radarData) {
          setRadarData(prev => prev.map(item => {
             const update = data.radarData.find((d: any) => d.subject === item.subject);
             return update ? { ...item, A: update.A } : item;
          }));
        }

        // Update Node Mastery
        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              const newVal = Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange));
              return { ...node, masteryLevel: newVal };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  // --- SVG Graph Visualization Helpers ---
  const getNodeColor = (mastery: number) => {
    // Red (0) -> Yellow (50) -> Green (100)
    if (mastery < 50) return '#f43f5e'; // Rose
    if (mastery < 80) return '#f59e0b'; // Amber
    return '#10b981'; // Emerald
  };

  // --- Radar Chart SVG Helper ---
  const renderRadar = () => {
    const size = 200;
    const center = size / 2;
    const radius = 80;
    const angleSlice = (Math.PI * 2) / 5;

    // Calculate points
    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    // Background Web
    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full">
         {/* Background Web */}
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}

         {/* Data Area */}
         <polygon points={points} fill="var(--kg-primary)" fillOpacity="0.4" stroke="var(--kg-primary)" strokeWidth="2" />

         {/* Labels */}
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text key={i} x={x} y={y} textAnchor="middle" dominantBaseline="middle" fontSize="10" fill="var(--kg-text)">
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300">
      {/* Header */}
      <div className="bg-kg-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-gray-200 dark:border-gray-700">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={toggleTheme} className="text-kg-primary hover:text-kg-text transition-colors w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
        </div>
      </div>

      {/* Main Content Layout */}
      <div className="flex-1 flex flex-col md:flex-row overflow-hidden">

        {/* Left Panel: Analysis & Controls */}
        <div className="w-full md:w-1/3 p-6 bg-kg-card/50 border-r border-gray-200 dark:border-gray-700 flex flex-col overflow-y-auto">

          {/* Capability Radar */}
          <div className="mb-8 p-4 bg-kg-card rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center">
             <h3 className="text-sm font-bold uppercase tracking-wider mb-4 text-kg-primary">能力雷达 (Capability Radar)</h3>
             <div className="w-64 h-64">
               {renderRadar()}
             </div>
             {analysisResult && (
               <div className="mt-2 text-center">
                 <div className="text-xs text-kg-text opacity-70">预测成绩</div>
                 <div className="text-3xl font-bold text-kg-secondary">{analysisResult.predictedScore}</div>
               </div>
             )}
          </div>

          {/* Import / Input Area */}
          <div className="mb-6">
            <label className="block text-xs font-bold uppercase mb-2 text-kg-text opacity-70">导入试题 / 成绩 / 文本</label>
            <textarea 
              className="w-full h-32 p-3 rounded-lg bg-kg-bg border border-gray-200 dark:border-gray-700 text-sm focus:outline-none focus:border-kg-primary resize-none"
              placeholder="例如：输入一道错题，或者粘贴一次考试的成绩分析..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
            ></textarea>
            <button 
              onClick={handleAnalyze}
              disabled={isAnalyzing || !input.trim()}
              className="w-full mt-2 py-2 bg-kg-primary text-white rounded-lg font-bold shadow-md hover:bg-opacity-90 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {isAnalyzing ? <i className="fas fa-circle-notch fa-spin"></i> : <i className="fas fa-brain"></i>}
              智能分析 & 更新图谱
            </button>
          </div>

          {/* Analysis Results */}
          {analysisResult && (
            <div className="p-4 bg-kg-bg rounded-lg border border-kg-primary/20 animate-[fadeInUp_0.3s_ease-out]">
              <h4 className="font-bold text-kg-primary mb-2"><i className="fas fa-lightbulb mr-1"></i> 改善建议</h4>
              <p className="text-sm mb-3 leading-relaxed">{analysisResult.analysis}</p>
              <ul className="text-xs space-y-1 text-kg-text opacity-80">
                {analysisResult.suggestions.map((s, i) => (
                  <li key={i}>• {s}</li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {/* Right Panel: Interactive Graph */}
        <div className="flex-1 bg-kg-bg relative overflow-hidden">
          <svg className="w-full h-full">
            {/* Draw Links */}
            {links.map((link, i) => {
              const src = nodes.find(n => n.id === link.source);
              const tgt = nodes.find(n => n.id === link.target);
              if (!src || !tgt) return null;
              return (
                <line 
                  key={i}
                  x1={src.x} y1={src.y}
                  x2={tgt.x} y2={tgt.y}
                  stroke="var(--kg-line)"
                  strokeWidth="2"
                  opacity="0.6"
                />
              );
            })}

            {/* Draw Nodes */}
            {nodes.map((node) => (
              <g 
                key={node.id} 
                transform={`translate(${node.x},${node.y})`}
                onClick={() => setSelectedNode(node)}
                className="cursor-pointer transition-transform hover:scale-110"
              >
                <circle 
                  r={node.category === 'root' ? 30 : node.category === 'core' ? 20 : 15} 
                  fill={getNodeColor(node.masteryLevel)}
                  stroke="var(--kg-bg)"
                  strokeWidth="3"
                  className="shadow-md"
                />
                <text 
                  y={node.category === 'root' ? 45 : 35} 
                  textAnchor="middle" 
                  fontSize="12" 
                  fontWeight="bold" 
                  fill="var(--kg-text)"
                  className="pointer-events-none"
                >
                  {node.label}
                </text>
                <text 
                  y={4} 
                  textAnchor="middle" 
                  dominantBaseline="middle"
                  fontSize="10" 
                  fontWeight="bold" 
                  fill="#fff"
                  className="pointer-events-none"
                >
                  {node.masteryLevel}%
                </text>
              </g>
            ))}
          </svg>

          <div className="absolute bottom-4 right-4 text-xs text-kg-text opacity-50 bg-kg-card p-2 rounded shadow">
             <div className="flex items-center gap-2 mb-1"><span className="w-2 h-2 rounded-full bg-emerald-500"></span> 掌握 (80-100)</div>
             <div className="flex items-center gap-2 mb-1"><span className="w-2 h-2 rounded-full bg-amber-500"></span> 良好 (50-79)</div>
             <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-rose-500"></span> 需加强 (&lt;50)</div>
          </div>
        </div>

      </div>
    </div>
  );
};

