const INITIAL_LINKS: KnowledgeLink[] = [
  { source: 'cs', target: 'os', strength: 1 },
  { source: 'cs', target: 'net', strength: 1 },
  { source: 'cs', target: 'ds', strength: 1 },
  { source: 'cs', target: 'algo', strength: 1 },
