        </div>

        {/* Input Bar */}
        <div className="bg-edu-card p-2 rounded-full shadow-lg border border-edu-accent z-10 flex items-center gap-2 pl-4 transition-colors">
          <button 
             onClick={() => fileInputRef.current?.click()}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="上传文件"
          >
             <i className="fas fa-folder-open"></i>
          </button>
          <button 
             onClick={() => cameraInputRef.current?.click()}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="拍照解题"
          >
            <i className="fas fa-camera"></i>
          </button>
          <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="有问题尽管问我..."
            className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-edu-text placeholder-edu-sub/50"
            disabled={isProcessing}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isProcessing}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
              input.trim() ? 'bg-edu-primary text-white rotate-0' : 'bg-edu-bg text-edu-sub -rotate-90'
            }`}
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { ThemeContext, KG_SYSTEM_INSTRUCTION } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';

// Mock Initial Data (Computer Science Basics)
const INITIAL_NODES: KnowledgeNode[] = [
  { id: 'cs', label: 'Computer Science', category: 'root', masteryLevel: 80, x: 400, y: 300 },
  { id: 'os', label: 'Operating Systems', category: 'core', masteryLevel: 60, x: 300, y: 200 },
  { id: 'net', label: 'Networks', category: 'core', masteryLevel: 40, x: 500, y: 200 },
  { id: 'ds', label: 'Data Structures', category: 'core', masteryLevel: 90, x: 300, y: 400 },
  { id: 'algo', label: 'Algorithms', category: 'core', masteryLevel: 70, x: 500, y: 400 },
  { id: 'tcp', label: 'TCP/IP', category: 'sub', masteryLevel: 30, x: 600, y: 150 },
  { id: 'process', label: 'Process Mgmt', category: 'sub', masteryLevel: 50, x: 200, y: 150 },
];

const INITIAL_LINKS: KnowledgeLink[] = [
  { source: 'cs', target: 'os', strength: 1 },
  { source: 'cs', target: 'net', strength: 1 },
  { source: 'cs', target: 'ds', strength: 1 },
  { source: 'cs', target: 'algo', strength: 1 },
  { source: 'net', target: 'tcp', strength: 0.8 },
  { source: 'os', target: 'process', strength: 0.8 },
  { source: 'ds', target: 'algo', strength: 0.5 },
];

const INITIAL_RADAR = [
  { subject: "Theory", A: 65, fullMark: 100 },
  { subject: "Practice", A: 40, fullMark: 100 },
  { subject: "Logic", A: 85, fullMark: 100 },
  { subject: "Memory", A: 50, fullMark: 100 },
  { subject: "Innovation", A: 60, fullMark: 100 },
];

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [radarData, setRadarData] = useState(INITIAL_RADAR);
  const [selectedNode, setSelectedNode] = useState<KnowledgeNode | null>(null);

  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);

  // --- Theme Icon ---
  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  // --- AI Analysis ---
  const handleAnalyze = async () => {
    if (!input.trim() || isAnalyzing) return;
    setIsAnalyzing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);

        // Update Analysis Display
        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        // Update Radar
        if (data.radarData) {
          setRadarData(prev => prev.map(item => {
             const update = data.radarData.find((d: any) => d.subject === item.subject);
             return update ? { ...item, A: update.A } : item;
          }));
        }

        // Update Node Mastery
        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              const newVal = Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange));
              return { ...node, masteryLevel: newVal };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>, type: 'file' | 'camera') => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = type === 'camera' 
        ? `[系统] 已拍摄试题: ${file.name}` 
        : `[系统] 已上传成绩单: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  // --- SVG Graph Visualization Helpers ---
  const getNodeColor = (mastery: number) => {
    // Red (0) -> Yellow (50) -> Green (100)
    if (mastery < 50) return '#f43f5e'; // Rose
    if (mastery < 80) return '#f59e0b'; // Amber
    return '#10b981'; // Emerald
  };

  // --- Radar Chart SVG Helper ---
  const renderRadar = () => {
    const size = 200;
    const center = size / 2;
    const radius = 80;
    const angleSlice = (Math.PI * 2) / 5;

    // Calculate points
    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    // Background Web
    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full">
         {/* Background Web */}
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}

         {/* Data Area */}
         <polygon points={points} fill="var(--kg-primary)" fillOpacity="0.4" stroke="var(--kg-primary)" strokeWidth="2" />

         {/* Labels */}
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text key={i} x={x} y={y} textAnchor="middle" dominantBaseline="middle" fontSize="10" fill="var(--kg-text)">
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300">
      {/* Hidden Inputs */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => handleFileChange(e, 'file')} />
      <input type="file" accept="image/*" capture="environment" ref={cameraInputRef} className="hidden" onChange={(e) => handleFileChange(e, 'camera')} />

      {/* Header */}
      <div className="bg-kg-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-gray-200 dark:border-gray-700">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={toggleTheme} className="text-kg-primary hover:text-kg-text transition-colors w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Content Layout */}
      <div className="flex-1 flex flex-col md:flex-row overflow-hidden relative">

        {/* Left Panel: Analysis & Controls */}
        <div className="w-full md:w-1/3 p-6 bg-kg-card/50 border-r border-gray-200 dark:border-gray-700 flex flex-col overflow-y-auto z-10 relative">

          {/* Capability Radar */}
          <div className="mb-6 p-4 bg-kg-card rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col items-center shrink-0">
             <h3 className="text-sm font-bold uppercase tracking-wider mb-4 text-kg-primary">能力雷达 (Capability Radar)</h3>
             <div className="w-48 h-48">
               {renderRadar()}
             </div>
             {analysisResult && (
               <div className="mt-2 text-center">
                 <div className="text-xs text-kg-text opacity-70">预测成绩</div>
                 <div className="text-3xl font-bold text-kg-secondary">{analysisResult.predictedScore}</div>
               </div>
             )}
          </div>

          {/* Analysis Results (Scrollable Area) */}
          <div className="flex-grow overflow-y-auto mb-4">
             {analysisResult ? (
              <div className="p-4 bg-kg-bg rounded-lg border border-kg-primary/20 animate-[fadeInUp_0.3s_ease-out]">
                <h4 className="font-bold text-kg-primary mb-2"><i className="fas fa-lightbulb mr-1"></i> 改善建议</h4>
                <p className="text-sm mb-3 leading-relaxed">{analysisResult.analysis}</p>
                <ul className="text-xs space-y-1 text-kg-text opacity-80">
                  {analysisResult.suggestions.map((s, i) => (
                    <li key={i}>• {s}</li>
                  ))}
                </ul>
              </div>
            ) : (
               <div className="text-center text-sm text-kg-text opacity-50 italic mt-4">
                 暂无分析数据。请导入试题或成绩单。
               </div>
            )}
          </div>

          {/* New Chat-style Input Area */}
          <div className="mt-auto bg-kg-card p-2 rounded-2xl shadow-soft border border-gray-200 dark:border-gray-700 flex items-center gap-2 transition-colors">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-10 h-10 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full transition-colors"
              title="上传成绩/试题"
            >
              <i className="fas fa-folder-open"></i>
            </button>
             <button 
              onClick={() => cameraInputRef.current?.click()}
              className="w-10 h-10 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full transition-colors"
              title="拍照分析"
            >
              <i className="fas fa-camera"></i>
            </button>
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
              placeholder="输入错题或分析指令..."
              className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-kg-text"
              disabled={isAnalyzing}
            />
            <button 
              onClick={handleAnalyze}
              disabled={!input.trim() || isAnalyzing}
              className={`px-4 py-2 rounded-xl text-sm font-medium transition-all ${
                input.trim() ? 'bg-kg-primary text-white shadow-md' : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
              }`}
            >
              {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : '分析'}
            </button>
          </div>
        </div>

        {/* Right Panel: Interactive Graph */}
        <div className="flex-1 bg-kg-bg relative overflow-hidden h-[50vh] md:h-full">
          <svg className="w-full h-full">
            {/* Draw Links */}
            {links.map((link, i) => {
              const src = nodes.find(n => n.id === link.source);
              const tgt = nodes.find(n => n.id === link.target);
              if (!src || !tgt) return null;
              return (
                <line 
                  key={i}
                  x1={src.x} y1={src.y}
                  x2={tgt.x} y2={tgt.y}
                  stroke="var(--kg-line)"
                  strokeWidth="2"
                  opacity="0.6"
                />
              );
            })}

            {/* Draw Nodes */}
            {nodes.map((node) => (
              <g 
                key={node.id} 
                transform={`translate(${node.x},${node.y})`}
                onClick={() => setSelectedNode(node)}
                className="cursor-pointer transition-transform hover:scale-110"
              >
                <circle 
                  r={node.category === 'root' ? 30 : node.category === 'core' ? 20 : 15} 
                  fill={getNodeColor(node.masteryLevel)}
                  stroke="var(--kg-bg)"
                  strokeWidth="3"
                  className="shadow-md"
                />
                <text 
                  y={node.category === 'root' ? 45 : 35} 
                  textAnchor="middle" 
                  fontSize="12" 
                  fontWeight="bold" 
                  fill="var(--kg-text)"
                  className="pointer-events-none"
                >
                  {node.label}
                </text>
                <text 
                  y={4} 
                  textAnchor="middle" 
                  dominantBaseline="middle"
                  fontSize="10" 
                  fontWeight="bold" 
                  fill="#fff"
                  className="pointer-events-none"
                >
                  {node.masteryLevel}%
                </text>
              </g>
            ))}
          </svg>

          <div className="absolute bottom-4 right-4 text-xs text-kg-text opacity-50 bg-kg-card p-2 rounded shadow">
             <div className="flex items-center gap-2 mb-1"><span className="w-2 h-2 rounded-full bg-emerald-500"></span> 掌握 (80-100)</div>
             <div className="flex items-center gap-2 mb-1"><span className="w-2 h-2 rounded-full bg-amber-500"></span> 良好 (50-79)</div>
             <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-rose-500"></span> 需加强 (&lt;50)</div>
          </div>
        </div>

      </div>
    </div>
  );
};

