import React, { useState, useContext, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { ThemeContext, KG_SYSTEM_INSTRUCTION } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

// Mock Initial Data (Computer Science Basics) - Translated
const INITIAL_NODES: KnowledgeNode[] = [
  { id: 'cs', label: '计算机科学', category: 'root', masteryLevel: 80, x: 400, y: 300 },
  { id: 'os', label: '操作系统', category: 'core', masteryLevel: 60, x: 300, y: 200 },
  { id: 'net', label: '计算机网络', category: 'core', masteryLevel: 40, x: 500, y: 200 },
  { id: 'ds', label: '数据结构', category: 'core', masteryLevel: 90, x: 300, y: 400 },
  { id: 'algo', label: '算法分析', category: 'core', masteryLevel: 70, x: 500, y: 400 },
  { id: 'tcp', label: 'TCP/IP协议', category: 'sub', masteryLevel: 30, x: 600, y: 150 },
  { id: 'process', label: '进程管理', category: 'sub', masteryLevel: 50, x: 200, y: 150 },
];

const INITIAL_LINKS: KnowledgeLink[] = [
  { source: 'cs', target: 'os', strength: 1 },
  { source: 'cs', target: 'net', strength: 1 },
  { source: 'cs', target: 'ds', strength: 1 },
  { source: 'cs', target: 'algo', strength: 1 },
  { source: 'net', target: 'tcp', strength: 0.8 },
  { source: 'os', target: 'process', strength: 0.8 },
  { source: 'ds', target: 'algo', strength: 0.5 },
];

const INITIAL_RADAR = [
  { subject: "理论基础", A: 65, fullMark: 100 },
  { subject: "实践应用", A: 40, fullMark: 100 },
  { subject: "逻辑思维", A: 85, fullMark: 100 },
  { subject: "记忆储备", A: 50, fullMark: 100 },
  { subject: "创新能力", A: 60, fullMark: 100 },
];

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [radarData, setRadarData] = useState(INITIAL_RADAR);
  const [selectedNode, setSelectedNode] = useState<KnowledgeNode | null>(null);
  const [showCamera, setShowCamera] = useState(false);

  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Theme Icon ---
  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  // --- AI Analysis ---
  const handleAnalyze = async () => {
    if (!input.trim() || isAnalyzing) return;
    setIsAnalyzing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);

        // Update Analysis Display
        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        // Update Radar
        if (data.radarData) {
          setRadarData(prev => prev.map(item => {
             const update = data.radarData.find((d: any) => d.subject === item.subject);
             return update ? { ...item, A: update.A } : item;
          }));
        }

        // Update Node Mastery
        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              const newVal = Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange));
              return { ...node, masteryLevel: newVal };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传成绩单: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄试题: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  // --- SVG Graph Visualization Helpers ---
  const getNodeColor = (mastery: number) => {
    // Red (0) -> Yellow (50) -> Green (100)
    if (mastery < 50) return '#f43f5e'; // Rose
    if (mastery < 80) return '#f59e0b'; // Amber
    return '#10b981'; // Emerald
  };

  // --- Radar Chart SVG Helper ---
  const renderRadar = () => {
    const size = 200;
    const center = size / 2;
    const radius = 80;
    const angleSlice = (Math.PI * 2) / 5;

    // Calculate points
    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    // Background Web
    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full">
         {/* Background Web */}
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}

         {/* Data Area */}
         <polygon points={points} fill="var(--kg-primary)" fillOpacity="0.4" stroke="var(--kg-primary)" strokeWidth="2" />

         {/* Labels */}
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text key={i} x={x} y={y} textAnchor="middle" dominantBaseline="middle" fontSize="10" fill="var(--kg-text)">
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      {/* Hidden Inputs */}
