<script>
    const canvas = document.getElementById('glCanvas');
    const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');

    if (!gl) {
        alert('您的浏览器不支持 WebGL。');
    }

    // 顶点着色器 (Vertex Shader) - 处理顶点位置，这里只是一个简单的全屏覆盖
    const vsSource = `
        attribute vec4 aVertexPosition;
        void main() {
            gl_Position = aVertexPosition;
        }
    `;

    // 片段着色器 (Fragment Shader) - 核心魔法所在：生成颜色和流动效果
    // 这里使用了类似域扭曲 (Domain Warping) 和噪声的技术来模拟流形
    const fsSource = `
        precision highp float;
        uniform vec2 uResolution;
        uniform float uTime;

        // 简单的噪声函数
        float hash(vec2 p) { return fract(1e4 * sin(17.0 * p.x + p.y * 0.1) * (0.1 + abs(sin(p.y * 13.0 + p.x)))); }
        float noise(vec2 x) {
            vec2 i = floor(x);
            vec2 f = fract(x);
            float a = hash(i);
            float b = hash(i + vec2(1.0, 0.0));
            float c = hash(i + vec2(0.0, 1.0));
            float d = hash(i + vec2(1.0, 1.0));
            vec2 u = f * f * (3.0 - 2.0 * f);
            return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
        }

        // 分形布朗运动 (FBM) - 用于创造更复杂的细节
        #define OCTAVES 6
        float fbm (in vec2 st) {
            // 旋转矩阵
            mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.50));
            float v = 0.0;
            float a = 0.5;
            vec2 shift = vec2(100.0);
            for (int i = 0; i < OCTAVES; ++i) {
                v += a * noise(st);
                st = rot * st * 2.0 + shift;
                a *= 0.5;
            }
            return v;
        }

        void main() {
            vec2 st = gl_FragCoord.xy / uResolution.xy;
            // 保持纵横比，防止拉伸
            st.x *= uResolution.x / uResolution.y;

            vec2 q = vec2(0.);
            q.x = fbm( st + 0.00 * uTime);
            q.y = fbm( st + vec2(1.0));

            vec2 r = vec2(0.);
            // 核心：域扭曲。用一个 FBM 的结果去扭曲另一个 FBM 的输入
            // 这创造了流体般的卷曲效果
            r.x = fbm( st + 1.0*q + vec2(1.7,9.2)+ 0.15*uTime );
            r.y = fbm( st + 1.0*q + vec2(8.3,2.8)+ 0.126*uTime);

            float f = fbm(st+r);

            // 颜色混合调色板 (基于计算出的 f 值进行混合)
            vec3 color = mix(vec3(0.101961,0.619608,0.666667),
                        vec3(0.666667,0.666667,0.498039),
                        clamp((f*f)*4.0,0.0,1.0));

            color = mix(color,
                        vec3(0.1,0.1,0.2), // 深蓝紫色调
                        clamp(length(q),0.0,1.0));

            color = mix(color,
                        vec3(0.9,0.3,0.2), // 橙红色高光
                        clamp(length(r.x),0.0,1.0));

            // 增加一些对比度和暗角
            gl_FragColor = vec4((f*f*f+.6*f*f+.5*f)*color,1.);
        }
    `;

    // --- WebGL 初始化辅助函数 ---

    function loadShader(gl, type, source) {
        const shader = gl.createShader(type);
        gl.shaderSource(shader, source);
        gl.compileShader(shader);
        if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
            console.error('Shader编译失败: ' + gl.getShaderInfoLog(shader));
            gl.deleteShader(shader);
            return null;
        }
        return shader;
    }

    function initShaderProgram(gl, vsSource, fsSource) {
        const vertexShader = loadShader(gl, gl.VERTEX_SHADER, vsSource);
        const fragmentShader = loadShader(gl, gl.FRAGMENT_SHADER, fsSource);
        const shaderProgram = gl.createProgram();
        gl.attachShader(shaderProgram, vertexShader);
        gl.attachShader(shaderProgram, fragmentShader);
        gl.linkProgram(shaderProgram);
        if (!gl.getProgramParameter(shaderProgram, gl.LINK_STATUS)) {
            console.error('程序链接失败: ' + gl.getProgramInfoLog(shaderProgram));
            return null;
        }
        return shaderProgram;
    }

    // --- 主流程 ---

    const shaderProgram = initShaderProgram(gl, vsSource, fsSource);

    // 获取 Shader 中变量的位置
    const programInfo = {
        program: shaderProgram,
        attribLocations: {
            vertexPosition: gl.getAttribLocation(shaderProgram, 'aVertexPosition'),
        },
        uniformLocations: {
            resolution: gl.getUniformLocation(shaderProgram, 'uResolution'),
            time: gl.getUniformLocation(shaderProgram, 'uTime'),
        },
    };

    // 创建一个覆盖全屏的大三角形（比两个三角形组成的矩形效率更高）
    const positionBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
    const positions = [
        -1.0, -1.0,
         3.0, -1.0,
        -1.0,  3.0,
    ];
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(positions), gl.STATIC_DRAW);

    // 渲染循环
    function render(now) {
        now *= 0.001; // 转换为秒

        // 调整画布大小以匹配窗口
        const displayWidth  = canvas.clientWidth;
        const displayHeight = canvas.clientHeight;
        if (canvas.width  !== displayWidth || canvas.height !== displayHeight) {
            canvas.width  = displayWidth;
            canvas.height = displayHeight;
            gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
        }

        gl.useProgram(programInfo.program);

        // 绑定顶点数据
        gl.bindBuffer(gl.ARRAY_BUFFER, positionBuffer);
        gl.vertexAttribPointer(programInfo.attribLocations.vertexPosition, 2, gl.FLOAT, false, 0, 0);
        gl.enableVertexAttribArray(programInfo.attribLocations.vertexPosition);

        // 传递 Uniforms (分辨率和时间)
        gl.uniform2f(programInfo.uniformLocations.resolution, canvas.width, canvas.height);
        gl.uniform1f(programInfo.uniformLocations.time, now * 0.5); // * 0.5 调整流动速度

        // 绘制
        gl.drawArrays(gl.TRIANGLES, 0, 3);

        requestAnimationFrame(render);
    }

    requestAnimationFrame(render);

</script>
