import React, { useEffect, useRef } from 'react';

const ColorManifoldBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl') as WebGLRenderingContext;

    if (!gl) {
      console.error('WebGL not supported');
      return;
    }

    // Vertex Shader
    const vsSource = `
      attribute vec4 aVertexPosition;
      void main() {
        gl_Position = aVertexPosition;
      }
    `;

    // Fragment Shader (Provided logic)
    const fsSource = `
      precision highp float;
      uniform vec2 uResolution;
      uniform float uTime;

      // Hash function
      float hash(vec2 p) { 
        return fract(1e4 * sin(17.0 * p.x + p.y * 0.1) * (0.1 + abs(sin(p.y * 13.0 + p.x)))); 
      }

      // Noise function
      float noise(vec2 x) {
        vec2 i = floor(x);
        vec2 f = fract(x);
        float a = hash(i);
        float b = hash(i + vec2(1.0, 0.0));
        float c = hash(i + vec2(0.0, 1.0));
        float d = hash(i + vec2(1.0, 1.0));
        vec2 u = f * f * (3.0 - 2.0 * f);
        return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
      }

      // FBM
      #define OCTAVES 6
      float fbm (in vec2 st) {
        // Rotation matrix
        mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.50));
        float v = 0.0;
        float a = 0.5;
        vec2 shift = vec2(100.0);
        for (int i = 0; i < OCTAVES; ++i) {
          v += a * noise(st);
          st = rot * st * 2.0 + shift;
          a *= 0.5;
        }
        return v;
      }

      void main() {
        vec2 st = gl_FragCoord.xy / uResolution.xy;
        st.x *= uResolution.x / uResolution.y;

        vec2 q = vec2(0.);
        q.x = fbm( st + 0.00 * uTime);
        q.y = fbm( st + vec2(1.0));

        vec2 r = vec2(0.);
        r.x = fbm( st + 1.0*q + vec2(1.7,9.2)+ 0.15*uTime );
        r.y = fbm( st + 1.0*q + vec2(8.3,2.8)+ 0.126*uTime);

        float f = fbm(st+r);

        // Color Palette Mixing
        vec3 color = mix(vec3(0.101961,0.619608,0.666667),
                  vec3(0.666667,0.666667,0.498039),
                  clamp((f*f)*4.0,0.0,1.0));

        color = mix(color,
                  vec3(0.1,0.1,0.2), // Dark Blue/Purple
                  clamp(length(q),0.0,1.0));

        color = mix(color,
                  vec3(0.9,0.3,0.2), // Orange/Red Highlight
                  clamp(length(r.x),0.0,1.0));

        // Contrast and Vignette
        gl_FragColor = vec4((f*f*f+.6*f*f+.5*f)*color, 1.);
      }
    `;

    // Initialize Shaders
    const loadShader = (gl: WebGLRenderingContext, type: number, source: string) => {
      const shader = gl.createShader(type);
      if (!shader) return null;
      gl.shaderSource(shader, source);
      gl.compileShader(shader);
      if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
        console.error('Shader compile failed: ' + gl.getShaderInfoLog(shader));
        gl.deleteShader(shader);
        return null;
      }
      return shader;
    };

    const vertexShader = loadShader(gl, gl.VERTEX_SHADER, vsSource);
    const fragmentShader = loadShader(gl, gl.FRAGMENT_SHADER, fsSource);

    if (!vertexShader || !fragmentShader) return;

    const shaderProgram = gl.createProgram();
    if (!shaderProgram) return;

    gl.attachShader(shaderProgram, vertexShader);
    gl.attachShader(shaderProgram, fragmentShader);
    gl.linkProgram(shaderProgram);

    if (!gl.getProgramParameter(shaderProgram, gl.LINK_STATUS)) {
      console.error('Program link failed: ' + gl.getProgramInfoLog(shaderProgram));
      return;
    }

    // Locations
    const positionAttributeLocation = gl.getAttribLocation(shaderProgram, 'aVertexPosition');
    const resolutionUniformLocation = gl.getUniformLocation(shaderProgram, 'uResolution');
    const timeUniformLocation = gl.getUniformLocation(shaderProgram, 'uTime');

