export const KnowledgeNodeDetail: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { nodeId } = useParams<{ nodeId: string }>();
  const navigate = useNavigate();
  const location = useLocation();

  // Retrieve node data passed via navigation state, or fallback (simplified)
  const node = location.state?.node as KnowledgeNode;

  const [aiTip, setAiTip] = useState<string>('');
  const [loadingTip, setLoadingTip] = useState(false);

  // If accessed directly without state, we might redirect or show error (or fetch real data)
  if (!node && !loadingTip) {
     return (
        <div className="flex flex-col items-center justify-center h-screen bg-kg-bg text-kg-text">
            <p>Node data missing.</p>
            <Link to="/knowledge-graph" className="text-kg-primary underline mt-2">Return to Graph</Link>
