import React, { useContext, useState, useEffect } from 'react';
import { Link, useParams, useLocation, useNavigate } from 'react-router-dom';
import { ThemeContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { GoogleGenAI } from "@google/genai";

export const KnowledgeAnalysis: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { subject } = useParams<{ subject: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const score = location.state?.score || 0;

  const [report, setReport] = useState<string>('');
  const [loading, setLoading] = useState(false);

  // Generate a mock or real report on load
  useEffect(() => {
    const generateReport = async () => {
        setLoading(true);
        try {
             // In a real app, we would fetch historical data here.
             // For now, we simulate an AI analysis generation based on the subject and score.
             const apiKey = process.env.API_KEY || '';
             const ai = new GoogleGenAI({ apiKey });
             const prompt = `分析学生的"${subject}"能力，当前评分为 ${score}/100。
             请生成一份简短的分析报告（约150字），包含：
             1. 当前水平评估。
             2. 两个具体的提升策略。
             3. 推荐的思维训练方式。
             请使用Markdown格式，语气专业且鼓励性。`;

             const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
             });
             setReport(response.text || "无法生成报告。");
        } catch (e) {
            setReport(`基于当前评分 ${score}，该维度的能力表现稳定。建议通过更多实践案例来强化。\n(AI服务暂时不可用)`);
        } finally {
            setLoading(false);
        }
    };
    generateReport();
  }, [subject, score]);

  const getScoreColor = (s: number) => {
      if (s < 60) return 'bg-rose-500';
      if (s < 80) return 'bg-amber-500';
      return 'bg-emerald-500';
  };

  return (
    <div className="flex flex-col min-h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300">
      {/* Header */}
      <div className="bg-kg-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-gray-200 dark:border-gray-700 sticky top-0">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate('/knowledge-graph')} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </button>
          <h1 className="text-lg font-bold tracking-wide">能力深度分析 <span className="text-kg-primary font-light">| {decodeURIComponent(subject || '')}</span></h1>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={toggleTheme} className="text-kg-primary hover:text-kg-text transition-colors w-8 h-8 flex items-center justify-center">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      <div className="flex-1 max-w-3xl w-full mx-auto p-6 animate-[fadeInUp_0.5s_ease-out]">

        {/* Score Card */}
        <div className="mb-8 text-center">
            <div className="inline-block relative">
                <svg className="w-40 h-40 transform -rotate-90">
                    <circle cx="80" cy="80" r="70" stroke="currentColor" strokeWidth="10" fill="transparent" className="text-gray-200 dark:text-gray-700" />
                    <circle 
                        cx="80" cy="80" r="70" 
                        stroke="currentColor" strokeWidth="10" fill="transparent" 
                        strokeDasharray={440}
                        strokeDashoffset={440 - (440 * score) / 100}
                        className={`${score < 60 ? 'text-rose-500' : score < 80 ? 'text-amber-500' : 'text-emerald-500'} transition-all duration-1000 ease-out`}
                    />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-4xl font-bold">{score}</span>
                    <span className="text-xs uppercase tracking-widest opacity-60">Score</span>
                </div>
            </div>
            <h2 className="text-2xl font-bold mt-4">{decodeURIComponent(subject || '')}</h2>
            <p className="text-sm opacity-60 mt-2">上次评估时间: {new Date().toLocaleDateString()}</p>
        </div>

        {/* Report Content */}
        <div className="bg-kg-card rounded-2xl p-8 shadow-sm border border-gray-100 dark:border-gray-700 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-kg-primary to-kg-secondary"></div>

            <h3 className="font-bold text-kg-primary mb-6 flex items-center gap-2 text-lg">
                <i className="fas fa-chart-pie"></i> 综合评估报告
