        </div>

        {/* Footer UI */}
        <footer className="p-4 bg-black border-t-4 border-white/20 text-center text-[10px] text-gray-500">
           INSERT COIN TO CONTINUE • GEMINI POWERED GENERATION
        </footer>

      </div>

      {/* Character Modal */}
      {selectedChar && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-[fadeIn_0.2s]">
          <div className="bg-gray-900 border-4 border-white w-full max-w-md relative shadow-[8px_8px_0_rgba(0,0,0,0.5)]">

            {/* Modal Header */}
