export const DarkStar: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const [characters, setCharacters] = useState<PixelChar[]>(SQUAD_PIXELS);
  const [selectedChar, setSelectedChar] = useState<PixelChar | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [scanMessage, setScanMessage] = useState('');

  // Starfield effect
  useEffect(() => {
    const canvas = document.getElementById('starfield') as HTMLCanvasElement;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let w = canvas.width = window.innerWidth;
    let h = canvas.height = window.innerHeight;

    const stars = Array.from({ length: 100 }).map(() => ({
      x: Math.random() * w,
      y: Math.random() * h,
      size: Math.random() * 2 + 1,
      speed: Math.random() * 0.5 + 0.1
    }));

    const animate = () => {
      ctx.fillStyle = '#050505'; // Very dark bg
      ctx.fillRect(0, 0, w, h);
      ctx.fillStyle = '#ffffff';
      stars.forEach(s => {
        s.y += s.speed;
        if (s.y > h) s.y = 0;
        ctx.fillRect(s.x, s.y, s.size, s.size);
      });
      requestAnimationFrame(animate);
    };
    animate();

    const handleResize = () => {
      w = canvas.width = window.innerWidth;
      h = canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleScan = async () => {
    if (isScanning) return;
    setIsScanning(true);
    setScanMessage('SCANNING DEEP WEB...');

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const prompt = `Generate a unique, creative pixel-art style character for a cyberpunk RPG game.
      Return ONLY a JSON object with this structure:
      {
        "name": "Character Name",
        "class": "Class Name (e.g. Hacker, Ronin)",
        "description": "Short description (max 10 words)",
        "story": "A short, interesting backstory (approx 30-50 words).",
        "color": "Hex Color Code (bright neon color)",
        "spriteMatrix": [array of 25 integers, 0 or 1, representing a 5x5 pixel grid shape]
      }
      Do not include markdown code blocks. Just the JSON.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const text = response.text;
      if (text) {
        const newCharData = JSON.parse(text);
        const newChar: PixelChar = {
          id: `gen_${Date.now()}`,
          ...newCharData
        };
        setCharacters(prev => [...prev, newChar]);
        setScanMessage('SIGNAL ACQUIRED!');
        setTimeout(() => setScanMessage(''), 2000);
      }
    } catch (e) {
      console.error(e);
      setScanMessage('SIGNAL LOST.');
      setTimeout(() => setScanMessage(''), 2000);
    } finally {
      setIsScanning(false);
    }
  };

  const PixelSprite = ({ matrix, color, size = 4 }: { matrix: number[], color: string, size?: number }) => (
    <div className="grid grid-cols-5 gap-px bg-transparent" style={{ width: size * 5 + 4, height: size * 5 + 4 }}>
      {matrix.map((val, i) => (
        <div 
          key={i} 
          style={{ 
            backgroundColor: val ? color : 'transparent',
            width: size,
            height: size
          }} 
        />
      ))}
    </div>
  );

  return (
    <div className="relative min-h-screen font-pixel text-white overflow-hidden bg-black selection:bg-[#a855f7] selection:text-white">
      {/* Canvas Background */}
      <canvas id="starfield" className="fixed inset-0 z-0 pointer-events-none opacity-50"></canvas>

      {/* Main Container */}
      <div className="relative z-10 flex flex-col h-screen">

        {/* Header UI */}
        <header className="p-6 flex justify-between items-center border-b-4 border-white/20 bg-black/80 backdrop-blur-sm">
          <div className="flex items-center gap-4">
            <Link to="/caibao" className="text-xs hover:text-[#a855f7] hover:underline">&lt; EXIT OS</Link>
            <h1 className="text-xl md:text-2xl text-[#a855f7] drop-shadow-[2px_2px_0_rgba(255,255,255,0.3)]">
              DARK STAR <span className="text-white text-xs block md:inline md:ml-2">PROTOCOL v3.0</span>
            </h1>
          </div>
          <div className="text-right">
             <div className="text-[10px] text-gray-400">CREDITS</div>
             <div className="text-yellow-400">∞</div>
          </div>
        </header>

        {/* Game Area */}
