            {/* Modal Content */}
            <div className="p-6">
              <div className="flex gap-6 mb-6">
                 <div className="w-24 h-24 bg-black border-2 border-gray-600 flex items-center justify-center shrink-0">
                    <div className="transform scale-[4]">
                       <PixelSprite matrix={selectedChar.spriteMatrix} color={selectedChar.color} size={2} />
