                 <div>
                    <div className="text-xs text-gray-400 mb-1">CLASS: <span className="text-white">{selectedChar.class}</span></div>
                    <div className="text-xs text-gray-400 mb-1">STATUS: <span className="text-[#00ff00]">ONLINE</span></div>
