export const DarkStar: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const [characters, setCharacters] = useState<PixelChar[]>(SQUAD_PIXELS);
  const [selectedChar, setSelectedChar] = useState<PixelChar | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [scanMessage, setScanMessage] = useState('');

  // Starfield effect
  useEffect(() => {
    const canvas = document.getElementById('starfield') as HTMLCanvasElement;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let w = canvas.width = window.innerWidth;
    let h = canvas.height = window.innerHeight;

    const stars = Array.from({ length: 100 }).map(() => ({
      x: Math.random() * w,
      y: Math.random() * h,
      size: Math.random() * 2 + 1,
      speed: Math.random() * 0.5 + 0.1
    }));

    const animate = () => {
      ctx.fillStyle = '#050505'; // Very dark bg
      ctx.fillRect(0, 0, w, h);
      ctx.fillStyle = '#ffffff';
      stars.forEach(s => {
        s.y += s.speed;
        if (s.y > h) s.y = 0;
        ctx.fillRect(s.x, s.y, s.size, s.size);
      });
      requestAnimationFrame(animate);
    };
    animate();

    const handleResize = () => {
      w = canvas.width = window.innerWidth;
      h = canvas.height = window.innerHeight;
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleScan = async () => {
    if (isScanning) return;
    setIsScanning(true);
    setScanMessage('SCANNING DEEP WEB...');

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const prompt = `Generate a unique, creative pixel-art style character for a cyberpunk RPG game.
      Return ONLY a JSON object with this structure:
      {
        "name": "Character Name",
        "class": "Class Name (e.g. Hacker, Ronin)",
        "description": "Short description (max 10 words)",
        "story": "A short, interesting backstory (approx 30-50 words).",
        "color": "Hex Color Code (bright neon color)",
        "spriteMatrix": [array of 25 integers, 0 or 1, representing a 5x5 pixel grid shape]
      }
      Do not include markdown code blocks. Just the JSON.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const text = response.text;
      if (text) {
        const newCharData = JSON.parse(text);
        const newChar: PixelChar = {
          id: `gen_${Date.now()}`,
          ...newCharData
        };
        setCharacters(prev => [...prev, newChar]);
        setScanMessage('SIGNAL ACQUIRED!');
        setTimeout(() => setScanMessage(''), 2000);
      }
    } catch (e) {
      console.error(e);
      setScanMessage('SIGNAL LOST.');
      setTimeout(() => setScanMessage(''), 2000);
    } finally {
      setIsScanning(false);
    }
  };

  const PixelSprite = ({ matrix, color, size = 4 }: { matrix: number[], color: string, size?: number }) => (
    <div className="grid grid-cols-5 gap-px bg-transparent" style={{ width: size * 5 + 4, height: size * 5 + 4 }}>
      {matrix.map((val, i) => (
        <div 
          key={i} 
          style={{ 
            backgroundColor: val ? color : 'transparent',
            width: size,
            height: size
          }} 
        />
      ))}
    </div>
  );

  return (
    <div className="relative min-h-screen font-pixel text-white overflow-hidden bg-black selection:bg-[#a855f7] selection:text-white">
      {/* Canvas Background */}
      <canvas id="starfield" className="fixed inset-0 z-0 pointer-events-none opacity-50"></canvas>

      {/* Main Container */}
      <div className="relative z-10 flex flex-col h-screen">

        {/* Header UI */}
        <header className="p-6 flex justify-between items-center border-b-4 border-white/20 bg-black/80 backdrop-blur-sm">
          <div className="flex items-center gap-4">
            <Link to="/caibao" className="text-xs hover:text-[#a855f7] hover:underline">&lt; EXIT OS</Link>
            <h1 className="text-xl md:text-2xl text-[#a855f7] drop-shadow-[2px_2px_0_rgba(255,255,255,0.3)]">
              DARK STAR <span className="text-white text-xs block md:inline md:ml-2">PROTOCOL v3.0</span>
            </h1>
          </div>
          <div className="text-right">
             <div className="text-[10px] text-gray-400">CREDITS</div>
             <div className="text-yellow-400">∞</div>
          </div>
        </header>

        {/* Game Area */}
        <div className="flex-1 overflow-auto p-4 md:p-8">

          {/* Controls */}
          <div className="flex justify-center mb-8">
            <button 
              onClick={handleScan}
              disabled={isScanning}
              className={`
                px-6 py-4 border-4 border-white bg-black hover:bg-white hover:text-black transition-all
                active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed
                text-sm md:text-base tracking-widest uppercase shadow-[4px_4px_0_rgba(168,85,247,0.5)]
              `}
            >
              {isScanning ? (
                <span className="animate-pulse">SCANNING...</span>
              ) : (
                <>
                  <i className="fas fa-satellite-dish mr-2"></i> SCAN SIGNAL
                </>
              )}
            </button>
          </div>

          {scanMessage && (
            <div className="text-center mb-8 text-[#00ff00] text-sm animate-bounce">
              {scanMessage}
            </div>
          )}

          {/* Character Grid */}
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6 max-w-6xl mx-auto">
            {characters.map((char) => (
              <div 
                key={char.id}
                onClick={() => setSelectedChar(char)}
                className="
                  group relative aspect-square bg-gray-900 border-4 border-gray-700 
                  hover:border-[#a855f7] hover:-translate-y-2 hover:shadow-[0_0_15px_rgba(168,85,247,0.4)]
                  transition-all cursor-pointer flex flex-col items-center justify-center p-4
                "
              >
                {/* Pixel Art Representation */}
                <div className="transform scale-[3] group-hover:scale-[3.5] transition-transform duration-300 image-pixelated mb-4">
                   <PixelSprite matrix={char.spriteMatrix} color={char.color} size={3} />
                </div>

                <div className="text-center z-10">
                  <div className="text-[10px] text-gray-400 mb-1">{char.class}</div>
                  <div className="text-xs font-bold truncate w-full px-2" style={{ color: char.color }}>{char.name}</div>
                </div>

                {/* Glitch Effect on Hover */}
                <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-5 pointer-events-none"></div>
              </div>
            ))}

            {/* Empty Slots */}
            {Array.from({length: Math.max(0, 10 - characters.length)}).map((_, i) => (
              <div key={i} className="aspect-square border-4 border-dashed border-gray-800 flex items-center justify-center opacity-30">
                 <span className="text-2xl text-gray-700">?</span>
              </div>
            ))}
          </div>

        </div>

        {/* Footer UI */}
        <footer className="p-4 bg-black border-t-4 border-white/20 text-center text-[10px] text-gray-500">
           INSERT COIN TO CONTINUE • GEMINI POWERED GENERATION
        </footer>

      </div>

      {/* Character Modal */}
      {selectedChar && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-[fadeIn_0.2s]">
          <div className="bg-gray-900 border-4 border-white w-full max-w-md relative shadow-[8px_8px_0_rgba(0,0,0,0.5)]">

            {/* Modal Header */}
            <div className="bg-white text-black p-2 flex justify-between items-center">
              <span className="text-sm font-bold">{selectedChar.name}</span>
              <button 
                onClick={() => setSelectedChar(null)} 
                className="hover:bg-red-500 hover:text-white px-2"
              >
                X
              </button>
            </div>

            {/* Modal Content */}
            <div className="p-6">
              <div className="flex gap-6 mb-6">
                 <div className="w-24 h-24 bg-black border-2 border-gray-600 flex items-center justify-center shrink-0">
                    <div className="transform scale-[4]">
                       <PixelSprite matrix={selectedChar.spriteMatrix} color={selectedChar.color} size={2} />
                    </div>
                 </div>
                 <div>
                    <div className="text-xs text-gray-400 mb-1">CLASS: <span className="text-white">{selectedChar.class}</span></div>
                    <div className="text-xs text-gray-400 mb-1">STATUS: <span className="text-[#00ff00]">ONLINE</span></div>
                    <p className="text-xs text-[#a855f7] mt-2">{selectedChar.description}</p>
                 </div>
              </div>

              <div className="bg-black border-2 border-gray-700 p-4 mb-6">
                <p className="text-xs leading-loose text-gray-300 font-sans">
                  {selectedChar.story}
                </p>
              </div>

              {selectedChar.isSquad && selectedChar.squadId && (
                <button 
                  onClick={() => navigate('/terminal', { state: { squadMember: SQUAD_MEMBERS[selectedChar.squadId!] } })}
                  className="w-full py-3 bg-[#a855f7] hover:bg-[#9333ea] text-white text-xs font-bold uppercase tracking-widest border-b-4 border-[#7e22ce] active:border-t-4 active:border-b-0"
                >
                  ESTABLISH LINK
                </button>
              )}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

