    const state = location.state as { autoAnalyzeText?: string };
    if (state?.autoAnalyzeText && !isAnalyzing) {
        setInput("基于以下内容进行知识点分析和图谱更新：\n" + state.autoAnalyzeText);
        // Automatically trigger analysis
        handleAnalyze(state.autoAnalyzeText);
        // Clear state to prevent re-run (React Router handles this, but good practice)
        window.history.replaceState({}, '');
    }
  }, [location.state]);

  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  // --- Dynamic Radar Calculation ---
  useEffect(() => {
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };

    const theory = calculateAverage(n => n.category === 'root' || n.category === 'core');
    const logic = calculateAverage(n => n.id.includes('ds') || n.id.includes('algo') || n.label.includes('逻辑') || n.label.includes('算法'));
    const practice = calculateAverage(n => n.category === 'sub');
    const memory = calculateAverage(n => true);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovationBonus = memory > 80 ? 10 : 0;
    const innovation = Math.min(100, Math.round(innovationBase + innovationBonus));

    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);

  }, [nodes]);

  // --- AI Analysis ---
  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true); // Ensure panel is open to show results

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);
        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              const newVal = Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange));
              return { ...node, masteryLevel: newVal };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传成绩单: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄试题: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  const handleNodeClick = (node: KnowledgeNode) => {
    navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleRadarClick = (subject: string) => {
    navigate(`/knowledge-graph/analysis/${encodeURIComponent(subject)}`, { state: { score: radarData.find(r => r.subject === subject)?.A } });
  };

  const getNodeColor = (mastery: number) => {
    if (mastery < 50) return '#f43f5e';
    if (mastery < 80) return '#f59e0b';
    return '#10b981';
  };

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;

    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full">
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}
         <polygon 
            points={points} 
            fill="var(--kg-primary)" 
            fillOpacity="0.4" 
            stroke="var(--kg-primary)" 
            strokeWidth="2" 
            className="transition-all duration-500 ease-in-out" 
         />
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text 
                key={i} 
                x={x} 
                y={y} 
                textAnchor="middle" 
                dominantBaseline="middle" 
                fontSize="9" 
                fill="var(--kg-text)"
                className="cursor-pointer hover:font-bold transition-all"
                onClick={() => handleRadarClick(d.subject)}
              >
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  const ControlPanelContent = () => (
    <div className="flex flex-col h-full">
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-bold text-kg-text">数据控制台</h2>
            <button onClick={() => setIsPanelOpen(false)} className="md:hidden text-kg-text"><i className="fas fa-times"></i></button>
        </div>

        {/* Capability Radar */}
        <div className="mb-4 p-2 bg-kg-bg rounded-2xl shadow-inner border border-kg-primary/10 flex flex-col items-center shrink-0">
            <h3 className="text-xs font-bold uppercase tracking-wider mb-2 text-kg-primary">能力雷达</h3>
            <div className="w-40 h-40">
            {renderRadar()}
            </div>
            {analysisResult && (
            <div className="mt-1 text-center">
                <div className="text-[10px] text-kg-text opacity-70">预测成绩</div>
                <div className="text-2xl font-bold text-kg-secondary">{analysisResult.predictedScore}</div>
            </div>
            )}
        </div>

        {/* Analysis Results */}
        <div className="flex-grow overflow-y-auto mb-4 min-h-[100px] bg-kg-bg rounded-xl p-3 border border-kg-primary/10">
            {analysisResult ? (
            <div className="animate-[fadeInUp_0.3s_ease-out]">
                <h4 className="font-bold text-kg-primary mb-2 text-sm"><i className="fas fa-lightbulb mr-1"></i> 改善建议</h4>
                <p className="text-xs mb-3 leading-relaxed">{analysisResult.analysis}</p>
                <ul className="text-xs space-y-1 text-kg-text opacity-80 pl-2">
                    {analysisResult.suggestions.map((s, i) => (
                    <li key={i}>• {s}</li>
                    ))}
                </ul>
            </div>
        ) : (
            <div className="flex flex-col items-center justify-center h-full text-center text-xs text-kg-text opacity-50 italic">
                <i className="fas fa-inbox text-2xl mb-2"></i>
                <p>暂无分析数据</p>
                <p className="text-[10px] mt-1">从其他模组同步或手动输入</p>
            </div>
        )}
        </div>

        {/* Input Area */}
        <div className="mt-auto bg-kg-bg p-2 rounded-2xl shadow-soft border border-kg-primary/20 flex items-center gap-2 transition-colors">
        <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full transition-colors"
        >
            <i className="fas fa-folder-open"></i>
        </button>
            <button 
            onClick={() => setShowCamera(true)}
            className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full transition-colors"
        >
            <i className="fas fa-camera"></i>
        </button>
        <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
            placeholder="手动输入知识点或题目..."
            className="flex-1 bg-transparent border-none outline-none text-xs p-2 text-kg-text"
            disabled={isAnalyzing}
        />
        <button 
            onClick={() => handleAnalyze()}
            disabled={!input.trim() || isAnalyzing}
            className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
            input.trim() ? 'bg-kg-primary text-white shadow-md' : 'bg-gray-200 dark:bg-gray-700 text-gray-400'
            }`}
        >
            {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : '分析'}
        </button>
        </div>
    </div>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/80 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/80 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full md:hidden">
              <i className="fas fa-bars"></i>
          </button>
          <button onClick={toggleTheme} className="text-kg-primary w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area (Full Screen) */}
      <div className="absolute inset-0 z-0">
          <svg className="w-full h-full bg-kg-bg" viewBox="0 0 1000 800" preserveAspectRatio="xMidYMid slice">
            <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
               <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.3" />
            </pattern>
            <rect width="100%" height="100%" fill="url(#grid)" />

            {links.map((link, i) => {
              const src = nodes.find(n => n.id === link.source);
              const tgt = nodes.find(n => n.id === link.target);
              if (!src || !tgt) return null;
              return (
                <line 
                  key={i}
                  x1={src.x} y1={src.y}
                  x2={tgt.x} y2={tgt.y}
                  stroke="var(--kg-line)"
                  strokeWidth="2"
                  opacity="0.6"
                />
              );
            })}

            {nodes.map((node) => {
              const isHovered = hoveredNode === node.id;
              const baseR = node.category === 'root' ? 40 : node.category === 'core' ? 30 : 20;
              const r = isHovered ? baseR + 5 : baseR;

              return (
                <g 
                  key={node.id} 
                  transform={`translate(${node.x},${node.y})`}
                  onClick={() => handleNodeClick(node)}
                  onMouseEnter={() => setHoveredNode(node.id)}
                  onMouseLeave={() => setHoveredNode(null)}
                  className="cursor-pointer transition-all duration-300"
                >
                  <circle 
                    r={r} 
                    fill={getNodeColor(node.masteryLevel)}
                    stroke="var(--kg-bg)"
                    strokeWidth={isHovered ? 6 : 4}
                    className="shadow-md transition-all duration-300 ease-out drop-shadow-lg"
                  />
                  <text 
                    y={node.category === 'root' ? 60 : 50} 
                    textAnchor="middle" 
                    fontSize="16" 
                    fontWeight="bold" 
                    fill="var(--kg-text)"
                    className="pointer-events-none select-none bg-kg-bg"
                    style={{ textShadow: '0 2px 4px rgba(255,255,255,0.8)' }}
                  >
                    {node.label}
                  </text>
                  <text 
                    y={6} 
                    textAnchor="middle" 
                    dominantBaseline="middle"
                    fontSize={isHovered ? 16 : 14} 
                    fontWeight="bold" 
                    fill="#fff"
                    className="pointer-events-none transition-all duration-300 select-none"
                  >
                    {node.masteryLevel}%
                  </text>
                </g>
              );
            })}
          </svg>
      </div>

      {/* Floating Control Panel (Desktop: Right Side, Mobile: Bottom Sheet via state) */}
      <div 
        className={`
            fixed right-6 top-24 bottom-6 w-96 bg-kg-card/90 backdrop-blur-xl 
            border border-gray-200 dark:border-gray-700 rounded-3xl shadow-2xl z-20
            transform transition-transform duration-300 ease-out p-6 flex flex-col
            ${isPanelOpen ? 'translate-x-0' : 'translate-x-[120%]'}
            hidden md:flex
        `}
      >
        <ControlPanelContent />
      </div>

      {/* Mobile Bottom Sheet */}
      <div 
        className={`
            md:hidden fixed inset-x-0 bottom-0 z-40 bg-kg-card rounded-t-3xl shadow-[0_-5px_20px_rgba(0,0,0,0.2)] 
            border-t border-kg-primary/20 transition-transform duration-500 ease-in-out
            flex flex-col h-[80vh]
            ${isPanelOpen ? 'translate-y-0' : 'translate-y-[100%]'}
        `}
      >
           <div className="flex-1 p-6 overflow-y-auto">
              <ControlPanelContent />
           </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION, ThemeContext } from '../constants';
import { GenerateContentResponse } from '@google/genai';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

export const Office: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'model', content: string}[]>([
    { role: 'model', content: '您好，灵境办公助手已就绪。请上传会议录音或输入指令。' }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: OFFICE_SYSTEM_INSTRUCTION },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.content }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        const text = (chunk as GenerateContentResponse).text || '';
        fullText += text;
        setMessages(prev => {
          const newArr = [...prev];
          newArr[newArr.length - 1].content = fullText;
          return newArr;
        });
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', content: '网络连接异常，请重试。' }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    // Collect context
    const context = messages.slice(-5).map(m => m.content).join('\n');
    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传文件: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄照片: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  const QuickAction = ({ icon, label, prompt }: { icon: string, label: string, prompt: string }) => (
    <button 
      onClick={() => { setInput(prompt); }}
      className="flex flex-col items-center justify-center p-4 bg-office-card rounded-xl shadow-card hover:shadow-soft transition-all duration-200 border border-office-border hover:border-office-primary/30"
    >
      <div className="w-10 h-10 rounded-full bg-office-accent flex items-center justify-center text-office-primary mb-2 text-lg">
        <i className={`fas ${icon}`}></i>
      </div>
      <span className="text-xs text-office-text font-medium">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-office-bg font-sans text-office-text transition-colors duration-300">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      {/* Hidden Inputs */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

      {/* Unified Header */}
      <div className="bg-office-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-office-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-office-sub hover:text-office-primary transition-colors rounded-full hover:bg-office-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">灵境 <span className="text-office-primary font-light">| 办公</span></h1>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleSyncToKG}
             className="text-office-sub hover:text-office-primary px-3 py-1 text-sm border border-transparent hover:border-office-border rounded transition-all"
             title="提取知识点到图谱"
           >
             <i className="fas fa-project-diagram mr-1"></i> 知识提取
           </button>
           <button onClick={toggleTheme} className="text-office-sub hover:text-office-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-office-sub" />
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col max-w-4xl w-full mx-auto p-4 overflow-hidden">

        {/* Quick Actions Panel */}
        {messages.length < 3 && (
          <div className="grid grid-cols-4 gap-4 mb-6 animate-[fadeInUp_0.5s_ease-out]">
            <QuickAction icon="fa-microphone-alt" label="会议转写" prompt="请模拟一段会议录音的转写，并整理成结构化的会议纪要，包含待办事项。" />
            <QuickAction icon="fa-file-powerpoint" label="一键PPT" prompt="请为我生成一份关于“2025年AI应用趋势”的PPT大纲，共5页，包含视觉建议。" />
            <QuickAction icon="fa-tasks" label="任务编排" prompt="我有以下任务：周三交报告，明天下午开会，周五团建。请帮我生成本周日程表。" />
            <QuickAction icon="fa-calendar-check" label="日程同步" prompt="检查我的日历冲突..." />
          </div>
        )}

        {/* Chat Area */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto mb-4 space-y-4 pr-2">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-office-primary text-white rounded-br-none' 
                  : 'bg-office-card text-office-text border border-office-border rounded-bl-none'
              }`}>
                {msg.role === 'model' && !msg.content ? <span className="typing-cursor"></span> : <div className="whitespace-pre-wrap">{msg.content}</div>}
              </div>
            </div>
          ))}
        </div>

        {/* Input */}
        <div className="bg-office-card p-2 rounded-2xl shadow-soft border border-office-border flex items-center gap-2 transition-colors">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="w-10 h-10 flex items-center justify-center text-office-sub hover:text-office-primary rounded-full hover:bg-office-bg transition-colors"
            title="上传文件"
          >
            <i className="fas fa-folder-open"></i>
          </button>
           <button 
            onClick={() => setShowCamera(true)}
            className="w-10 h-10 flex items-center justify-center text-office-sub hover:text-office-primary rounded-full hover:bg-office-bg transition-colors"
            title="拍照"
          >
            <i className="fas fa-camera"></i>
          </button>
          <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="输入指令或上传文件..."
            className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-office-text"
            disabled={isProcessing}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isProcessing}
            className={`px-6 py-2 rounded-xl text-sm font-medium transition-all ${
              input.trim() ? 'bg-office-primary text-white shadow-md' : 'bg-office-bg text-office-sub'
            }`}
          >
            发送
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { EDU_SYSTEM_INSTRUCTION, ThemeContext } from '../constants';
import { GenerateContentResponse } from '@google/genai';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

export const Education: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'model', content: string}[]>([
    { role: 'model', content: '嗨！我是你的AI导学助手。今天想学点什么？📐 🌍 🧬' }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: EDU_SYSTEM_INSTRUCTION },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.content }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        const text = (chunk as GenerateContentResponse).text || '';
        fullText += text;
        setMessages(prev => {
          const newArr = [...prev];
          newArr[newArr.length - 1].content = fullText;
          return newArr;
        });
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', content: '哎呀，大脑短路了，重试一下吧！' }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    // Collect context
    const context = messages.slice(-5).map(m => m.content).join('\n');
    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传资料: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄作业: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  const SubjectCard = ({ color, icon, label, prompt }: { color: string, icon: string, label: string, prompt: string }) => (
    <button 
      onClick={() => setInput(prompt)}
      className={`relative overflow-hidden p-4 rounded-2xl shadow-card hover:shadow-lg transition-all duration-300 transform hover:-translate-y-1 text-left flex flex-col justify-between h-28 group`}
      style={{ backgroundColor: color }}
    >
      <div className="text-white text-opacity-90 font-bold text-lg">{label}</div>
      <div className="absolute -bottom-4 -right-4 text-6xl text-white opacity-20 transform group-hover:scale-110 transition-transform">
        <i className={`fas ${icon}`}></i>
      </div>
      <div className="text-white text-xs opacity-80 mt-2 bg-black/10 inline-block px-2 py-1 rounded w-max backdrop-blur-sm">点击探索 &rarr;</div>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-edu-bg font-sans text-edu-text transition-colors duration-300">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      {/* Hidden Inputs */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

      {/* Unified Header */}
      <div className="bg-edu-card/80 backdrop-blur px-6 py-4 flex justify-between items-center shadow-sm sticky top-0 z-20 border-b border-edu-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-edu-sub hover:text-edu-primary transition-colors rounded-full hover:bg-edu-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold text-edu-text">灵境 · 导学</h1>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleSyncToKG}
             className="text-edu-sub hover:text-edu-primary px-3 py-1 text-sm border border-transparent hover:border-edu-border rounded transition-all"
             title="分析并存入知识图谱"
           >
             <i className="fas fa-project-diagram mr-1"></i> 存入图谱
           </button>
           <button onClick={toggleTheme} className="text-edu-sub hover:text-edu-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-edu-sub" />
        </div>
      </div>

      <div className="flex-1 flex flex-col max-w-4xl w-full mx-auto p-4 overflow-hidden relative">

        {/* Floating Shapes Background */}
        <div className="absolute top-10 left-10 w-32 h-32 bg-yellow-300 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-10 right-10 w-32 h-32 bg-pink-300 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse animation-delay-2000"></div>

        {/* Subject Cards */}
        {messages.length < 3 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6 z-10 animate-[fadeInUp_0.5s_ease-out]">
            <SubjectCard color="#ff8c42" icon="fa-calculator" label="数学解题" prompt="请演示这道几何题的解题步骤：已知直角三角形斜边长为10，一条直角边为6，求另一条边及面积。" />
            <SubjectCard color="#4caf50" icon="fa-flask" label="科学实验" prompt="请解释牛顿第二定律，并举一个生活中的例子。" />
            <SubjectCard color="#5c6bc0" icon="fa-landmark" label="历史回溯" prompt="请生成一条关于辛亥革命关键事件的交互式时间轴。" />
            <SubjectCard color="#ec407a" icon="fa-book-open" label="知识萃取" prompt="我有一段长视频课程，请帮我提炼关于‘光合作用’的核心知识点卡片。" />
          </div>
        )}

        {/* Chat Stream */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto mb-4 space-y-6 pr-2 z-10">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start items-end gap-2'}`}>
              {msg.role === 'model' && (
                <div className="w-8 h-8 rounded-full bg-edu-card border border-edu-accent flex items-center justify-center text-edu-primary shadow-sm mb-1 shrink-0">
                  <i className="fas fa-robot"></i>
                </div>
              )}
              <div className={`max-w-[80%] p-5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-edu-primary text-white rounded-br-none shadow-orange-200' 
                  : 'bg-edu-card text-edu-text border border-edu-accent rounded-bl-none'
              }`}>
                {msg.role === 'model' && !msg.content ? <span className="typing-cursor"></span> : <div className="whitespace-pre-wrap">{msg.content}</div>}
              </div>
            </div>
          ))}
        </div>

        {/* Input Bar */}
        <div className="bg-edu-card p-2 rounded-full shadow-lg border border-edu-accent z-10 flex items-center gap-2 pl-4 transition-colors">
          <button 
             onClick={() => fileInputRef.current?.click()}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="上传文件"
          >
             <i className="fas fa-folder-open"></i>
          </button>
          <button 
             onClick={() => setShowCamera(true)}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="拍照解题"
          >
            <i className="fas fa-camera"></i>
          </button>
          <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="有问题尽管问我..."
            className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-edu-text placeholder-edu-sub/50"
            disabled={isProcessing}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isProcessing}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
              input.trim() ? 'bg-edu-primary text-white rotate-0' : 'bg-edu-bg text-edu-sub -rotate-90'
            }`}
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, KG_SYSTEM_INSTRUCTION, INITIAL_NODES, INITIAL_LINKS, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const location = useLocation();

  // Data State
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // Interaction State
  const [hoveredNode, setHoveredNode] = useState<string | null>(null);
  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); // Default to Star for better initial view
  const [isPanelOpen, setIsPanelOpen] = useState(true);

  // Canvas Transform State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Layout Algorithms ---
  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    const width = window.innerWidth;
    const height = window.innerHeight;
    const centerX = 0; // Relative to transform origin
    const centerY = 0;

    return currentNodes.map((node, index) => {
      let x = 0;
      let y = 0;

      switch (type) {
        case 'mesh':
          // Random scatter with a bit of grid logic
          x = (Math.random() - 0.5) * 800;
          y = (Math.random() - 0.5) * 600;
          break;

        case 'star':
          if (node.category === 'root') {
            x = 0; y = 0;
          } else {
            const level = node.category === 'core' ? 1 : 2;
            const radius = 150 * level;
            const totalInLevel = currentNodes.filter(n => 
              (level === 1 && n.category === 'core') || (level === 2 && n.category === 'sub')
            ).length || 1;
            const myIndex = currentNodes.filter(n => 
              (level === 1 && n.category === 'core') || (level === 2 && n.category === 'sub')
            ).indexOf(node);
            const angle = (myIndex / totalInLevel) * Math.PI * 2;
            x = Math.cos(angle) * radius;
            y = Math.sin(angle) * radius;
          }
          break;

        case 'bus':
          // Linear horizontal
          const sorted = [...currentNodes].sort((a, b) => {
             const order = { root: 0, core: 1, sub: 2 };
             return (order[a.category as keyof typeof order] || 9) - (order[b.category as keyof typeof order] || 9);
          });
          const idx = sorted.indexOf(node);
          x = (idx - sorted.length / 2) * 180;
          y = (idx % 2 === 0 ? -50 : 50); // Slight zigzag
          break;

        case 'tree':
          // Upward growth: Root at bottom (positive Y visually down, so negative Y is up in SVG coords if we center)
          // Let's make Root at Y=200, Core at 0, Sub at -200
          if (node.category === 'root') y = 200;
          else if (node.category === 'core') y = 0;
          else y = -200;

          // Spread X
          const peers = currentNodes.filter(n => n.category === node.category);
          const pIdx = peers.indexOf(node);
          x = (pIdx - peers.length / 2 + 0.5) * 160;
          break;

        case 'evolution':
          // Wave form left to right
          x = (index - currentNodes.length / 2) * 120;
          y = Math.sin(index * 0.8) * 150;
          break;
      }

      return { ...node, x, y };
    });
  }, []);

  // Initialize Layout & Centering
  useEffect(() => {
    // Set initial transform to center of screen
    setTransform({ 
        x: window.innerWidth / 2, 
        y: window.innerHeight / 2, 
        k: 1 
    });
    // Apply initial layout
    setNodes(prev => applyLayout('star', prev));
  }, [applyLayout]);

  // Update layout when type changes
  useEffect(() => {
    setNodes(prev => applyLayout(layout, prev));
  }, [layout, applyLayout]);


  // --- Event Handlers for Pan/Zoom ---
  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        // Zoom
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        // Pan
        setTransform(t => ({
            ...t,
            x: t.x - e.deltaX,
            y: t.y - e.deltaY
        }));
    }
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    // Only drag if clicking on background (svg), not a node
    if ((e.target as Element).tagName === 'circle' || (e.target as Element).tagName === 'text') return;

    setIsDragging(true);
    dragStart.current = { x: e.clientX - transform.x, y: e.clientY - transform.y };
    (e.target as Element).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    setTransform(t => ({
        ...t,
        x: e.clientX - dragStart.current.x,
        y: e.clientY - dragStart.current.y
    }));
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    setIsDragging(false);
    (e.target as Element).releasePointerCapture(e.pointerId);
  };


  // --- Auto Analyze & Logic ---
  useEffect(() => {
    const state = location.state as { autoAnalyzeText?: string };
    if (state?.autoAnalyzeText && !isAnalyzing) {
        setInput("基于以下内容进行知识点分析和图谱更新：\n" + state.autoAnalyzeText);
        handleAnalyze(state.autoAnalyzeText);
        window.history.replaceState({}, '');
    }
  }, [location.state]);

  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  useEffect(() => {
    // Dynamic Radar Calculation (Same as before)
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };

    const theory = calculateAverage(n => n.category === 'root' || n.category === 'core');
    const logic = calculateAverage(n => n.id.includes('ds') || n.id.includes('algo'));
    const practice = calculateAverage(n => n.category === 'sub');
    const memory = calculateAverage(n => true);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovation = Math.min(100, Math.round(innovationBase + (memory > 80 ? 10 : 0)));

    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);
  }, [nodes]);

  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);
        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              return { ...node, masteryLevel: Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange)) };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleEmptyStateClick = () => {
    if (inputRef.current) {
        inputRef.current.focus();
        // Optional: flash animation
        inputRef.current.classList.add('ring-2', 'ring-kg-primary');
        setTimeout(() => inputRef.current?.classList.remove('ring-2', 'ring-kg-primary'), 1000);
    }
  };

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;

    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full cursor-pointer" onClick={() => navigate(`/knowledge-graph/analysis/综合能力`)}>
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}
         <polygon 
            points={points} 
            fill="var(--kg-primary)" 
            fillOpacity="0.4" 
            stroke="var(--kg-primary)" 
            strokeWidth="2" 
            className="transition-all duration-500 ease-in-out hover:fill-opacity-60" 
         />
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text 
                key={i} 
                x={x} 
                y={y} 
                textAnchor="middle" 
                dominantBaseline="middle" 
                fontSize="9" 
                fill="var(--kg-text)"
              >
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button 
      onClick={() => setLayout(type)}
      className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`}
      title={label}
    >
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full md:hidden">
              <i className="fas fa-bars"></i>
          </button>
          <button onClick={toggleTheme} className="text-kg-primary w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area (Infinite Pan/Zoom) */}
      <div 
        ref={containerRef}
        className="absolute inset-0 z-0 cursor-move touch-none bg-kg-bg"
        onWheel={handleWheel}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
      >
          <svg className="w-full h-full overflow-visible">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
            </defs>

            {/* Background Grid */}
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" />

            {/* Transform Group */}
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    return (
                        <line 
                        key={i}
                        x1={src.x} y1={src.y}
                        x2={tgt.x} y2={tgt.y}
                        stroke="var(--kg-line)"
                        strokeWidth="1.5"
                        strokeOpacity="0.4"
                        strokeLinecap="round"
                        />
                    );
                })}

                {nodes.map((node) => {
                    const isHovered = hoveredNode === node.id;
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isHovered ? baseR * 1.2 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';

                    return (
                        <g 
                            key={node.id} 
                            transform={`translate(${node.x},${node.y})`}
                            onClick={(e) => { e.stopPropagation(); navigate(`/knowledge-graph/node/${node.id}`, { state: { node } }); }}
                            onMouseEnter={() => setHoveredNode(node.id)}
                            onMouseLeave={() => setHoveredNode(null)}
                            className="cursor-pointer transition-all duration-300"
                        >
                            {/* Halo effect for high mastery */}
                            {node.masteryLevel > 90 && (
                                <circle r={r * 1.5} fill={color} fillOpacity="0.1" className="animate-pulse" />
                            )}

                            <circle 
                                r={r} 
                                fill={color}
                                stroke="var(--kg-bg)"
                                strokeWidth={3}
                                className="shadow-sm transition-all duration-300"
                            />

                            {/* Label Background for readability */}
                            <rect 
                                x={-node.label.length * 6} 
                                y={r + 8} 
                                width={node.label.length * 12} 
                                height="20" 
                                rx="4"
                                fill="var(--kg-bg)" 
                                fillOpacity="0.8"
                                className="pointer-events-none"
                            />

                            <text 
                                y={r + 22} 
                                textAnchor="middle" 
                                fontSize="12" 
                                fontWeight="bold" 
                                fill="var(--kg-text)"
                                className="pointer-events-none select-none"
                                style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}
                            >
                                {node.label}
                            </text>

                            {isHovered && (
                                <text 
                                    y={5} 
                                    textAnchor="middle" 
                                    fontSize="10" 
                                    fill="#fff" 
                                    fontWeight="bold"
                                    className="pointer-events-none"
                                >
                                    {node.masteryLevel}%
                                </text>
                            )}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      {/* Floating Layout Controls (Bottom Left) */}
      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="科技树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      {/* Floating Control Panel (Right Side) */}
      <div 
        className={`
            fixed right-6 top-24 bottom-6 w-96 bg-kg-card/90 backdrop-blur-xl 
            border border-gray-200 dark:border-gray-700 rounded-3xl shadow-2xl z-20
            transform transition-transform duration-300 ease-out p-6 flex flex-col pointer-events-auto
            ${isPanelOpen ? 'translate-x-0' : 'translate-x-[120%]'}
            hidden md:flex
        `}
      >
          <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-bold text-kg-text">数据控制台</h2>
              <div className="text-xs text-kg-primary px-2 py-1 bg-kg-primary/10 rounded-full font-mono">
                  NODES: {nodes.length}
              </div>
          </div>

          <div className="mb-4 p-2 bg-kg-bg rounded-2xl shadow-inner border border-kg-primary/10 flex flex-col items-center shrink-0">
             <h3 className="text-xs font-bold uppercase tracking-wider mb-2 text-kg-primary">能力雷达</h3>
             <div className="w-40 h-40">{renderRadar()}</div>
          </div>

          <div 
            className="flex-grow overflow-y-auto mb-4 min-h-[100px] bg-kg-bg rounded-xl p-1 border border-kg-primary/10 cursor-pointer hover:border-kg-primary/30 transition-colors group"
            onClick={analysisResult ? undefined : handleEmptyStateClick}
            title={!analysisResult ? "点击开始输入" : ""}
          >
              {analysisResult ? (
                <div className="p-3 animate-[fadeInUp_0.3s_ease-out]">
                    <h4 className="font-bold text-kg-primary mb-2 text-sm"><i className="fas fa-lightbulb mr-1"></i> 改善建议</h4>
                    <p className="text-xs mb-3 leading-relaxed">{analysisResult.analysis}</p>
                    <ul className="text-xs space-y-1 text-kg-text opacity-80 pl-2">
                        {analysisResult.suggestions.map((s, i) => (
                        <li key={i}>• {s}</li>
                        ))}
                    </ul>
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center h-full text-center text-xs text-kg-text opacity-50 italic group-hover:opacity-80 group-hover:text-kg-primary transition-all">
                    <i className="fas fa-edit text-2xl mb-2 group-hover:scale-110 transition-transform"></i>
                    <p>暂无分析数据</p>
                    <p className="text-[10px] mt-1">点击此处或手动输入以开始</p>
                </div>
            )}
          </div>

          {/* Input Area */}
          <div className="mt-auto bg-kg-bg p-2 rounded-2xl shadow-soft border border-kg-primary/20 flex items-center gap-2 transition-colors focus-within:ring-2 focus-within:ring-kg-primary/20">
            <button onClick={() => fileInputRef.current?.click()} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full transition-colors"><i className="fas fa-folder-open"></i></button>
            <button onClick={() => setShowCamera(true)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full transition-colors"><i className="fas fa-camera"></i></button>
            <input 
                ref={inputRef}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
                placeholder="输入知识点或题目..."
                className="flex-1 bg-transparent border-none outline-none text-xs p-2 text-kg-text placeholder-gray-400"
                disabled={isAnalyzing}
            />
            <button 
                onClick={() => handleAnalyze()}
                disabled={!input.trim() || isAnalyzing}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${input.trim() ? 'bg-kg-primary text-white shadow-md' : 'bg-gray-200 dark:bg-gray-700 text-gray-400'}`}
            >
                {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : '分析'}
            </button>
          </div>
      </div>

      {/* Mobile Bottom Sheet (Simplified for brevity, similar structure) */}
       <div className={`md:hidden fixed inset-x-0 bottom-0 z-40 bg-kg-card rounded-t-3xl shadow-[0_-5px_20px_rgba(0,0,0,0.2)] border-t border-kg-primary/20 transition-transform duration-500 ease-in-out flex flex-col h-[70vh] pointer-events-auto ${isPanelOpen ? 'translate-y-0' : 'translate-y-[100%]'}`}>
           <div className="flex-1 p-6 overflow-y-auto">
               <div className="flex justify-between items-center mb-4">
                  <h2 className="text-lg font-bold text-kg-text">数据控制台</h2>
                  <button onClick={() => setIsPanelOpen(false)}><i className="fas fa-times"></i></button>
               </div>
               <div className="mb-4 bg-kg-bg p-2 rounded-xl flex justify-center">{renderRadar()}</div>
               <div className="bg-kg-bg p-4 rounded-xl mb-4 min-h-[100px]" onClick={handleEmptyStateClick}>
                  {analysisResult ? <p className="text-xs">{analysisResult.analysis}</p> : <p className="text-center text-xs opacity-50 pt-8">暂无数据，点击输入</p>}
               </div>
               <div className="mt-auto flex gap-2">
                 <input className="flex-1 bg-kg-bg rounded p-2 text-xs" ref={inputRef} value={input} onChange={e=>setInput(e.target.value)} placeholder="输入..." />
                 <button onClick={() => handleAnalyze()} className="bg-kg-primary text-white px-4 rounded text-xs">分析</button>
               </div>
           </div>
      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, KG_SYSTEM_INSTRUCTION, INITIAL_NODES, INITIAL_LINKS, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const navigate = useNavigate();
  const location = useLocation();

  // Data State
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(true);

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink';
    startX: number;
    startY: number;
    targetId?: string; // For node drag/link start
    currentX?: number; // For temp link end
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  // --- Layout Algorithms ---
  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    return currentNodes.map((node, index) => {
      let x = 0; let y = 0;
      switch (type) {
        case 'mesh':
          x = (Math.random() - 0.5) * 800;
          y = (Math.random() - 0.5) * 600;
          break;
        case 'star':
          if (node.category === 'root') { x = 0; y = 0; } 
          else {
            const level = node.category === 'core' ? 1 : 2;
            const radius = 180 * level;
            const peers = currentNodes.filter(n => (level === 1 ? n.category === 'core' : n.category === 'sub'));
            const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
            x = Math.cos(angle) * radius;
            y = Math.sin(angle) * radius;
          }
          break;
        case 'bus':
          const sorted = [...currentNodes].sort((a, b) => (a.category === 'root' ? -1 : 1));
          x = (sorted.indexOf(node) - sorted.length/2) * 150;
          y = (sorted.indexOf(node) % 2) * 100;
          break;
        case 'tree':
          if (node.category === 'root') y = 250;
          else if (node.category === 'core') y = 0;
          else y = -250;
          const peers = currentNodes.filter(n => n.category === node.category);
          x = (peers.indexOf(node) - peers.length / 2 + 0.5) * 180;
          break;
        case 'evolution':
          x = (index - currentNodes.length / 2) * 140;
          y = Math.sin(index * 0.6) * 180;
          break;
      }
      return { ...node, x: node.x ?? x, y: node.y ?? y }; // Preserve existing if switching? No, layout resets pos usually.
    });
  }, []);

  // Initialize Center
  useEffect(() => {
    setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
    setNodes(prev => {
        // Only apply star layout if nodes don't have positions yet or strictly requested
        const hasPositions = prev.every(n => n.x !== undefined);
        return hasPositions ? prev : applyLayout('star', prev);
    });
  }, [applyLayout]);

  // Layout Switcher
  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    setNodes(prev => applyLayout(newLayout, prev));
  };

  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    // Check collision with nodes (reversed to click top elements first)
    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; // Hitbox radius
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (e.shiftKey) {
          // Start creating link
          setInteractionState({
              type: 'creatingLink',
              startX: worldX,
              startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX,
              currentY: worldY
          });
      } else {
          // Select and drag node
          setSelectedId(clickedNode.id);
          setSelectedLinkIndex(null);
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX,
              startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      // Check collision with Links (simple bounding box or distance to segment)
      // Simplified: Just clear selection if clicking bg, check links later if needed accurately.
      // For now, let's allow selecting links via SVG click event directly on line

      // Start Panning
      setInteractionState({
          type: 'panning',
          startX: clientX, // Screen coords for panning
          startY: clientY,
      });
      // Don't clear selection immediately to allow panning while editing, 
      // but if it's a pure click on BG, we clear in onClick/onPointerUp if no drag occurred.
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode' && interactionState.targetId) {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        setNodes(prev => prev.map(n => 
            n.id === interactionState.targetId 
            ? { ...n, x: worldX, y: worldY } 
            : n
        ));
    }
    else if (interactionState.type === 'creatingLink') {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        // Check drop target
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            // Create Link
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                setLinks(prev => [...prev, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }]);
            }
        }
    } else if (interactionState.type === 'panning') {
        // If moved very little, treat as click on bg -> clear selection
        if (Math.abs(clientX - interactionState.startX) < 5 && Math.abs(clientY - interactionState.startY) < 5) {
             // Optional: Clear selection on BG click
             // setSelectedId(null); 
             // setSelectedLinkIndex(null);
        }
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      // Create new node
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 0,
          x, y
      };
      setNodes(prev => [...prev, newNode]);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  // --- CRUD Operations ---
  const handleDeleteSelected = () => {
      if (selectedId) {
          if (window.confirm("确定删除该节点吗？")) {
            setNodes(prev => prev.filter(n => n.id !== selectedId));
            setLinks(prev => prev.filter(l => l.source !== selectedId && l.target !== selectedId));
            setSelectedId(null);
          }
      } else if (selectedLinkIndex !== null) {
          setLinks(prev => prev.filter((_, i) => i !== selectedLinkIndex));
          setSelectedLinkIndex(null);
      }
  };

  const updateSelectedNode = (updates: Partial<KnowledgeNode>) => {
      if (!selectedId) return;
      setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, ...updates } : n));
  };

  // Keyboard Delete
  useEffect(() => {
      const handleKey = (e: KeyboardEvent) => {
          if ((e.key === 'Delete' || e.key === 'Backspace') && (selectedId || selectedLinkIndex !== null)) {
              // Avoid deleting when typing in input
              if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;
              handleDeleteSelected();
          }
      };
      window.addEventListener('keydown', handleKey);
      return () => window.removeEventListener('keydown', handleKey);
  }, [selectedId, selectedLinkIndex]);


  // --- Auto Analyze & AI Logic ---
  useEffect(() => {
    const state = location.state as { autoAnalyzeText?: string };
    if (state?.autoAnalyzeText && !isAnalyzing) {
        setInput("基于以下内容进行知识点分析和图谱更新：\n" + state.autoAnalyzeText);
        handleAnalyze(state.autoAnalyzeText);
        window.history.replaceState({}, '');
    }
  }, [location.state]);

  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        // Fix: Strip markdown code blocks if present
        const cleanText = text.replace(/```json\n?|\n?```/g, '').trim();
        const data = JSON.parse(cleanText);

        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        if (data.updatedNodes) {
          setNodes(prev => prev.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              return { ...node, masteryLevel: Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange)) };
            }
            return node;
          }));
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("AI分析失败，请检查输入或稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  // --- Dynamic Radar ---
  useEffect(() => {
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };

    const theory = calculateAverage(n => n.category === 'root' || n.category === 'core');
    const logic = calculateAverage(n => n.id.includes('ds') || n.id.includes('algo'));
    const practice = calculateAverage(n => n.category === 'sub');
    const memory = calculateAverage(n => true);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovation = Math.min(100, Math.round(innovationBase + (memory > 80 ? 10 : 0)));

    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);
  }, [nodes]);

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;

    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full cursor-pointer" onClick={() => navigate(`/knowledge-graph/analysis/综合能力`, {state: {score: analysisResult?.predictedScore || 75}})}>
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}
         <polygon 
            points={points} 
            fill="var(--kg-primary)" 
            fillOpacity="0.4" 
            stroke="var(--kg-primary)" 
            strokeWidth="2" 
            className="transition-all duration-500 ease-in-out hover:fill-opacity-60" 
         />
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text key={i} x={x} y={y} textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="var(--kg-text)">
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button 
      onClick={() => handleLayoutChange(type)}
      className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`}
      title={label}
    >
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full md:hidden">
              <i className="fas fa-bars"></i>
          </button>
          <button onClick={toggleTheme} className="text-kg-primary w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area */}
      <div 
        ref={containerRef}
        className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg"
        onWheel={handleWheel}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
        onDoubleClick={handleDoubleClickBg}
      >
          <svg className="w-full h-full overflow-visible">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>

            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" />

            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {/* Links */}
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             {/* Thicker invisible line for hit area */}
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line 
                                x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y}
                                stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'}
                                strokeWidth={isSelected ? 3 : 1.5}
                                strokeOpacity={isSelected ? 1 : 0.6}
                                markerEnd="url(#arrowhead)"
                             />
                        </g>
                    );
                })}

                {/* Creating Temp Link */}
                {interactionState.type === 'creatingLink' && (
                    <line 
                        x1={interactionState.startX} y1={interactionState.startY}
                        x2={interactionState.currentX} y2={interactionState.currentY}
                        stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5"
                    />
                )}

                {/* Nodes */}
                {nodes.map((node) => {
                    const isSelected = selectedId === node.id;
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';

                    return (
                        <g 
                            key={node.id} 
                            transform={`translate(${node.x},${node.y})`}
                            onDoubleClick={(e) => handleNodeDoubleClick(e, node)}
                            className="cursor-pointer transition-all duration-300"
                        >
                            {/* Selection Ring */}
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}

                            <circle 
                                r={r} 
                                fill={color}
                                stroke="var(--kg-bg)"
                                strokeWidth={3}
                                className="shadow-sm"
                            />

                            {/* Label */}
                            <rect 
                                x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4"
                                fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none"
                            />
                            <text 
                                y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)"
                                className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}
                            >
                                {node.label}
                            </text>

                            {/* Hover/Select Info */}
                            {(isSelected) && (
                                <text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">
                                    {node.masteryLevel}%
                                </text>
                            )}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      {/* Layout Controls */}
      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="科技树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      {/* Interaction Hint */}
      <div className="absolute top-20 left-6 z-10 pointer-events-none opacity-50 text-[10px] text-kg-text space-y-1">
        <p>• 双击空白处添加节点</p>
        <p>• Shift+拖拽连线</p>
        <p>• 双击节点查看详情</p>
        <p>• Delete键删除选中项</p>
      </div>

      {/* Side Panel (Context Aware) */}
      <div 
        className={`
            fixed right-6 top-24 bottom-6 w-96 bg-kg-card/90 backdrop-blur-xl 
            border border-gray-200 dark:border-gray-700 rounded-3xl shadow-2xl z-20
            transform transition-transform duration-300 ease-out p-6 flex flex-col pointer-events-auto
            ${isPanelOpen ? 'translate-x-0' : 'translate-x-[120%]'}
            hidden md:flex
        `}
      >
          {selectedId ? (
              // Node Edit Mode
              <div className="flex flex-col h-full animate-[fadeInUp_0.3s_ease-out]">
                  <div className="flex justify-between items-center mb-6 border-b border-kg-primary/10 pb-4">
                      <h2 className="text-lg font-bold text-kg-primary">编辑节点</h2>
                      <button onClick={() => {setSelectedId(null); setIsPanelOpen(false);}} className="text-kg-text hover:text-kg-secondary"><i className="fas fa-times"></i></button>
                  </div>

                  {nodes.find(n => n.id === selectedId) && (
                      <div className="space-y-4">
                          <div>
                              <label className="text-xs text-kg-text opacity-60">名称</label>
                              <input 
                                className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" 
                                value={nodes.find(n => n.id === selectedId)?.label}
                                onChange={(e) => updateSelectedNode({label: e.target.value})}
                              />
                          </div>
                          <div>
                              <label className="text-xs text-kg-text opacity-60">掌握度 ({nodes.find(n => n.id === selectedId)?.masteryLevel}%)</label>
                              <input 
                                type="range" min="0" max="100" 
                                className="w-full mt-2 accent-kg-primary"
                                value={nodes.find(n => n.id === selectedId)?.masteryLevel}
                                onChange={(e) => updateSelectedNode({masteryLevel: parseInt(e.target.value)})}
                              />
                          </div>
                          <div className="pt-4 flex gap-2">
                               <button 
                                 onClick={() => navigate(`/knowledge-graph/node/${selectedId}`, { state: { node: nodes.find(n => n.id === selectedId) } })}
                                 className="flex-1 bg-kg-primary text-white py-2 rounded text-sm hover:opacity-90 transition-opacity"
                               >
                                   <i className="fas fa-book-open mr-1"></i> 查看详情
                               </button>
                               <button 
                                 onClick={handleDeleteSelected}
                                 className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors"
                               >
                                   <i className="fas fa-trash"></i>
                               </button>
                          </div>
                      </div>
                  )}
              </div>
          ) : selectedLinkIndex !== null ? (
              // Link Edit Mode
               <div className="flex flex-col h-full animate-[fadeInUp_0.3s_ease-out]">
                  <div className="flex justify-between items-center mb-6 border-b border-kg-primary/10 pb-4">
                      <h2 className="text-lg font-bold text-kg-text">编辑连线</h2>
                      <button onClick={() => setSelectedLinkIndex(null)} className="text-kg-text"><i className="fas fa-times"></i></button>
                  </div>
                  <div className="space-y-4">
                      <p className="text-sm text-kg-text opacity-70">连接强度可以反映知识点之间的关联紧密程度。</p>
                      <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded hover:bg-red-100">断开连接</button>
                  </div>
               </div>
          ) : (
              // Global Dashboard Mode
              <>
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-lg font-bold text-kg-text">数据控制台</h2>
                    <div className="text-xs text-kg-primary px-2 py-1 bg-kg-primary/10 rounded-full font-mono">
                        NODES: {nodes.length}
                    </div>
                </div>

                <div className="mb-4 p-2 bg-kg-bg rounded-2xl shadow-inner border border-kg-primary/10 flex flex-col items-center shrink-0">
                    <h3 className="text-xs font-bold uppercase tracking-wider mb-2 text-kg-primary">能力雷达</h3>
                    <div className="w-40 h-40">{renderRadar()}</div>
                </div>

                <div className="flex-grow overflow-y-auto mb-4 min-h-[100px] bg-kg-bg rounded-xl p-1 border border-kg-primary/10">
                    {analysisResult ? (
                        <div className="p-3 animate-[fadeInUp_0.3s_ease-out]">
                            <h4 className="font-bold text-kg-primary mb-2 text-sm">AI 分析报告</h4>
                            <p className="text-xs mb-3 leading-relaxed">{analysisResult.analysis}</p>
                            <ul className="text-xs space-y-1 text-kg-text opacity-80 pl-2">
                                {analysisResult.suggestions.map((s, i) => <li key={i}>• {s}</li>)}
                            </ul>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-center text-xs text-kg-text opacity-50 italic">
                            <i className="fas fa-magic text-2xl mb-2"></i>
                            <p>输入知识点开始AI分析</p>
                        </div>
                    )}
                </div>

                <div className="mt-auto bg-kg-bg p-2 rounded-2xl shadow-soft border border-kg-primary/20 flex items-center gap-2 transition-colors">
                    <button onClick={() => fileInputRef.current?.click()} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full"><i className="fas fa-folder-open"></i></button>
                    <button onClick={() => setShowCamera(true)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full"><i className="fas fa-camera"></i></button>
                    <input 
                        ref={inputRef}
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
                        placeholder="输入知识点或题目..."
                        className="flex-1 bg-transparent border-none outline-none text-xs p-2 text-kg-text"
                        disabled={isAnalyzing}
                    />
                    <button 
                        onClick={() => handleAnalyze()}
                        disabled={!input.trim() || isAnalyzing}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${input.trim() ? 'bg-kg-primary text-white shadow-md' : 'bg-gray-200 dark:bg-gray-700 text-gray-400'}`}
                    >
                        {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : '分析'}
                    </button>
                </div>
              </>
          )}
      </div>
    </div>
  );
};

import React, { useContext, useState, useEffect } from 'react';
import { Link, useParams, useLocation, useNavigate } from 'react-router-dom';
import { ThemeContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { GoogleGenAI } from "@google/genai";

export const KnowledgeAnalysis: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { subject } = useParams<{ subject: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const score = location.state?.score || 0;

  const [report, setReport] = useState<string>('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const generateReport = async () => {
        setLoading(true);
        try {
             const apiKey = process.env.API_KEY || '';
             const ai = new GoogleGenAI({ apiKey });
             const prompt = `分析学生的"${subject}"能力，当前评分为 ${score}/100。
             请生成一份简短的分析报告（约150字），包含：
             1. 当前水平评估。
             2. 两个具体的提升策略。
             3. 推荐的思维训练方式。
             请使用Markdown格式，语气专业且鼓励性。不要输出JSON，直接输出文本。`;

             const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
             });
             setReport(response.text || "无法生成报告。");
        } catch (e) {
            setReport(`基于当前评分 ${score}，该维度的能力表现稳定。建议通过更多实践案例来强化。\n(AI服务暂时不可用，请检查网络或Key)`);
        } finally {
            setLoading(false);
        }
    };
    generateReport();
  }, [subject, score]);

  const radius = 80;
  const stroke = 12;
  const normalizedRadius = radius - stroke * 2;
  const circumference = normalizedRadius * 2 * Math.PI;
  const strokeDashoffset = circumference - (score / 100) * circumference;

  return (
    <div className="flex flex-col min-h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300">
      {/* Header */}
      <div className="bg-kg-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-gray-200 dark:border-gray-700 sticky top-0">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate('/knowledge-graph')} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </button>
          <h1 className="text-lg font-bold tracking-wide">能力深度分析 <span className="text-kg-primary font-light">| {decodeURIComponent(subject || '')}</span></h1>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={toggleTheme} className="text-kg-primary hover:text-kg-text transition-colors w-8 h-8 flex items-center justify-center">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      <div className="flex-1 max-w-4xl w-full mx-auto p-6 md:p-10 animate-[fadeInUp_0.5s_ease-out]">

        {/* Top Section: Score Visualization */}
        <div className="flex flex-col md:flex-row items-center justify-center gap-12 mb-12">
            <div className="relative group cursor-default">
                {/* Glow Effect */}
                <div className={`absolute inset-0 rounded-full blur-xl opacity-30 ${score > 80 ? 'bg-emerald-500' : score > 60 ? 'bg-amber-500' : 'bg-rose-500'} group-hover:opacity-50 transition-opacity duration-500`}></div>

                <svg height={radius * 2} width={radius * 2} className="transform -rotate-90 relative z-10 drop-shadow-lg">
                    <circle
                        stroke="var(--kg-line)"
                        strokeWidth={stroke}
                        strokeOpacity="0.3"
                        fill="var(--kg-card)"
                        r={normalizedRadius}
                        cx={radius}
                        cy={radius}
                    />
                    <circle
                        stroke="currentColor"
                        strokeDasharray={circumference + ' ' + circumference}
                        style={{ strokeDashoffset, transition: 'stroke-dashoffset 1.5s ease-in-out' }}
                        strokeWidth={stroke}
                        strokeLinecap="round"
                        fill="transparent"
                        r={normalizedRadius}
                        cx={radius}
                        cy={radius}
                        className={`${score > 80 ? 'text-emerald-500' : score > 60 ? 'text-amber-500' : 'text-rose-500'}`}
                    />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center z-20">
                    <span className={`text-4xl font-extrabold ${score > 80 ? 'text-emerald-600' : score > 60 ? 'text-amber-600' : 'text-rose-600'}`}>{score}</span>
                    <span className="text-[10px] uppercase tracking-[0.2em] opacity-50 mt-1 font-bold">Score</span>
                </div>
            </div>

            <div className="text-center md:text-left max-w-md">
                 <h2 className="text-3xl font-bold mb-2 text-kg-text">{decodeURIComponent(subject || '')} 能力评估</h2>
                 <p className="text-kg-text opacity-70 leading-relaxed mb-4">
                     {score > 85 ? "表现卓越！您在该领域拥有深厚的理解和应用能力。" : 
                      score > 60 ? "基础扎实，但在高阶应用和逻辑连贯性上仍有提升空间。" : 
                      "处于起步阶段，建议加强基础概念的理解和记忆。"}
                 </p>
                 <div className="flex gap-2 justify-center md:justify-start">
                     <span className="px-3 py-1 rounded-full bg-kg-bg border border-kg-primary/20 text-xs text-kg-primary font-mono">Level {Math.floor(score/20) + 1}</span>
                     <span className="px-3 py-1 rounded-full bg-kg-bg border border-kg-primary/20 text-xs text-kg-text opacity-60">Percentile: Top {100 - score}%</span>
                 </div>
            </div>
        </div>

        {/* Report Content */}
        <div className="bg-kg-card rounded-2xl p-8 shadow-card border border-gray-100 dark:border-gray-700 relative overflow-hidden">
            {/* Decorative Header Line */}
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-kg-primary via-kg-secondary to-kg-primary"></div>

            <h3 className="font-bold text-kg-primary mb-6 flex items-center gap-3 text-lg border-b border-gray-100 dark:border-gray-700 pb-4">
                <i className="fas fa-microscope"></i> 深度分析报告
            </h3>

            {loading ? (
                <div className="flex flex-col items-center justify-center py-16 space-y-4">
                    <div className="w-12 h-12 border-4 border-kg-primary border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm opacity-60 animate-pulse font-mono">Neural Analysis In Progress...</p>
                </div>
            ) : (
                <div className="prose prose-sm dark:prose-invert max-w-none text-kg-text">
                    {report.split('\n').map((line, idx) => (
                        <p key={idx} className="mb-3 leading-7 opacity-90 first-letter:text-xl first-letter:font-bold first-letter:text-kg-primary">
                            {line}
                        </p>
                    ))}
                </div>
            )}

            <div className="mt-10 pt-6 border-t border-gray-100 dark:border-gray-700 flex justify-between items-center">
                <span className="text-xs text-kg-text opacity-40 font-mono">Generated by Eternal Core Engine</span>
                <button className="px-5 py-2 text-sm bg-kg-primary text-white hover:bg-kg-secondary transition-colors rounded-lg shadow-md hover:shadow-lg flex items-center gap-2">
                    <i className="fas fa-file-export"></i> 导出 PDF
                </button>
            </div>
        </div>

      </div>
    </div>
  );
};

