import React, { useState, useRef, useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

interface AnalysisResult {
  subject: string;
  predictedScore: number;
  weakPoints: string[];
  lineage: string;
  summary: string;
  recommendedTasks?: string[];
}

export const Office: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes, addCalendarBlock } = useContext(GlobalContext);
  const navigate = useNavigate();
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showCamera, setShowCamera] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) processFile(file);
  };

  const handleCameraCapture = (file: File) => {
    processFile(file);
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
      setResult(null); 
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!imagePreview || isProcessing) return;
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const base64Data = imagePreview.split(',')[1];
      const mimeType = imagePreview.split(':')[1].split(';')[0];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: "Analyze this image. Return JSON." }
          ]
        },
        config: {
           systemInstruction: OFFICE_SYSTEM_INSTRUCTION,
           responseMimeType: 'application/json'
        }
      });

      if (response.text) {
          const data = JSON.parse(response.text);
          setResult(data);

          // Auto-generate Calendar Blocks
          if (data.recommendedTasks) {
              data.recommendedTasks.forEach((task: string) => {
                 addCalendarBlock({
                     id: Date.now().toString() + Math.random(),
                     title: task,
                     duration: 45,
                     type: 'study'
                 });
              });
          }
      }
    } catch (e) {
      alert("分析失败");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    if (!result) return;
    // Add weak points as new nodes globally
    if (result.weakPoints) {
        const newNodes: KnowledgeNode[] = result.weakPoints.map(wp => ({
            id: `node_${Date.now()}_${Math.random().toString(36).substr(2,9)}`,
            label: wp,
            category: 'sub',
            masteryLevel: 20, // Low mastery for weak points
            x: Math.random() * 800 - 400,
            y: Math.random() * 600 - 300
        }));
        setNodes(prev => [...prev, ...newNodes]);
    }
    navigate('/knowledge-graph');
  };

  return (
    <div className="flex flex-col min-h-screen bg-office-bg font-sans text-office-text transition-colors duration-300">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />

      {/* Header */}
      <div className="bg-office-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-office-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-office-sub hover:text-office-primary transition-colors rounded-full hover:bg-office-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">学情分析中心</h1>
        </div>
        <div className="flex items-center gap-3">
           <SystemStatus />
           <button onClick={toggleTheme} className="text-office-sub hover:text-office-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-office-sub" />
        </div>
      </div>

      <div className="flex-1 max-w-6xl w-full mx-auto p-6 flex flex-col md:flex-row gap-6">

        {/* Left: Upload Zone - Fixed Layout (No Overlap) */}
        <div className="w-full md:w-[400px] flex flex-col gap-4 shrink-0">
            {/* Image Container */}
            <div className="bg-office-card rounded-2xl shadow-sm border border-office-border aspect-[3/4] overflow-hidden relative group flex items-center justify-center bg-gray-50 dark:bg-gray-900">
                {imagePreview ? (
                    <img src={imagePreview} alt="Preview" className="w-full h-full object-contain" />
                ) : (
                    <div className="text-center p-6">
                        <i className="fas fa-cloud-upload-alt text-4xl text-office-primary/50 mb-4"></i>
                        <p className="text-sm text-office-sub">点击下方按钮上传</p>
                    </div>
                )}
            </div>

            {/* Control Bar (Separate from Image) */}
            <div className="grid grid-cols-2 gap-3">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="py-3 bg-office-card border border-office-border rounded-xl hover:bg-office-bg text-office-sub hover:text-office-primary transition-colors flex items-center justify-center gap-2"
                >
                    <i className="fas fa-image"></i> 相册
                </button>
                <button 
                    onClick={() => setShowCamera(true)}
                    className="py-3 bg-office-card border border-office-border rounded-xl hover:bg-office-bg text-office-sub hover:text-office-primary transition-colors flex items-center justify-center gap-2"
                >
                    <i className="fas fa-camera"></i> 拍照
                </button>
            </div>

            <button 
                onClick={handleAnalyze}
                disabled={!imagePreview || isProcessing}
                className={`w-full py-3 rounded-xl font-bold tracking-wide shadow-md transition-all flex items-center justify-center gap-2 ${
                    !imagePreview || isProcessing 
                    ? 'bg-gray-200 dark:bg-gray-800 text-gray-400 cursor-not-allowed' 
                    : 'bg-office-primary text-white hover:bg-blue-600 hover:shadow-lg hover:-translate-y-1'
                }`}
            >
                {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-microscope"></i>}
                {isProcessing ? '分析中...' : '开始诊断'}
            </button>
        </div>

        {/* Right: Analysis Result */}
        <div className="flex-1 bg-office-card rounded-2xl shadow-sm border border-office-border p-8 min-h-[500px]">
            {!result ? (
                <div className="h-full flex flex-col items-center justify-center text-office-sub opacity-30">
                    <i className="fas fa-chart-pie text-6xl mb-4"></i>
                    <p>等待分析数据...</p>
                </div>
            ) : (
                <div className="animate-[fadeInUp_0.3s_ease-out] space-y-6">
                    <div className="flex justify-between items-start border-b border-office-border pb-4">
                        <div>
                            <h2 className="text-2xl font-bold text-office-text">{result.subject}</h2>
                            <div className="text-xs text-office-sub mt-1">AI Diagnostic Report</div>
                        </div>
                        <div className="text-right">
                            <div className="text-4xl font-bold text-office-primary">{result.predictedScore}</div>
                            <div className="text-xs text-office-sub">预估分</div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 bg-red-50 dark:bg-red-900/10 rounded-xl border border-red-100 dark:border-red-900/20">
                            <h3 className="font-bold text-red-500 text-sm mb-2">薄弱点</h3>
                            <div className="flex flex-wrap gap-2">
                                {result.weakPoints.map((wp, i) => (
                                    <span key={i} className="px-2 py-1 bg-white dark:bg-gray-800 rounded text-xs text-red-500 shadow-sm">{wp}</span>
                                ))}
                            </div>
                        </div>
                        <div className="p-4 bg-green-50 dark:bg-green-900/10 rounded-xl border border-green-100 dark:border-green-900/20">
                             <h3 className="font-bold text-green-600 text-sm mb-2">后续计划</h3>
                             <div className="text-xs text-green-700 dark:text-green-400">已自动生成 {result.recommendedTasks?.length || 0} 个学习磁块至日历。</div>
                        </div>
