import React, { useEffect, useState } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { Launcher } from './pages/Launcher';
import { Office } from './pages/Office';
import { Education } from './pages/Education';
import { KnowledgeGraph } from './pages/KnowledgeGraph';
import { KnowledgeNodeDetail } from './pages/KnowledgeNodeDetail';
import { KnowledgeAnalysis } from './pages/KnowledgeAnalysis';
import { Landing } from './pages/Landing'; // Cai Bao Landing
import { Chat } from './pages/Chat';
import { RecentChat } from './pages/RecentChat';
import { Modules } from './pages/Modules';
import { ModuleDetail } from './pages/ModuleDetail';
import { DarkStar } from './pages/DarkStar';
import { ThemeContext, UserContext, GlobalContext, INITIAL_NODES, INITIAL_LINKS } from './constants';
import { ThemeMode, User, KnowledgeNode, KnowledgeLink } from './types';

const AppContent: React.FC = () => {
  return (
    <Routes>
      <Route path="/" element={<Launcher />} />

      {/* New Modules */}
      <Route path="/office" element={<Office />} />
      <Route path="/education" element={<Education />} />
      <Route path="/knowledge-graph" element={<KnowledgeGraph />} />
      <Route path="/knowledge-graph/node/:nodeId" element={<KnowledgeNodeDetail />} />
      <Route path="/knowledge-graph/analysis/:subject" element={<KnowledgeAnalysis />} />

      {/* Cai Bao Module Routes */}
      <Route path="/caibao" element={<Landing />} />
      <Route path="/terminal" element={<Chat />} />
      <Route path="/recent_chat" element={<RecentChat />} />
      <Route path="/modules" element={<Modules />} />
      <Route path="/modules/:engineId" element={<ModuleDetail />} />
      <Route path="/dark_star" element={<DarkStar />} />
    </Routes>
  );
};

export default function App() {
  // Theme State
  const [theme, setTheme] = useState<ThemeMode>('light');

  // User State
  const [user, setUser] = useState<User>({
    username: 'Guest',
    isLoggedIn: false,
    role: 'guest'
  });

  // Global Knowledge Graph State
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as ThemeMode || 'light';
    setTheme(savedTheme);
  }, []);

  // Effect to handle CSS class application based on state
  useEffect(() => {
    const root = document.documentElement;
    const isSystemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (theme === 'dark' || (theme === 'system' && isSystemDark)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    // Cycle: Light -> Dark -> System -> Light
    let newTheme: ThemeMode = 'light';
    if (theme === 'light') newTheme = 'dark';
    else if (theme === 'dark') newTheme = 'system';

    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
  };

  // User Auth Methods
  const login = (username: string) => {
    setUser({
      username,
      isLoggedIn: true,
      role: 'user'
    });
  };

  const logout = () => {
    setUser({
      username: 'Guest',
      isLoggedIn: false,
      role: 'guest'
    });
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <UserContext.Provider value={{ user, login, logout }}>
        <GlobalContext.Provider value={{ nodes, setNodes, links, setLinks }}>
          <Router>
            <AppContent />
          </Router>
        </GlobalContext.Provider>
      </UserContext.Provider>
    </ThemeContext.Provider>
  );
}

import React, { useState, useRef, useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

interface AnalysisResult {
  subject: string;
  predictedScore: number;
  weakPoints: string[];
  lineage: string;
  summary: string;
}

export const Office: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes } = useContext(GlobalContext); // Access Global Context
  const navigate = useNavigate();
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showCamera, setShowCamera] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const handleCameraCapture = (file: File) => {
    processFile(file);
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
      setResult(null); // Reset previous result
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!imagePreview || isProcessing) return;
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const base64Data = imagePreview.split(',')[1];
      const mimeType = imagePreview.split(':')[1].split(';')[0];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: "Analyze this image according to the system instructions. Return ONLY JSON." }
          ]
        },
        config: {
           systemInstruction: OFFICE_SYSTEM_INSTRUCTION,
           responseMimeType: 'application/json'
        }
      });

      if (response.text) {
          const data = JSON.parse(response.text);
          setResult(data);
      }
    } catch (e) {
      console.error(e);
      alert("分析失败，请重试");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    if (!result) return;

    // Create new nodes from weak points
    const newNodes: KnowledgeNode[] = result.weakPoints.map(point => ({
        id: `node_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        label: point,
        category: 'sub',
        masteryLevel: 20, // Start low for weak points
        x: Math.random() * 800 - 400,
        y: Math.random() * 600 - 300
    }));

    // Add to global state
    setNodes(prev => [...prev, ...newNodes]);

    const context = `
      学科: ${result.subject}
      预测分数: ${result.predictedScore}
      薄弱点: ${result.weakPoints.join(', ')}
      知识谱系: ${result.lineage}
      分析总结: ${result.summary}
    `;
    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  return (
    <div className="flex flex-col min-h-screen bg-office-bg font-sans text-office-text transition-colors duration-300">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />

      {/* Header */}
      <div className="bg-office-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-office-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-office-sub hover:text-office-primary transition-colors rounded-full hover:bg-office-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">灵境 <span className="text-office-primary font-light">| 学情分析中心</span></h1>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={toggleTheme} className="text-office-sub hover:text-office-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-office-sub" />
        </div>
      </div>

      <div className="flex-1 max-w-6xl w-full mx-auto p-6 md:p-8 flex flex-col md:flex-row gap-8">

        {/* Left: Upload & Preview - FIXED UI LAYOUT */}
        <div className="w-full md:w-[400px] flex flex-col gap-4 flex-shrink-0">
            {/* 1. Image Area - No Overlays */}
            <div className="bg-office-card rounded-2xl p-2 shadow-sm border border-office-border aspect-[3/4] flex items-center justify-center overflow-hidden relative">
                {imagePreview ? (
                    <img src={imagePreview} alt="Upload" className="w-full h-full object-contain rounded-lg" />
                ) : (
                    <div className="text-center space-y-4 p-8">
                        <div className="w-20 h-20 bg-office-bg rounded-full flex items-center justify-center text-office-primary text-3xl mx-auto mb-2">
                             <i className="fas fa-file-image"></i>
                        </div>
                        <p className="text-sm text-office-sub">请选择图片进行分析</p>
                    </div>
                )}
            </div>

            {/* 2. Control Buttons - Separate from Image */}
            <div className="grid grid-cols-2 gap-3">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="py-3 bg-white dark:bg-gray-800 border border-office-border rounded-xl text-office-sub hover:text-office-primary hover:border-office-primary transition-all flex items-center justify-center gap-2 shadow-sm"
                >
                    <i className="fas fa-folder-open"></i> 相册上传
                </button>
                <button 
                    onClick={() => setShowCamera(true)}
                    className="py-3 bg-white dark:bg-gray-800 border border-office-border rounded-xl text-office-sub hover:text-office-primary hover:border-office-primary transition-all flex items-center justify-center gap-2 shadow-sm"
                >
                    <i className="fas fa-camera"></i> 拍照上传
                </button>
            </div>

            {/* 3. Main Action */}
            <button 
                onClick={handleAnalyze}
                disabled={!imagePreview || isProcessing}
                className={`w-full py-4 rounded-xl font-bold tracking-wide shadow-md transition-all flex items-center justify-center gap-2 text-lg ${
                    !imagePreview || isProcessing 
                    ? 'bg-gray-200 dark:bg-gray-800 text-gray-400 cursor-not-allowed' 
                    : 'bg-office-primary text-white hover:bg-blue-600 hover:shadow-lg hover:-translate-y-1'
                }`}
            >
                {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-microscope"></i>}
                {isProcessing ? '深度分析中...' : '开始学情诊断'}
            </button>
        </div>

        {/* Right: Analysis Result */}
        <div className="flex-1 bg-office-card rounded-2xl shadow-sm border border-office-border p-8 relative min-h-[500px]">
            {!result ? (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-office-sub opacity-40">
                    <i className="fas fa-chart-network text-6xl mb-4"></i>
                    <p>等待分析数据...</p>
                </div>
            ) : (
                <div className="animate-[fadeInUp_0.5s_ease-out] space-y-8">
                    <div className="flex justify-between items-start border-b border-office-border pb-6">
                        <div>
                            <h2 className="text-3xl font-bold text-office-text mb-2">{result.subject}</h2>
                            <span className="text-xs text-office-primary bg-office-accent px-3 py-1 rounded-full">AI 诊断报告</span>
                        </div>
                        <div className="text-center">
                            <div className="text-sm text-office-sub mb-1">预测得分</div>
                            <div className="text-6xl font-bold text-office-primary">{result.predictedScore}</div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="bg-red-50 dark:bg-red-900/10 rounded-xl p-5 border border-red-100 dark:border-red-900/30">
                            <h3 className="font-bold text-red-500 mb-4 text-sm flex items-center gap-2"><i className="fas fa-exclamation-circle"></i> 薄弱知识点</h3>
                            <div className="flex flex-wrap gap-2">
                                {result.weakPoints.map((wp, i) => (
                                    <span key={i} className="px-3 py-1 bg-white dark:bg-gray-800 border border-red-200 dark:border-red-900/30 rounded-full text-xs text-office-text">{wp}</span>
                                ))}
                            </div>
                        </div>
                        <div className="bg-green-50 dark:bg-green-900/10 rounded-xl p-5 border border-green-100 dark:border-green-900/30">
                            <h3 className="font-bold text-green-600 mb-4 text-sm flex items-center gap-2"><i className="fas fa-project-diagram"></i> 知识谱系定位</h3>
                            <p className="text-xs text-office-sub leading-relaxed">{result.lineage}</p>
                        </div>
                    </div>

                    <div>
                        <h3 className="font-bold text-office-text mb-3 text-sm flex items-center gap-2"><i className="fas fa-file-alt"></i> 综合分析总结</h3>
                        <p className="text-sm text-office-text leading-relaxed bg-office-bg p-6 rounded-xl border border-office-border">
                            {result.summary}
                        </p>
                    </div>

                    <div className="pt-6 border-t border-office-border flex justify-end">
                        <button 
                            onClick={handleSyncToKG}
                            className="px-8 py-3 bg-office-primary text-white rounded-lg hover:bg-blue-600 transition-colors shadow-md flex items-center gap-2 font-medium"
                        >
                            <i className="fas fa-sync-alt"></i> 生成并存入知识图谱
                        </button>
                    </div>
                </div>
            )}
        </div>

      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { EDU_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { GenerateContentResponse } from '@google/genai';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

export const Education: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes } = useContext(GlobalContext); // Access Global Nodes
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'model', content: string}[]>([
    { role: 'model', content: '嗨！我是你的AI导学助手。今天想学点什么？📐 🌍 🧬' }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: EDU_SYSTEM_INSTRUCTION },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.content }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        const text = (chunk as GenerateContentResponse).text || '';
        fullText += text;
        setMessages(prev => {
          const newArr = [...prev];
          newArr[newArr.length - 1].content = fullText;
          return newArr;
        });
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', content: '哎呀，大脑短路了，重试一下吧！' }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    // Collect context
    const context = messages.slice(-5).map(m => m.content).join('\n');

    // Create a generic node for this session
    const newNode: KnowledgeNode = {
        id: `edu_session_${Date.now()}`,
        label: "导学记录 " + new Date().toLocaleTimeString(),
        category: 'sub',
        masteryLevel: 50,
        x: 0, 
        y: 0
    };
    setNodes(prev => [...prev, newNode]);

    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传资料: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄作业: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  return (
    <div className="flex flex-col h-screen bg-edu-bg font-sans text-edu-text transition-colors duration-300">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}

      {/* Hidden Inputs */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

      {/* Unified Header */}
      <div className="bg-edu-card/80 backdrop-blur px-6 py-4 flex justify-between items-center shadow-sm sticky top-0 z-20 border-b border-edu-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-edu-sub hover:text-edu-primary transition-colors rounded-full hover:bg-edu-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold text-edu-text">灵境 · 导学</h1>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleSyncToKG}
             className="text-edu-sub hover:text-edu-primary px-3 py-1 text-sm border border-transparent hover:border-edu-border rounded transition-all"
             title="分析并存入知识图谱"
           >
             <i className="fas fa-project-diagram mr-1"></i> 存入图谱
           </button>
           <button onClick={toggleTheme} className="text-edu-sub hover:text-edu-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-edu-sub" />
        </div>
      </div>

      <div className="flex-1 flex flex-col max-w-4xl w-full mx-auto p-4 overflow-hidden relative">

        {/* Floating Shapes Background */}
        <div className="absolute top-10 left-10 w-32 h-32 bg-yellow-300 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
        <div className="absolute bottom-10 right-10 w-32 h-32 bg-pink-300 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse animation-delay-2000"></div>

        {/* Removed Subject Cards as requested to clean up UI */}

        {/* Chat Stream */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto mb-4 space-y-6 pr-2 z-10">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start items-end gap-2'}`}>
              {msg.role === 'model' && (
                <div className="w-8 h-8 rounded-full bg-edu-card border border-edu-accent flex items-center justify-center text-edu-primary shadow-sm mb-1 shrink-0">
                  <i className="fas fa-robot"></i>
                </div>
              )}
              <div className={`max-w-[80%] p-5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-edu-primary text-white rounded-br-none shadow-orange-200' 
                  : 'bg-edu-card text-edu-text border border-edu-accent rounded-bl-none'
              }`}>
                {msg.role === 'model' && !msg.content ? <span className="typing-cursor"></span> : <div className="whitespace-pre-wrap">{msg.content}</div>}
              </div>
            </div>
          ))}
        </div>

        {/* Input Bar */}
        <div className="bg-edu-card p-2 rounded-full shadow-lg border border-edu-accent z-10 flex items-center gap-2 pl-4 transition-colors">
          <button 
             onClick={() => fileInputRef.current?.click()}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="上传文件"
          >
             <i className="fas fa-folder-open"></i>
          </button>
          <button 
             onClick={() => setShowCamera(true)}
             className="text-edu-sub hover:text-edu-primary transition-colors"
             title="拍照解题"
          >
            <i className="fas fa-camera"></i>
          </button>
          <input 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="有问题尽管问我..."
            className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-edu-text placeholder-edu-sub/50"
            disabled={isProcessing}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isProcessing}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
              input.trim() ? 'bg-edu-primary text-white rotate-0' : 'bg-edu-bg text-edu-sub -rotate-90'
            }`}
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  // Consume Global State
  const { nodes, setNodes, links, setLinks } = useContext(GlobalContext);

  const navigate = useNavigate();
  const location = useLocation();

  // Local Visualization State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // History Stack for Undo/Redo (Tracking Global State Changes locally for this session)
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(true);

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink';
    startX: number;
    startY: number;
    targetId?: string; // For node drag/link start
    currentX?: number; // For temp link end
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); // Limit size
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  // Initial History Save
  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }
  }, [nodes.length]); // Only run if nodes exist

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  // --- Layout Algorithms ---
  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    return currentNodes.map((node, index) => {
      let x = 0; let y = 0;
      switch (type) {
        case 'mesh':
          x = (Math.random() - 0.5) * 800;
          y = (Math.random() - 0.5) * 600;
          break;
        case 'star':
          if (node.category === 'root') { x = 0; y = 0; } 
          else {
            const level = node.category === 'core' ? 1 : 2;
            const radius = 180 * level;
            const peers = currentNodes.filter(n => (level === 1 ? n.category === 'core' : n.category === 'sub'));
            const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
            x = Math.cos(angle) * radius;
            y = Math.sin(angle) * radius;
          }
          break;
        case 'bus':
          const sorted = [...currentNodes].sort((a, b) => (a.category === 'root' ? -1 : 1));
          x = (sorted.indexOf(node) - sorted.length/2) * 150;
          y = (sorted.indexOf(node) % 2) * 100;
          break;
        case 'tree':
          if (node.category === 'root') y = 250;
          else if (node.category === 'core') y = 0;
          else y = -250;
          const peers = currentNodes.filter(n => n.category === node.category);
          x = (peers.indexOf(node) - peers.length / 2 + 0.5) * 180;
          break;
        case 'evolution':
          x = (index - currentNodes.length / 2) * 140;
          y = Math.sin(index * 0.6) * 180;
          break;
      }
      return { ...node, x: node.x ?? x, y: node.y ?? y }; 
    });
  }, []);

  // Initialize Center
  useEffect(() => {
    setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
    setNodes(prev => {
        const hasPositions = prev.every(n => n.x !== undefined);
        return hasPositions ? prev : applyLayout('star', prev);
    });
  }, [applyLayout]);

  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    const newNodes = applyLayout(newLayout, nodes);
    setNodes(newNodes);
    saveToHistory(newNodes, links);
  };

  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    // Spacebar Panning Check
    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.code === 'Space')) {
       setInteractionState({
           type: 'panning',
           startX: clientX,
           startY: clientY,
       });
       return;
    }

    // Check collision with nodes
    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; 
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (e.shiftKey) {
          setInteractionState({
              type: 'creatingLink',
              startX: worldX,
              startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX,
              currentY: worldY
          });
      } else {
          setSelectedId(clickedNode.id);
          setSelectedLinkIndex(null);
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX,
              startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      // Check collision with background for panning
      if ((e.target as Element).tagName === 'svg' || (e.target as Element).id === 'bg-rect') {
          setInteractionState({
              type: 'panning',
              startX: clientX,
              startY: clientY,
          });
          // Clear selection on bg click
          setSelectedId(null);
          setSelectedLinkIndex(null);
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode' && interactionState.targetId) {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        setNodes(prev => prev.map(n => 
            n.id === interactionState.targetId 
            ? { ...n, x: worldX, y: worldY } 
            : n
        ));
    }
    else if (interactionState.type === 'creatingLink') {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const { x: worldX, y: worldY } = toWorld(clientX, clientY);
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                const newLinks = [...links, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }];
                setLinks(newLinks);
                saveToHistory(nodes, newLinks);
            }
        }
    } else if (interactionState.type === 'draggingNode') {
        // Save history after drag
        saveToHistory(nodes, links);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    if (e.target instanceof Element) {
        try {
            (e.target as Element).releasePointerCapture(e.pointerId);
        } catch (e) {/* Ignore if not captured */}
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 0,
          x, y
      };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  // --- CRUD & Keyboard Ops ---
  const handleDeleteSelected = useCallback(() => {
      if (selectedId) {
          const newNodes = nodes.filter(n => n.id !== selectedId);
          const newLinks = links.filter(l => l.source !== selectedId && l.target !== selectedId);
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedId(null);
      } else if (selectedLinkIndex !== null) {
          const newLinks = links.filter((_, i) => i !== selectedLinkIndex);
          setLinks(newLinks);
          saveToHistory(nodes, newLinks);
          setSelectedLinkIndex(null);
      }
  }, [selectedId, selectedLinkIndex, nodes, links, saveToHistory]);

  const updateSelectedNode = (updates: Partial<KnowledgeNode>) => {
      if (!selectedId) return;
      setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, ...updates } : n));
  };
  const commitNodeUpdate = () => saveToHistory(nodes, links);

  // Keyboard Event Listener
  useEffect(() => {
      const handleKey = (e: KeyboardEvent) => {
          // Ignore if input focused
          if (document.activeElement?.tagName === 'INPUT' || document.activeElement?.tagName === 'TEXTAREA') return;

          // Undo / Redo
          if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
              e.preventDefault();
              if (e.shiftKey) handleRedo();
              else handleUndo();
              return;
          }
          if ((e.ctrlKey || e.metaKey) && e.key === 'y') {
              e.preventDefault();
              handleRedo();
              return;
          }

          // Delete
          if (e.key === 'Delete' || e.key === 'Backspace') {
              handleDeleteSelected();
          }

          // Nudge
          if (selectedId) {
             const step = e.shiftKey ? 10 : 1;
             if (e.key === 'ArrowUp') { setNodes(prev => prev.map(n => n.id === selectedId ? {...n, y: (n.y||0) - step} : n)); }
             if (e.key === 'ArrowDown') { setNodes(prev => prev.map(n => n.id === selectedId ? {...n, y: (n.y||0) + step} : n)); }
             if (e.key === 'ArrowLeft') { setNodes(prev => prev.map(n => n.id === selectedId ? {...n, x: (n.x||0) - step} : n)); }
             if (e.key === 'ArrowRight') { setNodes(prev => prev.map(n => n.id === selectedId ? {...n, x: (n.x||0) + step} : n)); }
          }
      };
      window.addEventListener('keydown', handleKey);
      return () => window.removeEventListener('keydown', handleKey);
  }, [selectedId, selectedLinkIndex, handleDeleteSelected, handleUndo, handleRedo, nodes]); // Added nodes dependency


  // --- Auto Analyze ---
  useEffect(() => {
    const state = location.state as { autoAnalyzeText?: string };
    if (state?.autoAnalyzeText && !isAnalyzing) {
        setInput("基于以下内容进行知识点分析和图谱更新：\n" + state.autoAnalyzeText);
        handleAnalyze(state.autoAnalyzeText);
        window.history.replaceState({}, '');
    }
  }, [location.state]);

  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const cleanText = text.replace(/```json\n?|\n?```/g, '').trim();
        const data = JSON.parse(cleanText);

        setAnalysisResult({
          analysis: data.analysis,
          predictedScore: data.predictedScore,
          suggestions: data.suggestions
        });

        let updatedNodes = [...nodes];
        if (data.updatedNodes) {
          updatedNodes = updatedNodes.map(node => {
            const update = data.updatedNodes.find((u: any) => 
               node.id.toLowerCase().includes(u.id.toLowerCase()) || 
               node.label.toLowerCase().includes(u.id.toLowerCase())
            );
            if (update) {
              return { ...node, masteryLevel: Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange)) };
            }
            return node;
          });
          setNodes(updatedNodes);
          saveToHistory(updatedNodes, links);
        }
      }
    } catch (e) {
      console.error("Analysis failed", e);
      alert("AI分析失败，请检查输入或稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  // --- Dynamic Radar ---
  useEffect(() => {
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };

    const theory = calculateAverage(n => n.category === 'root' || n.category === 'core');
    const logic = calculateAverage(n => n.id.includes('ds') || n.id.includes('algo'));
    const practice = calculateAverage(n => n.category === 'sub');
    const memory = calculateAverage(n => true);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovation = Math.min(100, Math.round(innovationBase + (memory > 80 ? 10 : 0)));

    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);
  }, [nodes]);

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;

    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
      const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
      return `${x},${y}`;
    }).join(' ');

    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];

    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full cursor-pointer" onClick={() => navigate(`/knowledge-graph/analysis/综合能力`, {state: {score: analysisResult?.predictedScore || 75}})}>
         {webLevels.map((level, idx) => (
           <polygon 
             key={idx}
             points={radarData.map((_, i) => {
               const r = level * radius;
               const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
               const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
               return `${x},${y}`;
             }).join(' ')}
             fill="none"
             stroke="var(--kg-line)"
             strokeOpacity="0.5"
             strokeWidth="1"
           />
         ))}
         <polygon 
            points={points} 
            fill="var(--kg-primary)" 
            fillOpacity="0.4" 
            stroke="var(--kg-primary)" 
            strokeWidth="2" 
            className="transition-all duration-500 ease-in-out hover:fill-opacity-60" 
         />
         {radarData.map((d, i) => {
            const r = radius + 15;
            const x = center + r * Math.cos(i * angleSlice - Math.PI / 2);
            const y = center + r * Math.sin(i * angleSlice - Math.PI / 2);
            return (
              <text key={i} x={x} y={y} textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="var(--kg-text)">
                {d.subject}
              </text>
            )
         })}
      </svg>
    );
  };

  const getThemeIcon = () => {
    switch (theme) {
      case 'light': return 'fa-sun';
      case 'dark': return 'fa-moon';
      case 'system': return 'fa-laptop';
      default: return 'fa-sun';
    }
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button 
      onClick={() => handleLayoutChange(type)}
      className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`}
      title={label}
    >
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full md:hidden">
              <i className="fas fa-bars"></i>
          </button>
          <button onClick={toggleTheme} className="text-kg-primary w-8 h-8 flex items-center justify-center">
            <i className={`fas ${getThemeIcon()}`}></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area */}
      <div 
        ref={containerRef}
        className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg outline-none"
        tabIndex={0}
        onWheel={handleWheel}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
        onDoubleClick={handleDoubleClickBg}
      >
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>

            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />

            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {/* Links */}
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line 
                                x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y}
                                stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'}
                                strokeWidth={isSelected ? 3 : 1.5}
                                strokeOpacity={isSelected ? 1 : 0.6}
                                markerEnd="url(#arrowhead)"
                             />
                        </g>
                    );
                })}

                {/* Creating Temp Link */}
                {interactionState.type === 'creatingLink' && (
                    <line 
                        x1={interactionState.startX} y1={interactionState.startY}
                        x2={interactionState.currentX} y2={interactionState.currentY}
                        stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5"
                    />
                )}

                {/* Nodes */}
                {nodes.map((node) => {
                    const isSelected = selectedId === node.id;
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';

                    return (
                        <g 
                            key={node.id} 
                            transform={`translate(${node.x},${node.y})`}
                            onDoubleClick={(e) => handleNodeDoubleClick(e, node)}
                            className="cursor-pointer transition-all duration-300"
                        >
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}

                            <circle 
                                r={r} 
                                fill={color}
                                stroke="var(--kg-bg)"
                                strokeWidth={3}
                                className="shadow-sm"
                            />

                            <rect 
                                x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4"
                                fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none"
                            />
                            <text 
                                y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)"
                                className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}
                            >
                                {node.label}
                            </text>

                            {(isSelected) && (
                                <text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">
                                    {node.masteryLevel}%
                                </text>
                            )}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      {/* Layout Controls */}
      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="科技树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      {/* Interaction Hint */}
      <div className="absolute top-20 left-6 z-10 pointer-events-none opacity-50 text-[10px] text-kg-text space-y-1">
        <p>• 双击空白处添加节点</p>
        <p>• Shift+拖拽连线</p>
        <p>• 拖拽 + Space 平移画布</p>
        <p>• Delete 删除 | Ctrl+Z 撤销</p>
      </div>

      {/* Side Panel (Context Aware) */}
      <div 
        className={`
            fixed right-6 top-24 bottom-6 w-96 bg-kg-card/90 backdrop-blur-xl 
            border border-gray-200 dark:border-gray-700 rounded-3xl shadow-2xl z-20
            transform transition-transform duration-300 ease-out p-6 flex flex-col pointer-events-auto
            ${isPanelOpen ? 'translate-x-0' : 'translate-x-[120%]'}
            hidden md:flex
        `}
      >
          {selectedId ? (
              // Node Edit Mode
              <div className="flex flex-col h-full animate-[fadeInUp_0.3s_ease-out]">
                  <div className="flex justify-between items-center mb-6 border-b border-kg-primary/10 pb-4">
                      <h2 className="text-lg font-bold text-kg-primary">编辑节点</h2>
                      <button onClick={() => {setSelectedId(null); setIsPanelOpen(false);}} className="text-kg-text hover:text-kg-secondary"><i className="fas fa-times"></i></button>
                  </div>

                  {nodes.find(n => n.id === selectedId) && (
                      <div className="space-y-4">
                          <div>
                              <label className="text-xs text-kg-text opacity-60">名称</label>
                              <input 
                                className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" 
                                value={nodes.find(n => n.id === selectedId)?.label}
                                onChange={(e) => updateSelectedNode({label: e.target.value})}
                                onBlur={commitNodeUpdate}
                              />
                          </div>
                          <div>
                              <label className="text-xs text-kg-text opacity-60">掌握度 ({nodes.find(n => n.id === selectedId)?.masteryLevel}%)</label>
                              <input 
                                type="range" min="0" max="100" 
                                className="w-full mt-2 accent-kg-primary"
                                value={nodes.find(n => n.id === selectedId)?.masteryLevel}
                                onChange={(e) => updateSelectedNode({masteryLevel: parseInt(e.target.value)})}
                                onMouseUp={commitNodeUpdate}
                                onKeyUp={commitNodeUpdate}
                              />
                          </div>
                          <div className="pt-4 flex gap-2">
                               <button 
                                 onClick={() => navigate(`/knowledge-graph/node/${selectedId}`, { state: { node: nodes.find(n => n.id === selectedId) } })}
                                 className="flex-1 bg-kg-primary text-white py-2 rounded text-sm hover:opacity-90 transition-opacity"
                               >
                                   <i className="fas fa-book-open mr-1"></i> 查看详情
                               </button>
                               <button 
                                 onClick={handleDeleteSelected}
                                 className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors"
                               >
                                   <i className="fas fa-trash"></i>
                               </button>
                          </div>
                      </div>
                  )}
              </div>
          ) : selectedLinkIndex !== null ? (
              // Link Edit Mode
               <div className="flex flex-col h-full animate-[fadeInUp_0.3s_ease-out]">
                  <div className="flex justify-between items-center mb-6 border-b border-kg-primary/10 pb-4">
                      <h2 className="text-lg font-bold text-kg-text">编辑连线</h2>
                      <button onClick={() => setSelectedLinkIndex(null)} className="text-kg-text"><i className="fas fa-times"></i></button>
                  </div>
                  <div className="space-y-4">
                      <p className="text-sm text-kg-text opacity-70">连接强度可以反映知识点之间的关联紧密程度。</p>
                      <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded hover:bg-red-100">断开连接</button>
                  </div>
               </div>
          ) : (
              // Global Dashboard Mode
              <>
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-lg font-bold text-kg-text">数据控制台</h2>
                    <div className="text-xs text-kg-primary px-2 py-1 bg-kg-primary/10 rounded-full font-mono">
                        NODES: {nodes.length}
                    </div>
                </div>

                <div className="mb-4 p-2 bg-kg-bg rounded-2xl shadow-inner border border-kg-primary/10 flex flex-col items-center shrink-0">
                    <h3 className="text-xs font-bold uppercase tracking-wider mb-2 text-kg-primary">能力雷达</h3>
                    <div className="w-40 h-40">{renderRadar()}</div>
                </div>

                <div className="flex-grow overflow-y-auto mb-4 min-h-[100px] bg-kg-bg rounded-xl p-1 border border-kg-primary/10">
                    {analysisResult ? (
                        <div className="p-3 animate-[fadeInUp_0.3s_ease-out]">
                            <h4 className="font-bold text-kg-primary mb-2 text-sm">AI 分析报告</h4>
                            <p className="text-xs mb-3 leading-relaxed">{analysisResult.analysis}</p>
                            <ul className="text-xs space-y-1 text-kg-text opacity-80 pl-2">
                                {analysisResult.suggestions.map((s, i) => <li key={i}>• {s}</li>)}
                            </ul>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-center text-xs text-kg-text opacity-50 italic">
                            <i className="fas fa-magic text-2xl mb-2"></i>
                            <p>输入知识点开始AI分析</p>
                        </div>
                    )}
                </div>

                <div className="mt-auto bg-kg-bg p-2 rounded-2xl shadow-soft border border-kg-primary/20 flex items-center gap-2 transition-colors">
                    <button onClick={() => fileInputRef.current?.click()} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full"><i className="fas fa-folder-open"></i></button>
                    <button onClick={() => setShowCamera(true)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-card rounded-full"><i className="fas fa-camera"></i></button>
                    <input 
                        ref={inputRef}
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
                        placeholder="输入知识点或题目..."
                        className="flex-1 bg-transparent border-none outline-none text-xs p-2 text-kg-text"
                        disabled={isAnalyzing}
                    />
                    <button 
                        onClick={() => handleAnalyze()}
                        disabled={!input.trim() || isAnalyzing}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${input.trim() ? 'bg-kg-primary text-white shadow-md' : 'bg-gray-200 dark:bg-gray-700 text-gray-400'}`}
                    >
                        {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : '分析'}
                    </button>
                </div>
              </>
          )}
      </div>
    </div>
  );
};

import React from 'react';

export enum EngineType {
  FROST_BLADE = 'frost_blade', // Fast -> gemini-3-flash-preview
  ETERNAL_CORE = 'eternal_core', // Deep -> gemini-3-pro-preview
  LAND_VESSEL = 'land_vessel', // Custom Mod Loader
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  engine?: EngineType;
  senderName?: string; 
}

export type ThemeMode = 'light' | 'dark' | 'system';

export interface User {
  username: string;
  avatar?: string;
  isLoggedIn: boolean;
  role: 'guest' | 'user' | 'admin';
}

export interface ThemeContextType {
  theme: ThemeMode;
  toggleTheme: () => void;
}

export interface UserContextType {
  user: User;
  login: (username: string) => void;
  logout: () => void;
}

// New Global Context for cross-module data
export interface GlobalContextType {
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
  setNodes: React.Dispatch<React.SetStateAction<KnowledgeNode[]>>;
  setLinks: React.Dispatch<React.SetStateAction<KnowledgeLink[]>>;
  // Persistence
  savedGraphs: SavedGraph[];
  saveGraph: (name: string) => void;
  loadGraph: (id: string) => void;
  deleteGraph: (id: string) => void;
}

export interface SavedGraph {
  id: string;
  name: string;
  date: number;
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
}

export interface MBTIPersona {
  id: string;
  type: string; // e.g., INTJ
  name: string; // e.g., 建筑师
  functionStack: string[]; // e.g., Ni, Te, Fi, Se
  description: string;
  systemInstruction: string;
  color: string;
  icon: string;
}

// Knowledge Graph Types
export interface KnowledgeNode {
  id: string;
  label: string;
  category: string;
  masteryLevel: number; // 0-100
  x?: number; // For visualization
  y?: number;
  isGhost?: boolean; // If true, this is a placeholder/template node
}

export interface KnowledgeLink {
  source: string;
  target: string;
  strength: number;
}

