  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) processFile(file);
  };

  const handleCameraCapture = (file: File) => {
    processFile(file);
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
      setResult(null); 
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!imagePreview || isProcessing) return;
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const base64Data = imagePreview.split(',')[1];
      const mimeType = imagePreview.split(':')[1].split(';')[0];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: "Analyze this image. Return JSON." }
          ]
        },
        config: {
           systemInstruction: OFFICE_SYSTEM_INSTRUCTION,
           responseMimeType: 'application/json'
        }
      });

      if (response.text) {
          const data = JSON.parse(response.text);
          setResult(data);

          // Auto-generate Calendar Blocks
          if (data.recommendedTasks) {
              data.recommendedTasks.forEach((task: string) => {
                 addCalendarBlock({
                     id: Date.now().toString() + Math.random(),
                     title: task,
                     duration: 45,
                     type: 'study'
                 });
              });
          }
      }
    } catch (e) {
      alert("分析失败");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    if (!result) return;
    // Add weak points as new nodes globally
    if (result.weakPoints) {
        const newNodes: KnowledgeNode[] = result.weakPoints.map(wp => ({
            id: `node_${Date.now()}_${Math.random().toString(36).substr(2,9)}`,
            label: wp,
            category: 'sub',
            masteryLevel: 20, // Low mastery for weak points
            x: Math.random() * 800 - 400,
            y: Math.random() * 600 - 300
        }));
        setNodes(prev => [...prev, ...newNodes]);
    }
    navigate('/knowledge-graph');
  };

  return (
    <div className="flex flex-col min-h-screen bg-office-bg font-sans text-office-text transition-colors duration-300">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />

      {/* Header */}
      <div className="bg-office-card px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-office-border transition-colors">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-office-sub hover:text-office-primary transition-colors rounded-full hover:bg-office-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-lg font-bold tracking-wide">学情分析中心</h1>
        </div>
        <div className="flex items-center gap-3">
           <SystemStatus />
           <button onClick={toggleTheme} className="text-office-sub hover:text-office-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-office-sub" />
        </div>
      </div>

      <div className="flex-1 max-w-6xl w-full mx-auto p-6 flex flex-col md:flex-row gap-6">

        {/* Left: Upload Zone - Fixed Layout (No Overlap) */}
        <div className="w-full md:w-[400px] flex flex-col gap-4 shrink-0">
            {/* Image Container */}
            <div className="bg-office-card rounded-2xl shadow-sm border border-office-border aspect-[3/4] overflow-hidden relative group flex items-center justify-center bg-gray-50 dark:bg-gray-900">
                {imagePreview ? (
                    <img src={imagePreview} alt="Preview" className="w-full h-full object-contain" />
                ) : (
                    <div className="text-center p-6">
                        <i className="fas fa-cloud-upload-alt text-4xl text-office-primary/50 mb-4"></i>
                        <p className="text-sm text-office-sub">点击下方按钮上传</p>
                    </div>
                )}
            </div>

            {/* Control Bar (Separate from Image) */}
            <div className="grid grid-cols-2 gap-3">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="py-3 bg-office-card border border-office-border rounded-xl hover:bg-office-bg text-office-sub hover:text-office-primary transition-colors flex items-center justify-center gap-2"
                >
                    <i className="fas fa-image"></i> 相册
                </button>
                <button 
                    onClick={() => setShowCamera(true)}
                    className="py-3 bg-office-card border border-office-border rounded-xl hover:bg-office-bg text-office-sub hover:text-office-primary transition-colors flex items-center justify-center gap-2"
                >
                    <i className="fas fa-camera"></i> 拍照
                </button>
            </div>

            <button 
                onClick={handleAnalyze}
                disabled={!imagePreview || isProcessing}
                className={`w-full py-3 rounded-xl font-bold tracking-wide shadow-md transition-all flex items-center justify-center gap-2 ${
                    !imagePreview || isProcessing 
                    ? 'bg-gray-200 dark:bg-gray-800 text-gray-400 cursor-not-allowed' 
                    : 'bg-office-primary text-white hover:bg-blue-600 hover:shadow-lg hover:-translate-y-1'
                }`}
            >
                {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-microscope"></i>}
                {isProcessing ? '分析中...' : '开始诊断'}
            </button>
        </div>

        {/* Right: Analysis Result */}
        <div className="flex-1 bg-office-card rounded-2xl shadow-sm border border-office-border p-8 min-h-[500px]">
            {!result ? (
                <div className="h-full flex flex-col items-center justify-center text-office-sub opacity-30">
                    <i className="fas fa-chart-pie text-6xl mb-4"></i>
                    <p>等待分析数据...</p>
                </div>
            ) : (
                <div className="animate-[fadeInUp_0.3s_ease-out] space-y-6">
                    <div className="flex justify-between items-start border-b border-office-border pb-4">
                        <div>
                            <h2 className="text-2xl font-bold text-office-text">{result.subject}</h2>
                            <div className="text-xs text-office-sub mt-1">AI Diagnostic Report</div>
                        </div>
                        <div className="text-right">
                            <div className="text-4xl font-bold text-office-primary">{result.predictedScore}</div>
                            <div className="text-xs text-office-sub">预估分</div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 bg-red-50 dark:bg-red-900/10 rounded-xl border border-red-100 dark:border-red-900/20">
                            <h3 className="font-bold text-red-500 text-sm mb-2">薄弱点</h3>
                            <div className="flex flex-wrap gap-2">
                                {result.weakPoints.map((wp, i) => (
                                    <span key={i} className="px-2 py-1 bg-white dark:bg-gray-800 rounded text-xs text-red-500 shadow-sm">{wp}</span>
                                ))}
                            </div>
                        </div>
                        <div className="p-4 bg-green-50 dark:bg-green-900/10 rounded-xl border border-green-100 dark:border-green-900/20">
                             <h3 className="font-bold text-green-600 text-sm mb-2">后续计划</h3>
                             <div className="text-xs text-green-700 dark:text-green-400">已自动生成 {result.recommendedTasks?.length || 0} 个学习磁块至日历。</div>
                        </div>
                    </div>

                    <div className="bg-office-bg p-4 rounded-xl border border-office-border text-sm leading-relaxed text-office-text">
                        {result.summary}
                    </div>

                    <div className="flex justify-end pt-4">
                        <button 
                            onClick={handleSyncToKG}
                            className="px-6 py-2 bg-office-primary text-white rounded-lg hover:shadow-lg transition-all text-sm flex items-center gap-2"
                        >
                            <i className="fas fa-sync"></i> 生成知识点
                        </button>
                    </div>
                </div>
            )}
        </div>

      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { nodes, setNodes, links, setLinks, savedGraphs, saveGraph, loadGraph, deleteGraph } = useContext(GlobalContext);
  const navigate = useNavigate();
  const location = useLocation();

  // Local State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number;
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Analysis State
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }
  }, []);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  // --- Ghost Templates ---
  const generateTemplate = (type: LayoutType): { nodes: KnowledgeNode[], links: KnowledgeLink[] } => {
      let tNodes: KnowledgeNode[] = [];
      let tLinks: KnowledgeLink[] = [];
      const timestamp = Date.now();
      const createGhost = (suffix: string, lbl: string, cat: string): KnowledgeNode => ({
          id: `ghost_${type}_${suffix}_${timestamp}`, label: lbl, category: cat, masteryLevel: 0, x: 0, y: 0, isGhost: true
      });

      if (type === 'tree') {
          const root = createGhost('root', '核心', 'root');
          const b1 = createGhost('b1', '分支1', 'core');
          const b2 = createGhost('b2', '分支2', 'core');
          tNodes = [root, b1, b2];
          tLinks = [{source: root.id, target: b1.id, strength: 1}, {source: root.id, target: b2.id, strength: 1}];
      } else if (type === 'star') {
          const center = createGhost('center', '中心', 'root');
          tNodes.push(center);
          for(let i=0; i<5; i++) {
              const s = createGhost(`sat${i}`, `维度${i+1}`, 'core');
              tNodes.push(s);
              tLinks.push({source: center.id, target: s.id, strength: 1});
          }
      } else if (type === 'bus') {
           for(let i=0; i<4; i++) {
               tNodes.push(createGhost(`b${i}`, `节点${i}`, 'core'));
               if(i>0) tLinks.push({source: tNodes[i-1].id, target: tNodes[i].id, strength: 1});
           }
      } else {
           tNodes.push(createGhost('main', '主题', 'root'));
      }
      return { nodes: tNodes, links: tLinks };
  };

  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    return currentNodes.map((node, index) => {
      let x = 0; let y = 0;
      switch (type) {
        case 'mesh': x = (Math.random() - 0.5) * 600; y = (Math.random() - 0.5) * 400; break;
        case 'star':
          if (node.category === 'root') { x = 0; y = 0; } 
          else {
            const level = node.category === 'core' ? 1 : 2;
            const radius = 150 * level;
            const peers = currentNodes.filter(n => (level === 1 ? n.category === 'core' : n.category === 'sub'));
            const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
            x = Math.cos(angle) * radius; y = Math.sin(angle) * radius;
          }
          break;
        case 'bus': x = (index - currentNodes.length/2) * 120; y = (index % 2) * 80; break;
        case 'tree':
          if (node.category === 'root') y = -200;
          else if (node.category === 'core') y = 0;
          else y = 200;
          const peers = currentNodes.filter(n => n.category === node.category);
          x = (peers.indexOf(node) - peers.length / 2 + 0.5) * 160;
          break;
        case 'evolution': x = (index - currentNodes.length / 2) * 100; y = Math.sin(index * 0.5) * 150; break;
      }
      return { ...node, x: node.x ?? x, y: node.y ?? y }; 
    });
  }, []);

  // Initialize
  useEffect(() => {
    setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
    if (nodes.length > 0 && nodes.every(n => n.x === undefined)) {
        setNodes(prev => applyLayout('star', prev));
    }
  }, []);

  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    // Logic: If empty or very few nodes, generate template.
    if (nodes.length < 2) {
        const { nodes: tNodes, links: tLinks } = generateTemplate(newLayout);
        const arranged = applyLayout(newLayout, tNodes);
        setNodes(arranged);
        setLinks(tLinks);
        saveToHistory(arranged, tLinks);
    } else {
        const newNodes = applyLayout(newLayout, nodes);
        setNodes(newNodes);
        saveToHistory(newNodes, links);
    }
  };

  // --- Interactions ---
  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.code === 'Space')) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    // Box Selection (Ctrl + Click Drag or Long Press Logic simulated)
    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       return dx*dx + dy*dy <= 30*30;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (clickedNode.isGhost) {
          const newName = prompt("输入知识点名称:", "新知识点");
          if (newName) {
              setNodes(prev => prev.map(n => n.id === clickedNode.id ? { ...n, label: newName, isGhost: false, masteryLevel: 50 } : n));
          }
          return;
      }

      if (e.shiftKey) {
          setInteractionState({ type: 'creatingLink', startX: worldX, startY: worldY, targetId: clickedNode.id, currentX: worldX, currentY: worldY });
      } else {
          // If node not in selection, clear selection unless Ctrl pressed (which is handled above for box)
          if (!selectedNodeIds.has(clickedNode.id)) {
              setSelectedNodeIds(new Set([clickedNode.id]));
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({ type: 'draggingNode', startX: worldX, startY: worldY, targetId: clickedNode.id });
      }
    } else {
      if ((e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } else if (interactionState.type === 'draggingNode') {
        // Drag all selected nodes
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;

        setNodes(prev => prev.map(n => {
            if (selectedNodeIds.has(n.id) || n.id === interactionState.targetId) {
                return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
            }
            return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));

    } else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    } else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });
        if (targetNode && !targetNode.isGhost) {
            setLinks(prev => [...prev, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }]);
            saveToHistory(nodes, links);
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        // Calculate selection
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
      e.preventDefault();
      if (e.ctrlKey) {
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({ ...t, k: Math.max(0.1, Math.min(5, t.k + scaleAmount)) }));
      } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
      }
  };

  const handleSaveGraph = () => {
    if(!newGraphName) return;
    saveGraph(newGraphName, Array.from(selectedNodeIds));
    setNewGraphName('');
    setShowSaveModal(false);
  };

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      }
  }, [selectedNodeIds, nodes, links]);

  // Keyboard
  useEffect(() => {
      const handleKey = (e: KeyboardEvent) => {
          if (document.activeElement?.tagName === 'INPUT') return;
          if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteSelected();
          if ((e.ctrlKey || e.metaKey) && e.key === 'z') handleUndo();
      };
      window.addEventListener('keydown', handleKey);
      return () => window.removeEventListener('keydown', handleKey);
  }, [handleDeleteSelected, handleUndo]);

  const handleAnalyze = async () => {
     // AI Logic omitted for brevity, assume updated
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => handleLayoutChange(type)} className={`flex flex-col items-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white scale-110' : 'text-kg-text hover:bg-kg-card/50'}`}>
      <i className={`fas ${icon} text-lg`}></i>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans overflow-hidden relative">
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full"><i className="fas fa-arrow-left"></i></Link>
          <span className="font-bold">知识图谱</span>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700">
          <SystemStatus />
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      <div ref={containerRef} className="absolute inset-0 z-0 outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedNodeIds.has(src.id) && selectedNodeIds.has(tgt.id);
                    return <line key={i} x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} />;
                })}
                {interactionState.type === 'creatingLink' && (
                    <line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />
                )}
                 {interactionState.type === 'boxSelecting' && (
                    <rect 
                        x={Math.min(interactionState.startX, interactionState.currentX!)} 
                        y={Math.min(interactionState.startY, interactionState.currentY!)} 
                        width={Math.abs(interactionState.currentX! - interactionState.startX)} 
                        height={Math.abs(interactionState.currentY! - interactionState.startY)} 
                        fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2"
                    />
                )}
                {nodes.map((node) => (
                    <g key={node.id} transform={`translate(${node.x},${node.y})`}>
                        <circle 
                            r={node.isGhost ? 20 : (node.category === 'root' ? 35 : 20)} 
                            fill={node.isGhost ? 'transparent' : (selectedNodeIds.has(node.id) ? 'var(--kg-secondary)' : 'var(--kg-node)')}
                            stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-line)'}
                            strokeWidth={2}
                            strokeDasharray={node.isGhost ? "4,4" : "0"}
                            className="transition-all duration-300"
                        />
                        <text y={node.category === 'root' ? 5 : 4} textAnchor="middle" fontSize="10" fill="var(--kg-text)" className="pointer-events-none select-none">
                            {node.label}
                        </text>
                    </g>
                ))}
            </g>
          </svg>
      </div>

      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网" />
        <LayoutButton type="star" icon="fa-atom" label="星" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="流" />
      </div>

      {/* Side Panel */}
      <div className={`fixed top-0 right-0 h-full w-96 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button 
            onClick={() => setIsPanelOpen(!isPanelOpen)}
            className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"
          >
            <i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i>
          </button>

          <div className="p-6 h-full flex flex-col pt-20">
              <h2 className="text-lg font-bold mb-4 flex justify-between">
                  <span>数据控制台</span>
                  <button onClick={() => setShowSaveModal(true)} className="text-xs bg-kg-primary text-white px-2 py-1 rounded">保存网络</button>
              </h2>
              {selectedNodeIds.size > 0 ? (
                  <div className="space-y-4">
                      <p className="text-sm opacity-60">已选择 {selectedNodeIds.size} 个节点</p>
                      <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded text-sm">删除所选</button>
                      <div className="text-xs text-gray-400 mt-4">提示: Ctrl+拖拽 可框选多个节点保存为独立网络。</div>
                  </div>
              ) : (
                  <div className="space-y-4">
                      <div className="bg-kg-bg p-4 rounded-xl text-center">
                          <div className="text-sm font-bold text-kg-primary mb-2">雷达分析</div>
                      </div>
                  </div>
              )}
               {/* Saved Graphs List */}
              <div className="mt-6 border-t pt-4">
                  <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">已保存的图谱</div>
                  <div className="flex flex-col gap-2 max-h-48 overflow-y-auto">
                      {savedGraphs.map(g => (
                          <div key={g.id} className="flex justify-between items-center bg-kg-bg p-2 rounded border border-gray-200 dark:border-gray-700">
                              <span className="text-sm truncate cursor-pointer hover:text-kg-primary" onClick={() => loadGraph(g.id)}>{g.name}</span>
                              <button onClick={() => deleteGraph(g.id)} className="text-red-400 hover:text-red-600 px-2"><i className="fas fa-times"></i></button>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      </div>

       {/* Save Modal */}
      {showSaveModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
              <div className="bg-kg-card p-6 rounded-xl shadow-2xl w-80 border border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-bold mb-2">保存网络</h3>
                  <p className="text-xs text-gray-500 mb-4">{selectedNodeIds.size > 0 ? `将保存选中的 ${selectedNodeIds.size} 个节点及其连接。` : "将保存当前画布所有节点。"}</p>
                  <input 
                    value={newGraphName}
                    onChange={(e) => setNewGraphName(e.target.value)}
                    placeholder="图谱名称"
                    className="w-full p-2 border rounded mb-4 bg-kg-bg text-kg-text outline-none"
                    autoFocus
                  />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setShowSaveModal(false)} className="px-4 py-2 text-sm text-gray-500">取消</button>
                      <button onClick={handleSaveGraph} className="px-4 py-2 text-sm bg-kg-primary text-white rounded">保存</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useContext, useState } from 'react';
import { Link } from 'react-router-dom';
import { ThemeContext, GlobalContext } from '../constants';
import { SystemStatus } from '../components/SystemStatus';
import { UserAuth } from '../components/UserAuth';
import { CalendarBlock } from '../types';

export const Calendar: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { calendarBlocks, weather, mood } = useContext(GlobalContext);
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);

  // Time Slots: 08:00 - 22:00
  const hours = Array.from({ length: 15 }, (_, i) => i + 8);

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
  };

  const handleDrop = (hour: number) => {
    if (draggedBlock) {
      // In a real app, update start time in global state
      console.log(`Dropped ${draggedBlock.title} at ${hour}:00`);
      setDraggedBlock(null);
    }
  };

  const exportTable = () => {
    const csvContent = "data:text/csv;charset=utf-8," + "Task,Duration,Status\n" + calendarBlocks.map(b => `${b.title},${b.duration}m,${b.isCompleted?'Done':'Pending'}`).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "daily_plan.csv");
    document.body.appendChild(link);
    link.click();
  };

  return (
    <div className="flex flex-col min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans transition-colors duration-300">
      <div className="bg-white dark:bg-gray-800 px-6 py-4 flex justify-between items-center shadow-sm z-10 border-b border-gray-200 dark:border-gray-700">
        <div className="flex items-center gap-4">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"><i className="fas fa-arrow-left"></i></Link>
          <h1 className="text-lg font-bold">学习日历</h1>
        </div>
        <div className="flex items-center gap-4">
          <SystemStatus />
          <UserAuth />
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Sidebar: Magnetic Blocks */}
        <div className="w-64 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 p-4 flex flex-col">
            <h2 className="text-xs font-bold uppercase tracking-wider text-gray-500 mb-4">待办磁块 (Magnetic Blocks)</h2>
            <div className="flex-1 overflow-y-auto space-y-2">
                {calendarBlocks.length === 0 && <div className="text-xs text-gray-400 text-center py-4">暂无任务，请从学情分析导入</div>}
                {calendarBlocks.map(block => (
                    <div 
                        key={block.id}
                        draggable
                        onDragStart={() => handleDragStart(block)}
                        className="p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-900/30 rounded-lg cursor-move hover:shadow-md transition-shadow"
                    >
                        <div className="text-sm font-bold text-blue-800 dark:text-blue-300">{block.title}</div>
                        <div className="text-xs text-blue-500 mt-1">{block.duration} mins</div>
                    </div>
                ))}
            </div>
            <button onClick={exportTable} className="mt-4 w-full py-2 bg-gray-100 dark:bg-gray-700 rounded text-xs font-bold hover:bg-gray-200 transition-colors">
                <i className="fas fa-file-export mr-2"></i> 导出日报
            </button>
        </div>

        {/* Main Grid */}
        <div className="flex-1 overflow-y-auto p-6 relative">
            {/* Auto-segmentation visual based on weather/mood */}
            <div className={`absolute top-0 left-0 w-full h-2 bg-gradient-to-r ${mood === '🤩' ? 'from-yellow-400 to-orange-500' : 'from-gray-300 to-gray-400'}`}></div>

            <div className="grid grid-cols-1 gap-4 max-w-3xl mx-auto">
                {hours.map(hour => (
                    <div 
                        key={hour}
                        onDragOver={(e) => e.preventDefault()}
                        onDrop={() => handleDrop(hour)}
                        className="flex border-b border-gray-100 dark:border-gray-700 min-h-[80px] group"
                    >
                        <div className="w-16 text-xs text-gray-400 font-mono py-2">{hour}:00</div>
                        <div className="flex-1 bg-white dark:bg-gray-800/50 rounded-lg border border-transparent group-hover:border-blue-200 dark:group-hover:border-blue-900 transition-colors p-2 relative">
                             {/* Placeholder line */}
                             <div className="absolute top-1/2 left-0 w-full h-px bg-gray-50 dark:bg-gray-700 border-dashed border-t"></div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

