type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { nodes, setNodes, links, setLinks, savedGraphs, saveGraph, loadGraph, deleteGraph } = useContext(GlobalContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [radarData, setRadarData] = useState(INITIAL_RADAR);
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number;
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }
  }, [nodes.length]);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  // --- Ghost Templates ---
  const generateTemplate = (type: LayoutType): { nodes: KnowledgeNode[], links: KnowledgeLink[] } => {
      let tNodes: KnowledgeNode[] = [];
      let tLinks: KnowledgeLink[] = [];
      const timestamp = Date.now();
      const createGhost = (suffix: string, lbl: string, cat: string): KnowledgeNode => ({
          id: `ghost_${type}_${suffix}_${timestamp}`, label: lbl, category: cat, masteryLevel: 0, x: 0, y: 0, isGhost: true
      });

      if (type === 'tree') {
          const root = createGhost('root', '核心主题', 'root');
          const b1 = createGhost('b1', '分支1', 'core');
          const b2 = createGhost('b2', '分支2', 'core');
          const s1 = createGhost('s1', '细节A', 'sub');
          const s2 = createGhost('s2', '细节B', 'sub');
          tNodes = [root, b1, b2, s1, s2];
          tLinks = [
              {source: root.id, target: b1.id, strength: 1}, 
              {source: root.id, target: b2.id, strength: 1},
              {source: b1.id, target: s1.id, strength: 1},
              {source: b2.id, target: s2.id, strength: 1}
          ];
      } else if (type === 'star') {
          const center = createGhost('center', '中心点', 'root');
          tNodes.push(center);
          for(let i=1; i<=5; i++) {
              const s = createGhost(`sat${i}`, `维度${i}`, 'core');
              tNodes.push(s);
              tLinks.push({source: center.id, target: s.id, strength: 1});
          }
      } else if (type === 'bus') {
           for(let i=0; i<5; i++) {
               tNodes.push(createGhost(`b${i}`, `节点${i+1}`, 'core'));
               if(i>0) tLinks.push({source: tNodes[i-1].id, target: tNodes[i].id, strength: 1});
           }
      } else if (type === 'mesh') {
           for(let i=0; i<6; i++) {
               tNodes.push(createGhost(`m${i}`, `概念${i+1}`, 'core'));
           }
           // Random connections for mesh template
           for(let i=0; i<5; i++) {
               tLinks.push({source: tNodes[i].id, target: tNodes[i+1].id, strength: 1});
               if(i<4) tLinks.push({source: tNodes[i].id, target: tNodes[i+2].id, strength: 1});
           }
      } else {
           tNodes.push(createGhost('main', '起源点', 'root'));
      }
      return { nodes: tNodes, links: tLinks };
  };

  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    return currentNodes.map((node, index) => {
      let x = 0; let y = 0;
      switch (type) {
        case 'mesh': x = (Math.random() - 0.5) * 500; y = (Math.random() - 0.5) * 400; break;
        case 'star':
          if (node.category === 'root') { x = 0; y = 0; } 
          else {
            const peers = currentNodes.filter(n => n.category !== 'root');
            const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
            const r = 200;
            x = Math.cos(angle) * r; y = Math.sin(angle) * r;
          }
          break;
        case 'bus': x = (index - currentNodes.length/2) * 140; y = (index % 2) * 80; break;
        case 'tree':
          if (node.category === 'root') y = -220;
          else if (node.category === 'core') y = 0;
          else y = 220;
          const peers = currentNodes.filter(n => n.category === node.category);
          x = (peers.indexOf(node) - peers.length / 2 + 0.5) * 180;
          break;
        case 'evolution': x = (index - currentNodes.length / 2) * 100; y = Math.sin(index * 0.5) * 150; break;
      }
      return { ...node, x: node.x ?? x, y: node.y ?? y }; 
    });
  }, []);

  useEffect(() => {
    setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
    if (nodes.length > 0 && nodes.every(n => n.x === undefined)) {
        setNodes(prev => applyLayout('star', prev));
    }
  }, []);

  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    // If graph is small/empty, generate template automatically
    if (nodes.length <= 1) {
        const { nodes: tNodes, links: tLinks } = generateTemplate(newLayout);
        const arranged = applyLayout(newLayout, tNodes);
        setNodes(arranged);
        setLinks(tLinks);
        saveToHistory(arranged, tLinks);
    } else {
        const newNodes = applyLayout(newLayout, nodes);
        setNodes(newNodes);
        saveToHistory(newNodes, links);
    }
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.code === 'Space')) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    // Box Selection (Ctrl + Drag or Long press simulated logic)
    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       return dx*dx + dy*dy <= 30*30;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (clickedNode.isGhost) {
          const newName = prompt("输入知识点名称以激活:", "新知识点");
          if (newName) {
              setNodes(prev => prev.map(n => n.id === clickedNode.id ? { ...n, label: newName, isGhost: false, masteryLevel: 50 } : n));
              saveToHistory(nodes, links);
          }
          return;
      }

      if (e.shiftKey) {
          setInteractionState({ type: 'creatingLink', startX: worldX, startY: worldY, targetId: clickedNode.id, currentX: worldX, currentY: worldY });
      } else {
          // Add to selection if not already selected, unless standard click
          if (!selectedNodeIds.has(clickedNode.id)) {
              if (e.ctrlKey) {
                  const newSet = new Set(selectedNodeIds);
                  newSet.add(clickedNode.id);
                  setSelectedNodeIds(newSet);
              } else {
                  setSelectedNodeIds(new Set([clickedNode.id]));
              }
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({ type: 'draggingNode', startX: worldX, startY: worldY, targetId: clickedNode.id });
      }
    } else {
      if ((e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } else if (interactionState.type === 'draggingNode') {
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;

        setNodes(prev => prev.map(n => {
            if (selectedNodeIds.has(n.id)) {
                return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
            }
            return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));
    } else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    } else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });
        if (targetNode && !targetNode.isGhost) {
            setLinks(prev => [...prev, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }]);
            saveToHistory(nodes, links);
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
      e.preventDefault();
      if (e.ctrlKey) {
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({ ...t, k: Math.max(0.1, Math.min(5, t.k + scaleAmount)) }));
      } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
      }
  };

  const handleSaveGraph = () => {
    if(!newGraphName) return;
    saveGraph(newGraphName, Array.from(selectedNodeIds));
    setNewGraphName('');
    setShowSaveModal(false);
  };

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      }
  }, [selectedNodeIds, nodes, links]);

  // Keyboard
  useEffect(() => {
      const handleKey = (e: KeyboardEvent) => {
          if (document.activeElement?.tagName === 'INPUT') return;
          if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteSelected();
          if ((e.ctrlKey || e.metaKey) && e.key === 'z') handleUndo();
      };
      window.addEventListener('keydown', handleKey);
      return () => window.removeEventListener('keydown', handleKey);
  }, [handleDeleteSelected, handleUndo]);

  const handleAnalyze = async () => {
    // Logic kept same as before, simplified for brevity
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => handleLayoutChange(type)} className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white scale-110 shadow-lg' : 'text-kg-text hover:bg-kg-card/50'}`}>
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[10px]">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans overflow-hidden relative">
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full"><i className="fas fa-arrow-left"></i></Link>
          <span className="font-bold">知识图谱</span>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto">
           {/* Replaced old toggle with SystemStatus Trigger */}
          <SystemStatus />
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      <div ref={containerRef} className="absolute inset-0 z-0 outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedNodeIds.has(src.id) && selectedNodeIds.has(tgt.id);
                    return <line key={i} x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} />;
                })}
                {interactionState.type === 'creatingLink' && (
                    <line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />
                )}
                 {interactionState.type === 'boxSelecting' && (
                    <rect 
                        x={Math.min(interactionState.startX, interactionState.currentX!)} 
                        y={Math.min(interactionState.startY, interactionState.currentY!)} 
                        width={Math.abs(interactionState.currentX! - interactionState.startX)} 
                        height={Math.abs(interactionState.currentY! - interactionState.startY)} 
                        fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2"
                    />
                )}
                {nodes.map((node) => (
                    <g key={node.id} transform={`translate(${node.x},${node.y})`}>
                        <circle 
                            r={node.isGhost ? 20 : (node.category === 'root' ? 35 : 20)} 
                            fill={node.isGhost ? 'transparent' : (selectedNodeIds.has(node.id) ? 'var(--kg-secondary)' : 'var(--kg-node)')}
                            stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-line)'}
                            strokeWidth={2}
                            strokeDasharray={node.isGhost ? "4,4" : "0"}
                            className="transition-all duration-300"
                        />
                        <text y={node.category === 'root' ? 5 : 4} textAnchor="middle" fontSize="10" fill="var(--kg-text)" className="pointer-events-none select-none">
                            {node.label}
                        </text>
                        {node.isGhost && <text y={5} textAnchor="middle" fontSize="12" fill="var(--kg-text)" className="pointer-events-none">+</text>}
                    </g>
                ))}
            </g>
          </svg>
      </div>

      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="树形" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      {/* Side Panel */}
      <div className={`fixed top-0 right-0 h-full w-80 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button 
            onClick={() => setIsPanelOpen(!isPanelOpen)}
            className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"
          >
            <i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i>
          </button>

          <div className="p-6 h-full flex flex-col pt-20">
              <h2 className="text-lg font-bold mb-4 flex justify-between">
                  <span>数据控制台</span>
                  <button onClick={() => setShowSaveModal(true)} className="text-xs bg-kg-primary text-white px-2 py-1 rounded shadow hover:bg-opacity-90 transition">保存网络</button>
              </h2>
              {selectedNodeIds.size > 0 ? (
                  <div className="space-y-4">
                      <div className="p-3 bg-kg-bg rounded border border-kg-primary/20">
                          <p className="text-sm font-bold text-kg-primary">已选择 {selectedNodeIds.size} 个节点</p>
                      </div>
                      <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition">删除所选</button>
                      <div className="text-xs text-gray-400 mt-4 leading-relaxed bg-kg-bg p-2 rounded">
                          <i className="fas fa-info-circle mr-1"></i>
                          提示: 按住 <span className="font-mono bg-gray-200 dark:bg-gray-700 px-1 rounded">Ctrl</span> 并拖拽鼠标可进行框选。
                      </div>
                  </div>
              ) : (
                  <div className="space-y-4 text-center text-gray-400 text-sm mt-10">
                      <i className="fas fa-mouse-pointer text-2xl mb-2"></i>
                      <p>点击或框选节点进行操作</p>
                  </div>
              )}
               {/* Saved Graphs List */}
              <div className="mt-6 border-t border-gray-200 dark:border-gray-700 pt-4 flex-1 overflow-hidden flex flex-col">
                  <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">已保存的图谱</div>
                  <div className="flex flex-col gap-2 overflow-y-auto pr-1">
                      {savedGraphs.map(g => (
                          <div key={g.id} className="flex justify-between items-center bg-kg-bg p-2 rounded border border-gray-200 dark:border-gray-700 hover:border-kg-primary transition-colors group">
                              <span className="text-sm truncate cursor-pointer hover:text-kg-primary flex-1" onClick={() => loadGraph(g.id)}>{g.name}</span>
                              <div className="text-xs text-gray-400 mr-2">{new Date(g.date).toLocaleDateString()}</div>
                              <button onClick={() => deleteGraph(g.id)} className="text-gray-300 hover:text-red-500 px-1 opacity-0 group-hover:opacity-100 transition-opacity"><i className="fas fa-times"></i></button>
                          </div>
                      ))}
                      {savedGraphs.length === 0 && <div className="text-xs italic text-center opacity-40 py-4">暂无存档</div>}
                  </div>
              </div>
          </div>
      </div>

       {/* Save Modal */}
      {showSaveModal && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50 backdrop-blur-sm animate-[fadeIn_0.2s]">
              <div className="bg-kg-card p-6 rounded-xl shadow-2xl w-80 border border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-bold mb-2">保存网络快照</h3>
                  <p className="text-xs text-gray-500 mb-4">{selectedNodeIds.size > 0 ? `将保存选中的 ${selectedNodeIds.size} 个节点及其连接。` : "将保存当前画布所有节点。"}</p>
                  <input 
                    value={newGraphName}
                    onChange={(e) => setNewGraphName(e.target.value)}
                    placeholder="请输入图谱名称..."
                    className="w-full p-2 border rounded mb-4 bg-kg-bg text-kg-text outline-none focus:border-kg-primary"
                    autoFocus
                  />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setShowSaveModal(false)} className="px-4 py-2 text-sm text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded transition">取消</button>
                      <button onClick={handleSaveGraph} className="px-4 py-2 text-sm bg-kg-primary text-white rounded hover:opacity-90 transition shadow-md">保存</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

interface AnalysisResult {
  subject: string;
  predictedScore: number;
  weakPoints: string[];
  lineage: string;
  summary: string;
  recommendedTasks?: string[];
}

export const Office: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes, addCalendarBlock } = useContext(GlobalContext);
  const navigate = useNavigate();
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showCamera, setShowCamera] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const handleCameraCapture = (file: File) => {
    processFile(file);
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
      setResult(null); // Reset previous result
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!imagePreview || isProcessing) return;
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const base64Data = imagePreview.split(',')[1];
      const mimeType = imagePreview.split(':')[1].split(';')[0];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: "Analyze this image according to the system instructions. Return ONLY JSON. Also suggest 3 short tasks." }
          ]
        },
        config: {
           systemInstruction: OFFICE_SYSTEM_INSTRUCTION,
           responseMimeType: 'application/json'
        }
      });

      if (response.text) {
          const data = JSON.parse(response.text);
          setResult(data);

          // Auto-generate Calendar Blocks (Simulated if AI doesn't return exactly)
          const tasks = data.recommendedTasks || [`复习 ${data.subject} 薄弱点`, `${data.subject} 错题整理`];
          tasks.forEach((task: string, idx: number) => {
             addCalendarBlock({
                 id: Date.now().toString() + idx,
                 title: task,
                 duration: 30, // default 30 mins
                 type: 'study'
             });
          });
      }
    } catch (e) {
      console.error(e);
      alert("分析失败，请重试");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    if (!result) return;

    // Create new nodes from weak points
    const newNodes: KnowledgeNode[] = result.weakPoints.map(point => ({
        id: `node_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        label: point,
        category: 'sub',
        masteryLevel: 20, // Start low for weak points
        x: Math.random() * 800 - 400,
        y: Math.random() * 600 - 300
    }));

    // Add to global state
