                                ))}
                            </div>
                        </div>
                        <div className="bg-green-50 dark:bg-green-900/10 rounded-xl p-5 border border-green-100 dark:border-green-900/30">
                            <h3 className="font-bold text-green-600 mb-4 text-sm flex items-center gap-2"><i className="fas fa-calendar-check"></i> 学习计划</h3>
                            <p className="text-xs text-office-sub leading-relaxed">
