      <div className={`flex items-center gap-1 ${theme === 'dark' ? 'text-gray-300' : 'text-gray-600'}`}>
         <span>{time.getHours().toString().padStart(2,'0')}:{time.getMinutes().toString().padStart(2,'0')}</span>
      </div>

      <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>

      {/* Weather */}
      <div 
        className="relative group flex items-center gap-1 text-blue-500 hover:text-blue-600"
        onClick={(e) => e.stopPropagation()} 
      >
         <i className={`fas ${weather.icon}`}></i>
         <span>{weather.temp}°</span>

         {/* Weather Dropdown */}
         <div className="absolute top-full right-0 mt-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-xl p-1 hidden group-hover:flex flex-col gap-1 min-w-[40px] animate-[fadeIn_0.2s] z-[60]">
