import React, { useContext, useState } from 'react';
import { GlobalContext } from '../constants';
import { CalendarBlock } from '../types';

export const CalendarOverlay: React.FC = () => {
  const { isCalendarOpen, setIsCalendarOpen, calendarBlocks, updateCalendarBlock, addCalendarBlock, weather, mood } = useContext(GlobalContext);
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);
  const [newBlockTitle, setNewBlockTitle] = useState('');

  // Time Slots: 07:00 - 23:00
  const hours = Array.from({ length: 17 }, (_, i) => i + 7);

  if (!isCalendarOpen) return null;

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
  };

  const handleDrop = (time: string | undefined) => {
    if (draggedBlock) {
      updateCalendarBlock(draggedBlock.id, { assignedTime: time });
      setDraggedBlock(null);
    }
  };

  const handleAutoFill = () => {
      // Simple heuristic: fill empty slots starting from 09:00 with available blocks
      let currentHour = 9;
      const unassignedBlocks = calendarBlocks.filter(b => !b.assignedTime);

      unassignedBlocks.forEach(block => {
          if (currentHour < 22) {
             updateCalendarBlock(block.id, { assignedTime: `${currentHour.toString().padStart(2,'0')}:00` });
             currentHour += Math.ceil(block.duration / 60);
          }
      });
  };

  const exportReport = () => {
    const header = `Daily Report - ${new Date().toLocaleDateString()}\nWeather: ${weather.type} | Mood: ${mood}\n\n`;
    const csv = "Time,Task,Duration,Status\n" + 
      calendarBlocks
        .sort((a,b) => (a.assignedTime || 'z').localeCompare(b.assignedTime || 'z'))
        .map(b => `${b.assignedTime || 'Unassigned'},${b.title},${b.duration}m,${b.isCompleted?'Done':'Pending'}`)
        .join("\n");

    const blob = new Blob([header + csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `daily_report_${Date.now()}.csv`;
    link.click();
  };

  const handleAddBlock = () => {
    if(!newBlockTitle.trim()) return;
    addCalendarBlock({
      id: Date.now().toString(),
      title: newBlockTitle,
      duration: 30,
      type: 'other'
    });
    setNewBlockTitle('');
  };

  return (
    <div className="fixed inset-0 z-[100] flex justify-end pointer-events-none">
      {/* Backdrop (Click to close) */}
      <div 
        className="absolute inset-0 bg-black/20 backdrop-blur-[2px] pointer-events-auto transition-opacity" 
        onClick={() => setIsCalendarOpen(false)}
      ></div>

      {/* Calendar Panel */}
      <div className="relative w-full md:w-[450px] h-full bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl pointer-events-auto flex flex-col animate-[slideInRight_0.3s_ease-out]">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-black/20">
            <div>
                <h2 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
                    <i className="fas fa-calendar-alt text-purple-500"></i> 
                    学习磁贴日历
                </h2>
                <div className="text-xs text-gray-500 mt-1 flex gap-2">
                   <span><i className={`fas ${weather.icon}`}></i> {weather.type}</span>
                   <span>{mood} Mood</span>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={handleAutoFill} className="p-2 text-xs bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded hover:bg-blue-200 transition-colors" title="自动排程">
                    <i className="fas fa-magic"></i>
                </button>
                <button onClick={exportReport} className="p-2 text-xs bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded hover:bg-green-200 transition-colors" title="导出日报">
                    <i className="fas fa-file-export"></i>
                </button>
                <button onClick={() => setIsCalendarOpen(false)} className="p-2 text-gray-400 hover:text-gray-600">
                    <i className="fas fa-times"></i>
                </button>
            </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
            {/* Left Strip: Unassigned Blocks */}
            <div 
                className="w-1/3 bg-gray-50 dark:bg-black/20 border-r border-gray-200 dark:border-gray-700 p-2 overflow-y-auto flex flex-col"
                onDragOver={(e) => e.preventDefault()}
                onDrop={() => handleDrop(undefined)}
            >
                <h3 className="text-[10px] uppercase font-bold text-gray-400 mb-2 text-center tracking-wider">磁贴库</h3>

                {/* Add New Block Input */}
                <div className="mb-2 flex flex-col gap-1">
                   <input 
                     value={newBlockTitle}
                     onChange={e => setNewBlockTitle(e.target.value)}
                     placeholder="添加代办..."
                     className="w-full text-xs p-1 rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 focus:outline-none focus:border-purple-500"
                     onKeyDown={e => e.key === 'Enter' && handleAddBlock()}
                   />
                   {newBlockTitle && (
                      <button onClick={handleAddBlock} className="text-[10px] bg-purple-100 text-purple-600 rounded py-1 hover:bg-purple-200">
                        <i className="fas fa-plus"></i> 添加
                      </button>
                   )}
                </div>

                <div className="space-y-2 pb-10 flex-1">
                    {calendarBlocks.filter(b => !b.assignedTime).map(block => (
                        <div
                            key={block.id}
                            draggable
                            onDragStart={() => handleDragStart(block)}
                            className="p-2 bg-white dark:bg-gray-800 border border-purple-200 dark:border-purple-900/50 rounded shadow-sm text-xs cursor-grab active:cursor-grabbing hover:scale-105 transition-transform"
                        >
                            <div className="font-bold text-gray-700 dark:text-gray-200 truncate">{block.title}</div>
                            <div className="text-[10px] text-gray-400">{block.duration} min</div>
                        </div>
                    ))}
                    {calendarBlocks.filter(b => !b.assignedTime).length === 0 && (
                        <div className="text-center text-xs text-gray-400 py-4 opacity-50">空空如也</div>
                    )}
                </div>
            </div>

            {/* Right Area: Timeline */}
            <div className="flex-1 overflow-y-auto p-2 relative">
                {/* Timeline Line */}
                <div className="absolute left-10 top-0 bottom-0 w-px bg-gray-200 dark:bg-gray-700"></div>

                <div className="space-y-1 pb-10">
                    {hours.map(hour => {
                        const timeStr = `${hour.toString().padStart(2,'0')}:00`;
                        const blocksInSlot = calendarBlocks.filter(b => b.assignedTime === timeStr);

                        return (
                            <div 
                                key={hour}
                                onDragOver={(e) => e.preventDefault()}
                                onDrop={() => handleDrop(timeStr)}
                                className={`flex group min-h-[50px] rounded-lg transition-colors ${blocksInSlot.length > 0 ? 'bg-purple-50/50 dark:bg-purple-900/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800/30'}`}
                            >
                                {/* Time Label */}
                                <div className="w-12 text-[10px] text-gray-400 font-mono py-2 text-right pr-3 shrink-0">
                                    {timeStr}
                                </div>

                                {/* Drop Zone */}
                                <div className="flex-1 p-1 flex flex-col justify-center gap-1 border-l border-transparent group-hover:border-purple-300 dark:group-hover:border-purple-700 transition-colors">
                                    {blocksInSlot.map(block => (
                                        <div
                                            key={block.id}
                                            draggable
                                            onDragStart={() => handleDragStart(block)}
                                            className="px-2 py-1.5 bg-purple-100 dark:bg-purple-900/40 border border-purple-200 dark:border-purple-700/50 rounded text-xs flex justify-between items-center cursor-grab"
                                        >
                                            <span className="font-medium text-purple-900 dark:text-purple-100 truncate">{block.title}</span>
                                            <span className="text-[9px] text-purple-600 dark:text-purple-300">{block.duration}m</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

