export default function App() {
  // Theme State
  const [theme, setTheme] = useState<ThemeMode>('light');

  // User State
  const [user, setUser] = useState<User>({
    username: 'Guest',
    isLoggedIn: false,
    role: 'guest'
  });

  // Global Knowledge Graph State
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [savedGraphs, setSavedGraphs] = useState<SavedGraph[]>([]);

  // Calendar & Weather State
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const [calendarBlocks, setCalendarBlocks] = useState<CalendarBlock[]>([]);
  const [weather, setWeather] = useState<WeatherState>({ type: 'sunny', temp: 24, icon: 'fa-sun' });
  const [mood, setMood] = useState('😐');

  // Load persistence
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as ThemeMode || 'light';
    setTheme(savedTheme);

    // Load Saved Graphs
    const saved = localStorage.getItem('saved_graphs');
    if (saved) {
      try {
        setSavedGraphs(JSON.parse(saved));
      } catch(e) { console.error("Failed to load graphs"); }
    }

    // Load Calendar Blocks
    const savedBlocks = localStorage.getItem('calendar_blocks');
    if (savedBlocks) {
      try {
        setCalendarBlocks(JSON.parse(savedBlocks));
      } catch(e) { console.error("Failed to load calendar"); }
    }
  }, []);

  // Save Persistence (Graphs)
  useEffect(() => {
      localStorage.setItem('saved_graphs', JSON.stringify(savedGraphs));
  }, [savedGraphs]);

  // Save Persistence (Calendar)
  useEffect(() => {
      localStorage.setItem('calendar_blocks', JSON.stringify(calendarBlocks));
  }, [calendarBlocks]);

  // Effect to handle CSS class application based on state
  useEffect(() => {
    const root = document.documentElement;
    const isSystemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (theme === 'dark' || (theme === 'system' && isSystemDark)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    // Cycle: Light -> Dark -> System -> Light
    let newTheme: ThemeMode = 'light';
    if (theme === 'light') newTheme = 'dark';
    else if (theme === 'dark') newTheme = 'system';

    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
  };

  // User Auth Methods
  const login = (username: string) => {
    setUser({
      username,
      isLoggedIn: true,
      role: 'user'
    });
  };

  const logout = () => {
    setUser({
      username: 'Guest',
      isLoggedIn: false,
      role: 'guest'
    });
  };

  // Graph Persistence Methods
  const saveGraph = (name: string, selectedNodeIds?: string[]) => {
    let nodesToSave = nodes;
    let linksToSave = links;

    // Filter if specific selection
    if (selectedNodeIds && selectedNodeIds.length > 0) {
        nodesToSave = nodes.filter(n => selectedNodeIds.includes(n.id));
        linksToSave = links.filter(l => selectedNodeIds.includes(l.source) && selectedNodeIds.includes(l.target));
    }

    const newGraph: SavedGraph = {
      id: Date.now().toString(),
      name,
      date: Date.now(),
      nodes: [...nodesToSave], // Copy
      links: [...linksToSave]
    };
    setSavedGraphs(prev => [newGraph, ...prev]);
  };

  const loadGraph = (id: string) => {
    const graph = savedGraphs.find(g => g.id === id);
    if (graph) {
      setNodes(graph.nodes);
      setLinks(graph.links);
    }
  };

  const deleteGraph = (id: string) => {
    setSavedGraphs(prev => prev.filter(g => g.id !== id));
  };

  // Calendar Methods
  const addCalendarBlock = (block: CalendarBlock) => {
    setCalendarBlocks(prev => [...prev, block]);
  };

  const updateCalendarBlock = (id: string, updates: Partial<CalendarBlock>) => {
      // If updates is null/undefined (used for deletion), filter it out
      // But type definition is Partial<CalendarBlock>, so we need a separate delete method or convention.
      // Let's stick to update logic here and handle deletion via state filtering in the component or add a delete method.
      // Actually, let's add a delete method to context in types if strict, but for now I'll implement delete logic via filtering 
      // by exposing setCalendarBlocks logic indirectly or just adding a specific property like 'deleted'.
      // Better yet, let's just use setCalendarBlocks directly if exposed, or modify this function to handle a delete flag.

      // Simpler approach: If updates has a flag or we export a delete function. 
      // Since context interface is fixed in previous prompts, I will use setCalendarBlocks 
      // exposed via Context to delete in component, or add a delete method here if I could change types.
      // I will assume I can change types/constants if needed, but to minimize churn:
      // I'll add `deleteCalendarBlock` to context.
      setCalendarBlocks(prev => prev.map(b => b.id === id ? {...b, ...updates} : b));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <UserContext.Provider value={{ user, login, logout }}>
        <GlobalContext.Provider value={{ 
          nodes, setNodes, 
          links, setLinks, 
          savedGraphs, saveGraph, loadGraph, deleteGraph,
          isCalendarOpen, setIsCalendarOpen,
          calendarBlocks, 
          addCalendarBlock, 
          updateCalendarBlock, 
          setCalendarBlocks, // Exposing setter for deletion logic
          weather, setWeather, mood, setMood
        } as any}> 
          <Router>
            <AppContent />
          </Router>
        </GlobalContext.Provider>
      </UserContext.Provider>
    </ThemeContext.Provider>
  );
}

import React, { useContext, useEffect, useState } from 'react';
import { GlobalContext, ThemeContext } from '../constants';

export const SystemStatus: React.FC = () => {
  const { weather, setWeather, mood, setMood, setIsCalendarOpen, isCalendarOpen } = useContext(GlobalContext);
  const { theme } = useContext(ThemeContext);
  const [time, setTime] = useState(new Date());
  const [locationName, setLocationName] = useState('');

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  // Real-time Weather Fetching
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          // Open-Meteo Free API
          const response = await fetch(
            `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current_weather=true`
          );
          const data = await response.json();

          if (data.current_weather) {
            const code = data.current_weather.weathercode;
            let weatherType: any = 'sunny';
            let icon = 'fa-sun';

            // Map WMO codes
            if (code <= 1) { weatherType = 'sunny'; icon = 'fa-sun'; }
            else if (code <= 3) { weatherType = 'cloudy'; icon = 'fa-cloud'; }
            else if (code <= 48) { weatherType = 'foggy'; icon = 'fa-smog'; }
            else if (code <= 67) { weatherType = 'rainy'; icon = 'fa-cloud-rain'; }
            else if (code <= 77) { weatherType = 'snow'; icon = 'fa-snowflake'; }
            else if (code <= 82) { weatherType = 'rainy'; icon = 'fa-cloud-showers-heavy'; }
            else if (code <= 99) { weatherType = 'storm'; icon = 'fa-bolt'; }

            setWeather({
              type: weatherType,
              temp: Math.round(data.current_weather.temperature),
              icon: icon
            });
            setLocationName('本地'); // Could use reverse geocoding here if API available
          }
        } catch (error) {
          console.error("Weather fetch failed", error);
        }
      }, (error) => {
        console.warn("Location permission denied", error);
        // Fallback or keep default
      });
    }
  }, []);

  const moodOptions = ['🤩', '🙂', '😐', '😫', '😡', '🤯', '😴', '🧐'];

  const handleMoodClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      const currentIndex = moodOptions.indexOf(mood);
      const nextIndex = (currentIndex + 1) % moodOptions.length;
      setMood(moodOptions[nextIndex]);
  };

  return (
    <div 
        className="flex items-center gap-3 text-xs font-mono select-none bg-white/60 dark:bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm cursor-pointer hover:bg-white/80 dark:hover:bg-black/60 transition-all z-50"
        onClick={() => setIsCalendarOpen(!isCalendarOpen)}
        title="点击打开/关闭学习日历"
    >
      {/* Time */}
      <div className={`flex items-center gap-1 ${theme === 'dark' ? 'text-gray-300' : 'text-gray-600'}`}>
         <span>{time.getHours().toString().padStart(2,'0')}:{time.getMinutes().toString().padStart(2,'0')}</span>
      </div>

      <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>

      {/* Weather (Read-only, Real-time) */}
      <div 
        className="flex items-center gap-1 text-blue-500"
        title="本地实时天气"
      >
         <i className={`fas ${weather.icon}`}></i>
         <span>{weather.temp}°C</span>
      </div>

      <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>

      {/* Mood */}
      <div 
         className="text-base hover:scale-110 transition-transform active:scale-90"
         onClick={handleMoodClick}
         title="点击切换心情"
      >
         {mood}
      </div>

      {/* Indicator */}
      <i className={`fas fa-chevron-${isCalendarOpen ? 'up' : 'down'} text-[10px] opacity-50 ml-1`}></i>
    </div>
  );
};

import React, { useContext, useState } from 'react';
import { GlobalContext } from '../constants';
import { CalendarBlock } from '../types';

export const CalendarOverlay: React.FC = () => {
  const { isCalendarOpen, setIsCalendarOpen, calendarBlocks, updateCalendarBlock, addCalendarBlock, setCalendarBlocks, weather, mood } = useContext(GlobalContext) as any;
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);
  const [newBlockTitle, setNewBlockTitle] = useState('');

  // Time Slots: 07:00 - 23:00
  const hours = Array.from({ length: 17 }, (_, i) => i + 7);

  if (!isCalendarOpen) return null;

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
  };

  const handleDrop = (time: string | undefined) => {
    if (draggedBlock) {
      updateCalendarBlock(draggedBlock.id, { assignedTime: time });
      setDraggedBlock(null);
    }
  };

  const handleDeleteBlock = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('确定删除这个学习磁块吗？')) {
        setCalendarBlocks((prev: CalendarBlock[]) => prev.filter(b => b.id !== id));
    }
  };

  const handleAutoFill = () => {
      // Simple heuristic: fill empty slots starting from 09:00 with available blocks
      let currentHour = 9;
      const unassignedBlocks = calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime);

      unassignedBlocks.forEach((block: CalendarBlock) => {
          if (currentHour < 22) {
             updateCalendarBlock(block.id, { assignedTime: `${currentHour.toString().padStart(2,'0')}:00` });
             currentHour += Math.ceil(block.duration / 60);
          }
      });
  };

  const exportReport = () => {
    const header = `每日复盘 (Daily Report) - ${new Date().toLocaleDateString()}\n天气: ${weather.type} (${weather.temp}°C) | 心情: ${mood}\n\n`;
    const csvContent = "时间,任务,时长,状态\n" + 
      calendarBlocks
        .sort((a: CalendarBlock, b: CalendarBlock) => (a.assignedTime || 'z').localeCompare(b.assignedTime || 'z'))
        .map((b: CalendarBlock) => `${b.assignedTime || '未安排'},${b.title},${b.duration}分钟,${b.isCompleted?'完成':'待办'}`)
        .join("\n");

    // Add BOM (\uFEFF) for Excel to recognize UTF-8/Chinese correctly
    const blob = new Blob(['\uFEFF' + header + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `daily_report_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleAddBlock = () => {
    if(!newBlockTitle.trim()) return;
    addCalendarBlock({
      id: Date.now().toString(),
      title: newBlockTitle,
      duration: 30,
      type: 'other'
    });
    setNewBlockTitle('');
  };

  return (
    <div className="fixed inset-0 z-[100] flex justify-end pointer-events-none">
      {/* Backdrop (Click to close) */}
      <div 
        className="absolute inset-0 bg-black/20 backdrop-blur-[2px] pointer-events-auto transition-opacity" 
        onClick={() => setIsCalendarOpen(false)}
      ></div>

      {/* Calendar Panel */}
      <div className="relative w-full md:w-[500px] h-full bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl pointer-events-auto flex flex-col animate-[slideInRight_0.3s_ease-out]">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-black/20">
            <div>
                <h2 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2">
                    <i className="fas fa-calendar-alt text-purple-500"></i> 
                    学习磁贴日历
                </h2>
                <div className="text-xs text-gray-500 mt-1 flex gap-2">
                   <span><i className={`fas ${weather.icon}`}></i> {weather.temp}°C</span>
                   <span>{mood} 今日心情</span>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={handleAutoFill} className="p-2 text-xs bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded hover:bg-blue-200 transition-colors" title="自动排程">
                    <i className="fas fa-magic"></i> 自动
                </button>
                <button onClick={exportReport} className="p-2 text-xs bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded hover:bg-green-200 transition-colors" title="导出GB格式日报">
                    <i className="fas fa-file-export"></i> 导出
                </button>
                <button onClick={() => setIsCalendarOpen(false)} className="p-2 text-gray-400 hover:text-gray-600">
                    <i className="fas fa-times"></i>
                </button>
            </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
            {/* Left Strip: Unassigned Blocks (GRID LAYOUT) */}
            <div 
                className="w-[180px] bg-gray-50 dark:bg-black/20 border-r border-gray-200 dark:border-gray-700 p-3 overflow-y-auto flex flex-col"
                onDragOver={(e) => e.preventDefault()}
                onDrop={() => handleDrop(undefined)}
            >
                <h3 className="text-[10px] uppercase font-bold text-gray-400 mb-2 text-center tracking-wider">磁贴库 (拖拽)</h3>

                {/* Add New Block Input */}
                <div className="mb-4 flex flex-col gap-2">
                   <input 
                     value={newBlockTitle}
                     onChange={e => setNewBlockTitle(e.target.value)}
                     placeholder="添加代办..."
                     className="w-full text-xs p-2 rounded border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 focus:outline-none focus:border-purple-500"
                     onKeyDown={e => e.key === 'Enter' && handleAddBlock()}
                   />
                   {newBlockTitle && (
                      <button onClick={handleAddBlock} className="text-[10px] bg-purple-100 text-purple-600 rounded py-1 hover:bg-purple-200 w-full font-bold">
                        + 添加
                      </button>
                   )}
                </div>

                {/* Grid Container for Blocks */}
                <div className="grid grid-cols-2 gap-2 pb-10 content-start">
                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).map((block: CalendarBlock) => (
                        <div
                            key={block.id}
                            draggable
                            onDragStart={() => handleDragStart(block)}
                            className="relative group p-2 bg-white dark:bg-gray-800 border border-purple-200 dark:border-purple-900/50 rounded shadow-sm text-xs cursor-grab active:cursor-grabbing hover:scale-105 transition-transform flex flex-col justify-between min-h-[60px]"
                        >
                            <div className="font-bold text-gray-700 dark:text-gray-200 line-clamp-2 leading-tight">{block.title}</div>
                            <div className="text-[9px] text-gray-400 mt-1">{block.duration}m</div>

                            {/* Delete Button */}
                            <button 
                                onClick={(e) => handleDeleteBlock(e, block.id)}
                                className="absolute -top-1 -right-1 w-4 h-4 bg-red-400 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"
                                title="删除"
                            >
                                <i className="fas fa-times text-[8px]"></i>
                            </button>
                        </div>
                    ))}

                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).length === 0 && (
                        <div className="col-span-2 text-center text-xs text-gray-400 py-4 opacity-50">
                            暂无待办事项
                        </div>
                    )}
                </div>
            </div>

            {/* Right Area: Timeline */}
            <div className="flex-1 overflow-y-auto p-4 relative bg-white dark:bg-gray-900">
                {/* Timeline Visual Line */}
                <div className="absolute left-[3.5rem] top-0 bottom-0 w-px bg-purple-100 dark:bg-purple-900/30"></div>

                <div className="space-y-2 pb-20">
                    {hours.map(hour => {
                        const timeStr = `${hour.toString().padStart(2,'0')}:00`;
                        const nextHourStr = `${(hour + 1).toString().padStart(2,'0')}:00`;
                        const blocksInSlot = calendarBlocks.filter((b: CalendarBlock) => b.assignedTime === timeStr);

                        return (
                            <div 
                                key={hour}
                                onDragOver={(e) => e.preventDefault()}
                                onDrop={() => handleDrop(timeStr)}
                                className={`flex min-h-[60px] rounded-xl transition-all border border-transparent ${blocksInSlot.length > 0 ? 'bg-purple-50/50 dark:bg-purple-900/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800/30 hover:border-gray-100 dark:hover:border-gray-700'}`}
                            >
                                {/* Optimized Time Label */}
                                <div className="w-14 text-[10px] text-gray-400 font-mono py-3 flex flex-col items-end pr-3 shrink-0 leading-none gap-1">
                                    <span className="font-bold text-gray-600 dark:text-gray-300">{timeStr}</span>
                                    <span className="text-[9px] opacity-50">{nextHourStr}</span>
                                </div>

                                {/* Drop Zone */}
                                <div className="flex-1 p-1 flex flex-col justify-center gap-1">
                                    {blocksInSlot.map((block: CalendarBlock) => (
                                        <div
                                            key={block.id}
                                            draggable
                                            onDragStart={() => handleDragStart(block)}
                                            className="group relative px-3 py-2 bg-purple-100 dark:bg-purple-900/40 border-l-4 border-purple-500 dark:border-purple-400 rounded-r text-xs flex justify-between items-center cursor-grab shadow-sm"
                                        >
                                            <span className="font-medium text-purple-900 dark:text-purple-100 truncate flex-1">{block.title}</span>
                                            <span className="text-[9px] text-purple-600 dark:text-purple-300 ml-2 bg-white/50 dark:bg-black/20 px-1 rounded">{block.duration}m</span>

                                            {/* Delete Button (Assigned) */}
                                            <button 
                                                onClick={(e) => handleDeleteBlock(e, block.id)}
                                                className="ml-2 text-purple-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <i className="fas fa-times"></i>
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

