                <div className="text-xs text-gray-500 mt-1 flex gap-3 font-mono">
                   <span className="flex items-center gap-1"><i className={`fas ${weather.icon} text-blue-500`}></i> {weather.temp}°C</span>
                   <span className="flex items-center gap-1">心情: {mood}</span>
