            </div>
            <div className="flex gap-2">
                <button onClick={handleAutoFill} className="px-3 py-1.5 text-xs bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 border border-blue-200 dark:border-blue-800 transition-colors">
