import React, { useContext, useEffect, useState, useRef } from 'react';
import { GlobalContext, ThemeContext } from '../constants';

export const SystemStatus: React.FC = () => {
  const { weather, setWeather, mood, setMood, setIsCalendarOpen, isCalendarOpen } = useContext(GlobalContext);
  const { theme } = useContext(ThemeContext);
  const [time, setTime] = useState(new Date());
  const [showMoodSelector, setShowMoodSelector] = useState(false);
  const moodRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (moodRef.current && !moodRef.current.contains(event.target as Node)) {
        setShowMoodSelector(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Real-time Weather Fetching
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          const response = await fetch(
            `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current_weather=true`
          );
          const data = await response.json();

          if (data.current_weather) {
            const code = data.current_weather.weathercode;
            let weatherType: any = 'sunny';
            let icon = 'fa-sun';

            if (code <= 1) { weatherType = 'sunny'; icon = 'fa-sun'; }
            else if (code <= 3) { weatherType = 'cloudy'; icon = 'fa-cloud'; }
            else if (code <= 48) { weatherType = 'foggy'; icon = 'fa-smog'; }
            else if (code <= 67) { weatherType = 'rainy'; icon = 'fa-cloud-rain'; }
            else if (code <= 77) { weatherType = 'snow'; icon = 'fa-snowflake'; }
            else if (code <= 82) { weatherType = 'rainy'; icon = 'fa-cloud-showers-heavy'; }
            else if (code <= 99) { weatherType = 'storm'; icon = 'fa-bolt'; }

            setWeather({
              type: weatherType,
              temp: Math.round(data.current_weather.temperature),
              icon: icon
            });
          }
        } catch (error) {
          console.error("Weather fetch failed", error);
        }
      }, (error) => {
        console.warn("Location permission denied", error);
      });
    }
  }, []);

  const moodOptions = ['🤩', '🙂', '😐', '😫', '😡', '🤯', '😴', '🧐', '🥳', '😎', '😭', '👻'];

  const toggleMood = (emoji: string) => {
      // Split current mood into array, defaulting to empty if it's the initial string
      let currentMoods = Array.from(mood); 
      // Filter out non-emoji chars if necessary, but simple split works for emojis mostly. 
      // Actually better to treat the string as a list of characters.
      // However, spread operator [...mood] works for emojis.

      const parts = [...mood].filter(c => moodOptions.includes(c)); // Basic filter

      if (parts.includes(emoji)) {
          const newMoods = parts.filter(m => m !== emoji);
          setMood(newMoods.length > 0 ? newMoods.join('') : '😐');
      } else {
          if (parts.length === 1 && parts[0] === '😐') {
              setMood(emoji);
          } else {
              setMood(parts.join('') + emoji);
          }
      }
  };

  return (
    <div className="relative flex items-center gap-3 text-xs font-mono select-none bg-white/60 dark:bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm z-50">

      {/* Time & Weather Trigger Calendar */}
      <div 
        className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity"
        onClick={() => setIsCalendarOpen(!isCalendarOpen)}
        title="点击打开/关闭学习日历"
      >
          {/* Time */}
          <div className={`flex items-center gap-1 ${theme === 'dark' ? 'text-gray-300' : 'text-gray-600'}`}>
            <span>{time.getHours().toString().padStart(2,'0')}:{time.getMinutes().toString().padStart(2,'0')}</span>
          </div>

          <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>

          {/* Weather */}
          <div className="flex items-center gap-1 text-blue-500">
            <i className={`fas ${weather.icon}`}></i>
            <span>{weather.temp}°C</span>
          </div>

          <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>
      </div>

      {/* Mood Selector */}
      <div className="relative" ref={moodRef}>
          <div 
            className="text-base hover:scale-110 transition-transform active:scale-90 cursor-pointer"
            onClick={() => setShowMoodSelector(!showMoodSelector)}
            title="点击切换心情"
          >
            {mood}
          </div>

          {showMoodSelector && (
              <div className="absolute top-full right-0 mt-3 p-2 bg-white dark:bg-gray-800 rounded-xl shadow-xl border border-gray-200 dark:border-gray-700 grid grid-cols-4 gap-2 w-48 animate-[fadeIn_0.2s]">
                  {moodOptions.map(m => (
                      <button 
                        key={m}
                        onClick={() => toggleMood(m)}
                        className={`text-xl p-2 rounded hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors ${mood.includes(m) ? 'bg-purple-100 dark:bg-purple-900/50' : ''}`}
                      >
                          {m}
                      </button>
                  ))}
              </div>
          )}
      </div>

      <i 
        className={`fas fa-chevron-${isCalendarOpen ? 'up' : 'down'} text-[10px] opacity-50 ml-1 cursor-pointer`}
        onClick={() => setIsCalendarOpen(!isCalendarOpen)}
      ></i>
    </div>
  );
};

import React, { useContext, useState } from 'react';
import { GlobalContext } from '../constants';
import { CalendarBlock } from '../types';

export const CalendarOverlay: React.FC = () => {
  const { isCalendarOpen, setIsCalendarOpen, calendarBlocks, updateCalendarBlock, addCalendarBlock, setCalendarBlocks, weather, mood } = useContext(GlobalContext) as any;
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);
  const [newBlockTitle, setNewBlockTitle] = useState('');
  const [newBlockType, setNewBlockType] = useState<'study'|'exam'|'rest'|'other'|'weather'|'mood'>('study');

  // Time Slots: 06:00 - 23:00
  const hours = Array.from({ length: 18 }, (_, i) => i + 6);

  if (!isCalendarOpen) return null;

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
  };

  const handleDrop = (time: string | undefined) => {
    if (draggedBlock) {
      updateCalendarBlock(draggedBlock.id, { assignedTime: time });
      setDraggedBlock(null);
    }
  };

  const handleDeleteBlock = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm('确定删除这个学习磁块吗？')) {
        setCalendarBlocks((prev: CalendarBlock[]) => prev.filter(b => b.id !== id));
    }
  };

  const handleAutoFill = () => {
      let currentHour = 9;
      const unassignedBlocks = calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime);
      unassignedBlocks.forEach((block: CalendarBlock) => {
          if (currentHour < 22) {
             updateCalendarBlock(block.id, { assignedTime: `${currentHour.toString().padStart(2,'0')}:00` });
             currentHour += Math.ceil(block.duration / 60);
          }
      });
  };

  const exportReport = () => {
    const header = `每日复盘 (Daily Report) - ${new Date().toLocaleDateString()}\n`;
    const csvContent = "时间,任务,类型,时长,状态\n" + 
      calendarBlocks
        .sort((a: CalendarBlock, b: CalendarBlock) => (a.assignedTime || 'z').localeCompare(b.assignedTime || 'z'))
        .map((b: CalendarBlock) => `${b.assignedTime || '未安排'},${b.title},${b.type},${b.duration}分钟,${b.isCompleted?'完成':'待办'}`)
        .join("\n");
    const blob = new Blob(['\uFEFF' + header + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `daily_report_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleAddBlock = () => {
    if(!newBlockTitle.trim()) return;
    addCalendarBlock({
      id: Date.now().toString(),
      title: newBlockTitle,
      duration: 30,
      type: newBlockType
    });
    setNewBlockTitle('');
  };

  const handleAddMoodBlock = () => {
      addCalendarBlock({
          id: `mood_${Date.now()}`,
          title: `心情: ${mood}`,
          duration: 15,
          type: 'mood',
          assignedTime: undefined
      });
  };

  const handleAddWeatherBlock = () => {
      const timeStr = `${new Date().getHours().toString().padStart(2,'0')}:00`;
      // Default to adding at current hour if possible, or pool
      addCalendarBlock({
          id: `weather_${Date.now()}`,
          title: `天气: ${weather.type} (${weather.temp}°C)`,
          duration: 15,
          type: 'weather',
          assignedTime: timeStr 
      });
  };

  // Type Color Mapping
  const getTypeColor = (type: string) => {
      switch(type) {
          case 'study': return 'bg-blue-100 dark:bg-blue-900/40 border-blue-200 dark:border-blue-700/50 text-blue-900 dark:text-blue-100';
          case 'exam': return 'bg-red-100 dark:bg-red-900/40 border-red-200 dark:border-red-700/50 text-red-900 dark:text-red-100';
          case 'rest': return 'bg-emerald-100 dark:bg-emerald-900/40 border-emerald-200 dark:border-emerald-700/50 text-emerald-900 dark:text-emerald-100';
          case 'weather': return 'bg-sky-100 dark:bg-sky-900/40 border-sky-200 dark:border-sky-700/50 text-sky-900 dark:text-sky-100';
          case 'mood': return 'bg-pink-100 dark:bg-pink-900/40 border-pink-200 dark:border-pink-700/50 text-pink-900 dark:text-pink-100';
          case 'other': default: return 'bg-gray-100 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-900 dark:text-gray-100';
      }
  };

  const getTypeIcon = (type: string) => {
      switch(type) {
          case 'study': return 'fa-book-open';
          case 'exam': return 'fa-exclamation-circle';
          case 'rest': return 'fa-coffee';
          case 'weather': return 'fa-cloud';
          case 'mood': return 'fa-smile';
          case 'other': return 'fa-sticky-note';
          default: return 'fa-circle';
      }
  };

  return (
    <div className="fixed inset-0 z-[100] flex justify-end pointer-events-none">
      <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px] pointer-events-auto transition-opacity" onClick={() => setIsCalendarOpen(false)}></div>

      <div className="relative w-full md:w-[600px] h-full bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl pointer-events-auto flex flex-col animate-[slideInRight_0.3s_ease-out]">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-black/20">
            <div>
                <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2 tracking-tight">
                    <span className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center text-white shadow-md"><i className="fas fa-calendar-day"></i></span>
                    日程规划
                </h2>
                <div className="text-xs text-gray-500 mt-1 flex gap-3 font-mono">
                   <span>{new Date().toLocaleDateString()}</span>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={handleAutoFill} className="px-3 py-1.5 text-xs bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 border border-blue-200 dark:border-blue-800 transition-colors">
                    <i className="fas fa-magic mr-1"></i>自动
                </button>
                <button onClick={exportReport} className="px-3 py-1.5 text-xs bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400 rounded-lg hover:bg-green-100 border border-green-200 dark:border-green-800 transition-colors">
                    <i className="fas fa-file-export mr-1"></i>导出
                </button>
                <button onClick={() => setIsCalendarOpen(false)} className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gray-600 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                    <i className="fas fa-times"></i>
                </button>
            </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
            {/* Left Strip: Pool */}
            <div className="w-[200px] bg-gray-50 dark:bg-black/20 border-r border-gray-200 dark:border-gray-700 p-3 overflow-y-auto flex flex-col" onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop(undefined)}>
                <h3 className="text-[10px] uppercase font-bold text-gray-400 mb-3 text-center tracking-widest">任务池</h3>

                {/* Quick Add Buttons */}
                <div className="grid grid-cols-2 gap-2 mb-3">
                    <button 
                        onClick={handleAddMoodBlock}
                        className="p-2 bg-pink-100 dark:bg-pink-900/30 text-pink-600 dark:text-pink-300 rounded-lg text-xs font-medium hover:bg-pink-200 transition-colors border border-pink-200 dark:border-pink-800"
                        title="添加当前心情磁块"
                    >
                        <i className="fas fa-smile mr-1"></i> +心情
                    </button>
                    <button 
                        onClick={handleAddWeatherBlock}
                        className="p-2 bg-sky-100 dark:bg-sky-900/30 text-sky-600 dark:text-sky-300 rounded-lg text-xs font-medium hover:bg-sky-200 transition-colors border border-sky-200 dark:border-sky-800"
                        title="添加当前天气磁块"
                    >
                        <i className="fas fa-cloud mr-1"></i> +天气
                    </button>
                </div>

                <div className="mb-4 bg-white dark:bg-gray-800 p-2 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
                   <div className="flex gap-1 mb-2 overflow-x-auto pb-1 no-scrollbar">
                       {(['study','exam','rest','other'] as const).map(t => (
                           <button 
                             key={t}
                             onClick={() => setNewBlockType(t)}
                             className={`flex-shrink-0 px-2 h-6 rounded flex items-center justify-center text-[10px] transition-all ${newBlockType === t ? 'bg-gray-800 text-white dark:bg-white dark:text-black shadow' : 'bg-gray-100 dark:bg-gray-700 text-gray-400 hover:bg-gray-200'}`}
