export default function App() {
  // Theme State
  const [theme, setTheme] = useState<ThemeMode>('light');

  // User State
  const [user, setUser] = useState<User>({
    username: 'Guest',
    isLoggedIn: false,
    role: 'guest'
  });

  // Global Knowledge Graph State
  const [nodes, setNodes] = useState<KnowledgeNode[]>(INITIAL_NODES);
  const [links, setLinks] = useState<KnowledgeLink[]>(INITIAL_LINKS);
  const [savedGraphs, setSavedGraphs] = useState<SavedGraph[]>([]);

  // Knowledge Transfer Station
  const [transferStation, setTransferStation] = useState<KnowledgeNode[]>([]);

  // Calendar & Weather State
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const [calendarBlocks, setCalendarBlocks] = useState<CalendarBlock[]>([]);
  const [weather, setWeather] = useState<WeatherState>({ type: 'sunny', temp: 24, icon: 'fa-sun' });
  const [mood, setMood] = useState('😐');

  // Load persistence
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as ThemeMode || 'light';
    setTheme(savedTheme);

    // Load Saved Graphs
    const saved = localStorage.getItem('saved_graphs');
    if (saved) {
      try {
        setSavedGraphs(JSON.parse(saved));
      } catch(e) { console.error("Failed to load graphs"); }
    }

    // Load Calendar Blocks
    const savedBlocks = localStorage.getItem('calendar_blocks');
    if (savedBlocks) {
      try {
        setCalendarBlocks(JSON.parse(savedBlocks));
      } catch(e) { console.error("Failed to load calendar"); }
    }
  }, []);

  // Save Persistence (Graphs)
  useEffect(() => {
      localStorage.setItem('saved_graphs', JSON.stringify(savedGraphs));
  }, [savedGraphs]);

  // Save Persistence (Calendar)
  useEffect(() => {
      localStorage.setItem('calendar_blocks', JSON.stringify(calendarBlocks));
  }, [calendarBlocks]);

  // Effect to handle CSS class application based on state
  useEffect(() => {
    const root = document.documentElement;
    const isSystemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (theme === 'dark' || (theme === 'system' && isSystemDark)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    // Cycle: Light -> Dark -> System -> Light
    let newTheme: ThemeMode = 'light';
    if (theme === 'light') newTheme = 'dark';
    else if (theme === 'dark') newTheme = 'system';

    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
  };

  // User Auth Methods
  const login = (username: string) => {
    setUser({
      username,
      isLoggedIn: true,
      role: 'user'
    });
  };

  const logout = () => {
    setUser({
      username: 'Guest',
      isLoggedIn: false,
      role: 'guest'
    });
  };

  // Graph Persistence Methods
  const saveGraph = (name: string, selectedNodeIds?: string[]) => {
    let nodesToSave = nodes;
    let linksToSave = links;

    // Filter if specific selection
    if (selectedNodeIds && selectedNodeIds.length > 0) {
        nodesToSave = nodes.filter(n => selectedNodeIds.includes(n.id));
        linksToSave = links.filter(l => selectedNodeIds.includes(l.source) && selectedNodeIds.includes(l.target));
    }

    const newGraph: SavedGraph = {
      id: Date.now().toString(),
      name,
      date: Date.now(),
      nodes: [...nodesToSave], // Copy
      links: [...linksToSave]
    };
    setSavedGraphs(prev => [newGraph, ...prev]);
  };

  const loadGraph = (id: string) => {
    const graph = savedGraphs.find(g => g.id === id);
    if (graph) {
      setNodes(graph.nodes);
      setLinks(graph.links);
    }
  };

  const deleteGraph = (id: string) => {
    setSavedGraphs(prev => prev.filter(g => g.id !== id));
  };

  // Transfer Station Methods
  const addToTransferStation = (newNodes: KnowledgeNode[]) => {
    setTransferStation(prev => {
      const existingIds = new Set(prev.map(n => n.id));
      const uniqueNewNodes = newNodes.filter(n => !existingIds.has(n.id)).map(n => ({...n, x: 0, y: 0})); // Reset pos
      return [...prev, ...uniqueNewNodes];
    });
  };

  const removeFromTransferStation = (nodeId: string) => {
    setTransferStation(prev => prev.filter(n => n.id !== nodeId));
  };

  // Calendar Methods
  const addCalendarBlock = (block: CalendarBlock) => {
    setCalendarBlocks(prev => [...prev, block]);
  };

  const updateCalendarBlock = (id: string, updates: Partial<CalendarBlock>) => {
      setCalendarBlocks(prev => prev.map(b => b.id === id ? {...b, ...updates} : b));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      <UserContext.Provider value={{ user, login, logout }}>
        <GlobalContext.Provider value={{ 
          nodes, setNodes, 
          links, setLinks, 
          savedGraphs, saveGraph, loadGraph, deleteGraph,
          transferStation, addToTransferStation, removeFromTransferStation,
          isCalendarOpen, setIsCalendarOpen,
          calendarBlocks, 
          addCalendarBlock, 
          updateCalendarBlock, 
          setCalendarBlocks, 
          weather, setWeather, mood, setMood
        } as any}> 
          <Router>
            <AppContent />
          </Router>
        </GlobalContext.Provider>
      </UserContext.Provider>
    </ThemeContext.Provider>
  );
}

import React, { useContext, useEffect, useState, useRef } from 'react';
import { GlobalContext, ThemeContext } from '../constants';

export const SystemStatus: React.FC = () => {
  const { weather, setWeather, mood, setMood, setIsCalendarOpen, isCalendarOpen, addCalendarBlock } = useContext(GlobalContext) as any;
  const { theme } = useContext(ThemeContext);
  const [time, setTime] = useState(new Date());
  const [showMoodSelector, setShowMoodSelector] = useState(false);
  const moodRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (moodRef.current && !moodRef.current.contains(event.target as Node)) {
        setShowMoodSelector(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Real-time Weather Fetching
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const { latitude, longitude } = position.coords;
        try {
          const response = await fetch(
            `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current_weather=true`
          );
          const data = await response.json();

          if (data.current_weather) {
            const code = data.current_weather.weathercode;
            let weatherType: any = 'sunny';
            let icon = 'fa-sun';

            if (code <= 1) { weatherType = 'sunny'; icon = 'fa-sun'; }
            else if (code <= 3) { weatherType = 'cloudy'; icon = 'fa-cloud'; }
            else if (code <= 48) { weatherType = 'foggy'; icon = 'fa-smog'; }
            else if (code <= 67) { weatherType = 'rainy'; icon = 'fa-cloud-rain'; }
            else if (code <= 77) { weatherType = 'snow'; icon = 'fa-snowflake'; }
            else if (code <= 82) { weatherType = 'rainy'; icon = 'fa-cloud-showers-heavy'; }
            else if (code <= 99) { weatherType = 'storm'; icon = 'fa-bolt'; }

            setWeather({
              type: weatherType,
              temp: Math.round(data.current_weather.temperature),
              icon: icon
            });
          }
        } catch (error) {
          console.error("Weather fetch failed", error);
        }
      }, (error) => {
        console.warn("Location permission denied", error);
      });
    }
  }, []);

  const moodOptions = ['🤩', '🙂', '😐', '😫', '😡', '🤯', '😴', '🧐', '🥳', '😎', '😭', '👻'];

  const toggleMood = (emoji: string) => {
      // Split current mood into array, defaulting to empty if it's the initial string
      const parts = [...mood].filter(c => moodOptions.includes(c)); // Basic filter

      let newMoodStr = emoji;
      if (parts.includes(emoji)) {
          const newMoods = parts.filter(m => m !== emoji);
          newMoodStr = newMoods.length > 0 ? newMoods.join('') : '😐';
      } else {
          // If the only current mood is the default 'Neutral' and we click something else, replace it.
          // Otherwise append.
          if (parts.length === 1 && parts[0] === '😐') {
              newMoodStr = emoji;
          } else {
              newMoodStr = parts.join('') + emoji;
          }
      }
      setMood(newMoodStr);

      // INSTANTLY ADD TO CALENDAR
      const currentHourStr = new Date().getHours().toString().padStart(2, '0') + ":00";
      addCalendarBlock({
          id: `instant_mood_${Date.now()}`,
          title: `心情切换: ${emoji}`,
          duration: 15,
          type: 'mood',
          assignedTime: currentHourStr
      });
  };

  return (
    <div className="relative flex items-center gap-3 text-xs font-mono select-none bg-white/60 dark:bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm z-50">

      {/* Time & Weather Trigger Calendar */}
      <div 
        className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity"
        onClick={() => setIsCalendarOpen(!isCalendarOpen)}
        title="点击打开/关闭学习日历"
      >
          {/* Time */}
          <div className={`flex items-center gap-1 ${theme === 'dark' ? 'text-gray-300' : 'text-gray-600'}`}>
            <span>{time.getHours().toString().padStart(2,'0')}:{time.getMinutes().toString().padStart(2,'0')}</span>
          </div>

          <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>

          {/* Weather */}
          <div className="flex items-center gap-1 text-blue-500">
            <i className={`fas ${weather.icon}`}></i>
            <span>{weather.temp}°C</span>
          </div>

          <div className="w-px h-3 bg-gray-300 dark:bg-gray-600"></div>
      </div>

      {/* Mood Selector */}
      <div className="relative" ref={moodRef}>
          <div 
            className="text-base hover:scale-110 transition-transform active:scale-90 cursor-pointer"
            onClick={() => setShowMoodSelector(!showMoodSelector)}
            title="点击切换心情"
          >
            {mood}
          </div>

          {showMoodSelector && (
              <div className="absolute top-full right-0 mt-3 p-2 bg-white dark:bg-gray-800 rounded-xl shadow-xl border border-gray-200 dark:border-gray-700 grid grid-cols-4 gap-2 w-48 animate-[fadeIn_0.2s]">
                  {moodOptions.map(m => (
                      <button 
                        key={m}
                        onClick={() => toggleMood(m)}
                        className={`text-xl p-2 rounded hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors ${mood.includes(m) ? 'bg-purple-100 dark:bg-purple-900/50' : ''}`}
                      >
                          {m}
                      </button>
                  ))}
              </div>
          )}
      </div>

      <i 
        className={`fas fa-chevron-${isCalendarOpen ? 'up' : 'down'} text-[10px] opacity-50 ml-1 cursor-pointer`}
        onClick={() => setIsCalendarOpen(!isCalendarOpen)}
      ></i>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  // Consume Global State
  const { 
      nodes, setNodes, links, setLinks, 
      savedGraphs, saveGraph, loadGraph, deleteGraph,
      transferStation, addToTransferStation, removeFromTransferStation 
  } = useContext(GlobalContext) as any;

  const navigate = useNavigate();
  const location = useLocation();

  // Local Visualization State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // History Stack for Undo/Redo
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false); 
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number; 
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  // Initial History Save & View Restore
  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }

      // Load View State
      const savedTransform = localStorage.getItem('kg_transform');
      if (savedTransform) {
          try {
              const t = JSON.parse(savedTransform);
              setTransform(t);
          } catch(e) {}
      } else {
           setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
      }
  }, [nodes.length]); 

  // Save View State on Change
  useEffect(() => {
      localStorage.setItem('kg_transform', JSON.stringify(transform));
  }, [transform]);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      } else if (selectedId) {
          const newNodes = nodes.filter(n => n.id !== selectedId);
          const newLinks = links.filter(l => l.source !== selectedId && l.target !== selectedId);
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedId(null);
      } else if (selectedLinkIndex !== null) {
          const newLinks = links.filter((_, i) => i !== selectedLinkIndex);
          setLinks(newLinks);
          saveToHistory(nodes, newLinks);
          setSelectedLinkIndex(null);
      }
  }, [selectedId, selectedLinkIndex, selectedNodeIds, nodes, links, saveToHistory]);

  const handleCopy = useCallback(() => {
      const nodesToCopy = nodes.filter(n => selectedNodeIds.has(n.id) || n.id === selectedId);
      if (nodesToCopy.length > 0) {
          addToTransferStation(nodesToCopy);
          // Optional: Tiny toast notification
      }
  }, [nodes, selectedNodeIds, selectedId, addToTransferStation]);

  const handlePaste = useCallback(() => {
      if (transferStation.length > 0) {
         // Paste at center of screen
         const cx = (window.innerWidth / 2 - transform.x) / transform.k;
         const cy = (window.innerHeight / 2 - transform.y) / transform.k;

         const newNodes = [...nodes];
         transferStation.forEach((n: KnowledgeNode, idx: number) => {
             newNodes.push({
                 ...n,
                 id: `paste_${Date.now()}_${idx}`,
                 x: cx + (Math.random() - 0.5) * 50,
                 y: cy + (Math.random() - 0.5) * 50
             });
         });
         setNodes(newNodes);
         saveToHistory(newNodes, links);
      }
  }, [transferStation, transform, nodes, links, saveToHistory]);

  // KEYBOARD SHORTCUTS LISTENER
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        // Ignore if input focused
        if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

        // Save: Ctrl + S
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            setShowSaveModal(true);
        }

        // Undo: Ctrl + Z
        if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            handleUndo();
        }

        // Redo: Ctrl + Y or Ctrl + Shift + Z
        if (((e.ctrlKey || e.metaKey) && e.key === 'y') || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'z')) {
            e.preventDefault();
            handleRedo();
        }

        // Delete: Del or Backspace
        if (e.key === 'Delete' || e.key === 'Backspace') {
            e.preventDefault();
            handleDeleteSelected();
        }

        // Copy: Ctrl + C
        if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
            e.preventDefault();
            handleCopy();
        }

        // Paste: Ctrl + V
        if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
             e.preventDefault();
             handlePaste();
        }

        // Arrow Keys Nudge
        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
            e.preventDefault();
            const step = e.shiftKey ? 10 : 2;
            const dx = e.key === 'ArrowLeft' ? -step : e.key === 'ArrowRight' ? step : 0;
            const dy = e.key === 'ArrowUp' ? -step : e.key === 'ArrowDown' ? step : 0;

            if (selectedNodeIds.size > 0 || selectedId) {
                setNodes((prev: KnowledgeNode[]) => prev.map(n => {
                    if (selectedNodeIds.has(n.id) || n.id === selectedId) {
                        return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
                    }
                    return n;
                }));
            }
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleUndo, handleRedo, handleDeleteSelected, handleCopy, handlePaste, selectedNodeIds, selectedId]);


  // --- Templates & Layouts ---
  const generateTemplate = (type: LayoutType): { nodes: KnowledgeNode[], links: KnowledgeLink[] } => {
      let tNodes: KnowledgeNode[] = [];
      let tLinks: KnowledgeLink[] = [];
      const timestamp = Date.now();

      // Create STANDARD nodes (isGhost: false) so they are persistent and editable immediately
      const createNode = (suffix: string, lbl: string, cat: string, level=0): KnowledgeNode => ({
          id: `node_${type}_${suffix}_${timestamp}`,
          label: lbl,
          category: cat,
          masteryLevel: 50, // Default to 50 for template nodes
          isGhost: false,
          x: 0, y: 0 
      });

      if (type === 'tree') {
          const root = createNode('root', '核心主题', 'root');
          const b1 = createNode('b1', '分支一', 'core');
          const b2 = createNode('b2', '分支二', 'core');
          const s1 = createNode('s1', '细节A', 'sub');
          const s2 = createNode('s2', '细节B', 'sub');
          tNodes = [root, b1, b2, s1, s2];
          tLinks = [
              {source: root.id, target: b1.id, strength: 1},
              {source: root.id, target: b2.id, strength: 1},
              {source: b1.id, target: s1.id, strength: 1},
              {source: b2.id, target: s2.id, strength: 1},
          ];
      } else if (type === 'star') {
          const center = createNode('center', '中心', 'root');
          tNodes.push(center);
          for(let i=1; i<=5; i++) {
              const sat = createNode(`sat${i}`, `维度${i}`, 'core');
              tNodes.push(sat);
              tLinks.push({source: center.id, target: sat.id, strength: 1});
          }
      } else if (type === 'bus') {
          for(let i=0; i<6; i++) {
              tNodes.push(createNode(`bus${i}`, `节点${i+1}`, 'core'));
              if(i>0) tLinks.push({source: tNodes[i-1].id, target: tNodes[i].id, strength: 1});
          }
      } else if (type === 'mesh') {
           for(let i=0; i<6; i++) {
               tNodes.push(createNode(`mesh${i}`, `概念${i+1}`, 'core'));
           }
           tLinks = [
             {source: tNodes[0].id, target: tNodes[1].id, strength: 1},
             {source: tNodes[1].id, target: tNodes[2].id, strength: 1},
             {source: tNodes[2].id, target: tNodes[0].id, strength: 1},
             {source: tNodes[3].id, target: tNodes[4].id, strength: 1},
             {source: tNodes[4].id, target: tNodes[5].id, strength: 1},
             {source: tNodes[5].id, target: tNodes[3].id, strength: 1},
             {source: tNodes[0].id, target: tNodes[3].id, strength: 1}
           ];
      } else {
          tNodes.push(createNode('main', '新主题', 'root'));
      }
      return { nodes: tNodes, links: tLinks };
  };

  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    return currentNodes.map((node, index) => {
      let x = 0; let y = 0;
      switch (type) {
        case 'mesh':
          x = (Math.random() - 0.5) * 500;
          y = (Math.random() - 0.5) * 400;
          break;
        case 'star':
          if (node.category === 'root') { x = 0; y = 0; } 
          else {
            const peers = currentNodes.filter(n => n.category !== 'root');
            const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
            const r = 200;
            x = Math.cos(angle) * r;
            y = Math.sin(angle) * r;
          }
          break;
        case 'bus':
          x = (index - currentNodes.length/2) * 150;
          y = (index % 2 === 0 ? -50 : 50);
          break;
        case 'tree':
          if (node.category === 'root') y = -250;
          else if (node.category === 'core') y = 0;
          else y = 250;
          const peers = currentNodes.filter(n => n.category === node.category);
          x = (peers.indexOf(node) - peers.length / 2 + 0.5) * 180;
          break;
        case 'evolution':
          x = (index - currentNodes.length / 2) * 120;
          y = Math.sin(index * 0.5) * 100;
          break;
      }
      return { ...node, x: node.x ?? x, y: node.y ?? y }; 
    });
  }, []);

  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    // Just re-arrange current nodes
    const newNodes = applyLayout(newLayout, nodes);
    setNodes(newNodes);
    saveToHistory(newNodes, links);
  };

  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.code === 'Space')) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; 
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (e.shiftKey) {
          setInteractionState({
              type: 'creatingLink',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX, currentY: worldY
          });
      } else {
          if (!selectedNodeIds.has(clickedNode.id)) {
              if (e.ctrlKey) {
                  const newSet = new Set(selectedNodeIds);
                  newSet.add(clickedNode.id);
                  setSelectedNodeIds(newSet);
              } else {
                  setSelectedNodeIds(new Set([clickedNode.id]));
              }
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      if ((e.target as Element).tagName === 'svg' || (e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedLinkIndex(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode') {
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;
        setNodes(prev => prev.map(n => {
             if (selectedNodeIds.has(n.id) || n.id === interactionState.targetId) {
                return { ...n, x: (n.x || 0) + dx, y: (n.y || 0) + dy };
             }
             return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));
    }
    else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
    else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                const newLinks = [...links, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }];
                setLinks(newLinks);
                saveToHistory(nodes, newLinks);
            }
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 50,
          isGhost: false,
          x, y
      };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  const handleGenerate = async () => {
    // If input is empty, use preset template
    if (!input.trim()) {
        const { nodes: tNodes, links: tLinks } = generateTemplate(layout);
        // Center the template
        const arranged = applyLayout(layout, tNodes);
        setNodes(arranged);
        setLinks(tLinks);
        saveToHistory(arranged, tLinks);
        return;
    }
    // Else AI generation
    handleAnalyze();
  };

  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const cleanText = text.replace(/```json\n?|\n?```/g, '').trim();
        const data = JSON.parse(cleanText);
        setAnalysisResult({ analysis: data.analysis, predictedScore: data.predictedScore, suggestions: data.suggestions });
        let updatedNodes = [...nodes];
        if (data.updatedNodes) {
          updatedNodes = updatedNodes.map(node => {
            const update = data.updatedNodes.find((u: any) => node.id.toLowerCase().includes(u.id.toLowerCase()) || node.label.toLowerCase().includes(u.id.toLowerCase()));
            if (update) return { ...node, masteryLevel: Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange)) };
            return node;
          });
          setNodes(updatedNodes);
          saveToHistory(updatedNodes, links);
        }
      }
    } catch (e) {
      alert("AI分析失败，请检查输入或稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleSaveGraph = () => {
    if(!newGraphName) return;
    saveGraph(newGraphName, Array.from(selectedNodeIds));
    setNewGraphName('');
    setShowSaveModal(false);
  };

  const handleAddToTransfer = () => {
      const nodesToAdd = nodes.filter(n => selectedNodeIds.has(n.id));
      if (nodesToAdd.length > 0) {
          addToTransferStation(nodesToAdd);
          alert(`已将 ${nodesToAdd.length} 个节点添加到中转站`);
      }
  };

  const handleDropFromTransfer = (node: KnowledgeNode) => {
      // Add copy of node to center of screen
      const newNode = { ...node, id: `copy_${Date.now()}_${node.id}`, x: -transform.x/transform.k + window.innerWidth/2/transform.k, y: -transform.y/transform.k + window.innerHeight/2/transform.k };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
  };

  // --- Dynamic Radar ---
  useEffect(() => {
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };
    const theory = calculateAverage(n => !n.isGhost && (n.category === 'root' || n.category === 'core'));
    const logic = calculateAverage(n => !n.isGhost && (n.id.includes('ds') || n.id.includes('algo')));
    const practice = calculateAverage(n => !n.isGhost && n.category === 'sub');
    const memory = calculateAverage(n => !n.isGhost);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovation = Math.min(100, Math.round(innovationBase + (memory > 80 ? 10 : 0)));
    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);
  }, [nodes]);

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;
    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      return `${center + r * Math.cos(i * angleSlice - Math.PI / 2)},${center + r * Math.sin(i * angleSlice - Math.PI / 2)}`;
    }).join(' ');
    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];
    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full cursor-pointer" onClick={() => navigate(`/knowledge-graph/analysis/综合能力`, {state: {score: analysisResult?.predictedScore || 75}})}>
         {webLevels.map((level, idx) => (
           <polygon key={idx} points={radarData.map((_, i) => `${center + level * radius * Math.cos(i * angleSlice - Math.PI / 2)},${center + level * radius * Math.sin(i * angleSlice - Math.PI / 2)}`).join(' ')} fill="none" stroke="var(--kg-line)" strokeOpacity="0.5" strokeWidth="1" />
         ))}
         <polygon points={points} fill="var(--kg-primary)" fillOpacity="0.4" stroke="var(--kg-primary)" strokeWidth="2" />
      </svg>
    );
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => handleLayoutChange(type)} className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`} title={label}>
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
          <Link to="/" className="w-8 h-8 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide">灵境 <span className="text-kg-primary font-light">| 知识图谱</span></h1>
          <div className="hidden md:flex gap-2 text-[10px] text-gray-400 ml-4 font-mono">
              <span className="px-1 border border-gray-300 rounded">Ctrl+S 保存</span>
              <span className="px-1 border border-gray-300 rounded">Ctrl+Z 撤销</span>
              <span className="px-1 border border-gray-300 rounded">Ctrl+C 复制</span>
          </div>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm">
           <SystemStatus />
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full">
              <i className="fas fa-bars"></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area */}
      <div ref={containerRef} className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp} onDoubleClick={handleDoubleClickBg}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i || (selectedNodeIds.has(src.id) && selectedNodeIds.has(tgt.id));
                    const isGhostLink = src.isGhost || tgt.isGhost;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} strokeOpacity={isSelected ? 1 : 0.6} strokeDasharray={isGhostLink ? "5,5" : "0"} markerEnd={isGhostLink ? "" : "url(#arrowhead)"} />
                        </g>
                    );
                })}
                {interactionState.type === 'creatingLink' && (<line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />)}
                 {interactionState.type === 'boxSelecting' && (<rect x={Math.min(interactionState.startX, interactionState.currentX!)} y={Math.min(interactionState.startY, interactionState.currentY!)} width={Math.abs(interactionState.currentX! - interactionState.startX)} height={Math.abs(interactionState.currentY! - interactionState.startY)} fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2" className="pointer-events-none" />)}
                {nodes.map((node) => {
                    const isSelected = selectedId === node.id || selectedNodeIds.has(node.id);
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';
                    return (
                        <g key={node.id} transform={`translate(${node.x},${node.y})`} onDoubleClick={(e) => handleNodeDoubleClick(e, node)} className="cursor-pointer transition-all duration-300">
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}
                            <circle r={r} fill={node.isGhost ? 'transparent' : color} stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-bg)'} strokeWidth={node.isGhost ? 1 : 3} strokeDasharray={node.isGhost ? "4,2" : "0"} className={node.isGhost ? "" : "shadow-sm"} />
                            <rect x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4" fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none" />
                            <text y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)" className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}>{node.label}</text>
                            {(isSelected && !node.isGhost) && (<text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">{node.masteryLevel}%</text>)}
                            {node.isGhost && (<text y={5} textAnchor="middle" fontSize="10" fill="var(--kg-text)" fontWeight="bold" className="pointer-events-none">+</text>)}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="科技树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      <div className={`fixed top-0 right-0 h-full w-80 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"><i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i></button>

          <div className="p-6 h-full flex flex-col pt-20 overflow-y-auto">
              <h2 className="text-lg font-bold mb-4 flex justify-between items-center">
                  <span>数据控制台</span>
                  <button onClick={()=>setShowSaveModal(true)} className="text-xs text-kg-primary bg-kg-bg px-2 py-1 rounded hover:bg-kg-primary hover:text-white transition-colors"><i className="fas fa-save mr-1"></i> 保存</button>
              </h2>

              {selectedNodeIds.size > 0 && (
                  <div className="mb-6 p-4 bg-kg-bg rounded border border-kg-primary/20 animate-[fadeIn_0.2s]">
                      <h3 className="text-sm font-bold text-kg-primary mb-2">已选节点: {selectedNodeIds.size}</h3>
                      <button onClick={handleAddToTransfer} className="w-full text-xs text-purple-500 border border-purple-200 rounded py-1 hover:bg-purple-50 mb-2"><i className="fas fa-archive mr-1"></i> 复制到中转站</button>
                      <button onClick={handleDeleteSelected} className="w-full text-xs text-red-500 border border-red-200 rounded py-1 hover:bg-red-50">删除所选</button>
                      <div className="text-[10px] text-gray-400 mt-2">提示: 按住 Ctrl + 拖拽可框选。</div>
                  </div>
              )}

              {/* Transfer Station (Clipboard) */}
              <div className="mb-6 border-t border-gray-200 dark:border-gray-700 pt-4">
                  <div className="flex justify-between items-center mb-2">
                      <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 font-bold">知识中转站</div>
                      <span className="text-xs bg-gray-200 dark:bg-gray-700 px-1.5 rounded-full">{transferStation.length}</span>
                  </div>
                  <div className="bg-kg-bg rounded p-2 max-h-32 overflow-y-auto border border-gray-200 dark:border-gray-700 space-y-1">
                      {transferStation.length === 0 && <div className="text-[10px] text-gray-400 text-center py-2">空空如也</div>}
                      {transferStation.map((n: KnowledgeNode) => (
                          <div key={n.id} className="flex justify-between items-center bg-white dark:bg-gray-800 p-1.5 rounded border border-gray-100 dark:border-gray-700 group">
                              <span className="text-xs truncate flex-1 cursor-grab active:cursor-grabbing" title="点击添加副本到画布" onClick={() => handleDropFromTransfer(n)}>{n.label}</span>
                              <button onClick={() => removeFromTransferStation(n.id)} className="text-gray-300 hover:text-red-400 opacity-0 group-hover:opacity-100"><i className="fas fa-times"></i></button>
                          </div>
                      ))}
                  </div>
                  <div className="text-[10px] text-gray-400 mt-1">点击节点即可在画布中心生成副本。</div>
              </div>

              {!selectedId && selectedNodeIds.size === 0 && (
                  <div className="space-y-6">
                      <div className="bg-kg-bg p-4 rounded-xl text-center border border-gray-100 dark:border-gray-700 shadow-inner">
                          <div className="text-sm font-bold text-kg-primary mb-2">综合能力雷达</div>
                          <div className="w-32 h-32 mx-auto">{renderRadar()}</div>
                          <div className="text-xs opacity-60 mt-2">点击图表查看详情</div>
                      </div>

                      <div className="flex-grow">
                           <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">AI 辅助生成</div>
                           <textarea value={input} onChange={e=>setInput(e.target.value)} placeholder="输入主题或留空使用预设..." className="w-full bg-kg-bg p-3 rounded-lg mb-2 text-sm border border-gray-200 dark:border-gray-700 h-24 focus:border-kg-primary outline-none resize-none" />
                           <div className="flex gap-2">
                               <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-folder-open"></i></button>
                               <button onClick={() => setShowCamera(true)} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-camera"></i></button>
                               <button onClick={() => handleGenerate()} disabled={isAnalyzing} className="flex-1 bg-kg-primary text-white py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all">
                                   {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : (input.trim() ? 'AI生成图谱' : '一键生成预设')}
                               </button>
                           </div>
                      </div>
                  </div>
              )}

              {selectedId && !selectedNodeIds.has(selectedId) && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">节点编辑</span></div>
                      {nodes.find(n => n.id === selectedId) && (
                          <div className="space-y-4">
                              <div>
                                  <label className="text-xs text-kg-text opacity-60">名称</label>
                                  <input className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" value={nodes.find(n => n.id === selectedId)?.label} onChange={(e) => { const val = e.target.value; setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, label: val } : n)); }} onBlur={() => saveToHistory(nodes, links)} />
                              </div>
                              <button onClick={handleDeleteSelected} className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors w-full"><i className="fas fa-trash"></i> 删除</button>
                          </div>
                      )}
                  </div>
              )}
          </div>
      </div>

      {showSaveModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm animate-[fadeIn_0.2s]">
              <div className="bg-kg-card p-6 rounded-xl shadow-2xl w-80 border border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-bold mb-4">保存图谱快照</h3>
                  <div className="text-sm text-gray-600 dark:text-gray-400 mb-4 p-3 bg-gray-50 dark:bg-gray-800 rounded border border-gray-200 dark:border-gray-700">
                     {selectedNodeIds.size > 0 ? (
                         <span className="flex items-center gap-2 text-purple-600"><i className="fas fa-crop-alt"></i> 将保存选中的 {selectedNodeIds.size} 个节点 (局部)</span>
                     ) : (
                         <span className="flex items-center gap-2 text-green-600"><i className="fas fa-expand"></i> 将保存整个画布 (全景)</span>
                     )}
                  </div>
                  <input value={newGraphName} onChange={(e) => setNewGraphName(e.target.value)} placeholder="输入图谱名称..." className="w-full p-2 border rounded mb-4 bg-kg-bg text-kg-text outline-none focus:border-kg-primary" autoFocus />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setShowSaveModal(false)} className="px-4 py-2 text-sm text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded">取消</button>
                      <button onClick={handleSaveGraph} className="px-4 py-2 text-sm bg-kg-primary text-white rounded hover:opacity-90">保存</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { OFFICE_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

interface AnalysisResult {
  subject: string;
  predictedScore: number;
  weakPoints: string[];
  lineage: string;
  summary: string;
  recommendedTasks?: string[];
}

export const Office: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes, addCalendarBlock, calendarBlocks } = useContext(GlobalContext) as any;
  const navigate = useNavigate();
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showCamera, setShowCamera] = useState(false);
  const [activeTab, setActiveTab] = useState<'diagnosis' | 'graph' | 'plan'>('diagnosis');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const handleCameraCapture = (file: File) => {
    processFile(file);
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setImagePreview(reader.result as string);
      setResult(null); // Reset previous result
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!imagePreview || isProcessing) return;
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const base64Data = imagePreview.split(',')[1];
      const mimeType = imagePreview.split(':')[1].split(';')[0];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: "Analyze this image according to the system instructions. Return ONLY JSON." }
          ]
        },
        config: {
           systemInstruction: OFFICE_SYSTEM_INSTRUCTION,
           responseMimeType: 'application/json'
        }
      });

      if (response.text) {
          const data = JSON.parse(response.text);
          setResult(data);
          setActiveTab('diagnosis');

          // Auto-generate Calendar Blocks
          const tasks = data.recommendedTasks || [`复习 ${data.subject} 薄弱点`, `${data.subject} 错题整理`];
          tasks.forEach((task: string, idx: number) => {
             addCalendarBlock({
                 id: Date.now().toString() + idx,
                 title: task,
                 duration: 30, // default 30 mins
                 type: 'study'
             });
          });
      }
    } catch (e) {
      console.error(e);
      alert("分析失败，请重试");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    if (!result) return;

    // Create new nodes from weak points
    const newNodes: KnowledgeNode[] = result.weakPoints.map(point => ({
        id: `node_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        label: point,
        category: 'sub',
        masteryLevel: 20, // Start low for weak points
        x: Math.random() * 800 - 400,
        y: Math.random() * 600 - 300
    }));

    // Add to global state
    setNodes((prev: KnowledgeNode[]) => [...prev, ...newNodes]);

    const context = `
      学科: ${result.subject}
      预测分数: ${result.predictedScore}
      薄弱点: ${result.weakPoints.join(', ')}
      知识谱系: ${result.lineage}
      分析总结: ${result.summary}
    `;
    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  const TabButton = ({ id, label, icon }: { id: string, label: string, icon: string }) => (
      <button 
        onClick={() => setActiveTab(id as any)}
        className={`flex-1 py-3 text-sm font-medium transition-all border-b-2 flex items-center justify-center gap-2 ${activeTab === id ? 'border-office-primary text-office-primary bg-office-primary/5' : 'border-transparent text-office-sub hover:text-office-text'}`}
      >
          <i className={`fas ${icon}`}></i> {label}
      </button>
  );

  return (
    <div className="flex flex-col min-h-screen bg-office-bg font-sans text-office-text transition-colors duration-300">
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
