                            >
                                {/* Time Column */}
                                <div className="w-16 py-3 px-2 border-r border-gray-100 dark:border-gray-800 flex flex-col items-end gap-1 shrink-0">
                                    <span className="text-xs font-bold text-gray-700 dark:text-gray-300 font-mono">{timeStr}</span>
                                </div>

                                {/* Task Area (Flex Row for Compression) */}
                                <div className="flex-1 p-1 flex flex-row gap-1 relative">
                                    {blocksInSlot.length > 0 ? blocksInSlot.map((block: CalendarBlock) => (
                                        <div
                                            key={block.id}
                                            draggable
                                            onDragStart={() => handleDragStart(block)}
                                            className={`flex-1 min-w-0 p-2 rounded-lg border text-xs flex flex-col justify-center cursor-grab relative group/block overflow-hidden ${getTypeColor(block.type)}`}
                                        >
                                            <div className="font-bold truncate">{block.title}</div>
                                            <div className="text-[10px] opacity-70 flex items-center gap-1">
                                                <i className={`fas ${getTypeIcon(block.type)}`}></i> {block.duration}m
                                            </div>
                                            <button onClick={(e) => handleDeleteBlock(e, block.id)} className="absolute top-1 right-1 text-red-500 opacity-0 group-hover/block:opacity-100 transition-opacity hover:scale-110">
                                                <i className="fas fa-times"></i>
                                            </button>
                                        </div>
                                    )) : (
                                        <div className="w-full h-full flex items-center justify-center opacity-0 group-hover:opacity-20 transition-opacity">
                                            <i className="fas fa-plus text-gray-400"></i>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

