import React, { useState, useRef, useEffect, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { GoogleGenAI } from "@google/genai";
import { EDU_SYSTEM_INSTRUCTION, ThemeContext, GlobalContext } from '../constants';
import { GenerateContentResponse } from '@google/genai';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';
import { KnowledgeNode } from '../types';

type SubjectType = 'arts' | 'science' | 'lang' | 'math';

export const Education: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  const { setNodes } = useContext(GlobalContext) as any;
  const navigate = useNavigate();
  const [selectedSubject, setSelectedSubject] = useState<SubjectType | null>(null);

  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{role: 'user' | 'model', content: string}[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initial Greeting based on subject
  useEffect(() => {
    if (selectedSubject && messages.length === 0) {
        let greeting = '';
        switch(selectedSubject) {
            case 'arts': greeting = '欢迎来到文史哲研讨室。📜 我们可以聊聊历史长河、文学经典或哲学思辨。'; break;
            case 'science': greeting = '欢迎来到理工实验室。🔬 物理定律、化学反应或生物奥秘，请随意提问。'; break;
            case 'lang': greeting = 'Welcome! 这里是语言学习中心。🗣️ 无论是英语口语还是写作润色，我都可协助。'; break;
            case 'math': greeting = '欢迎来到数学思维馆。📐 让我们一起破解那些复杂的公式和逻辑谜题吧。'; break;
        }
        setMessages([{ role: 'model', content: greeting }]);
    }
  }, [selectedSubject]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsProcessing(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      // Inject subject context into system instruction
      let contextInstruction = EDU_SYSTEM_INSTRUCTION;
      if (selectedSubject === 'arts') contextInstruction += " You are an expert in Humanities, History, and Literature.";
      if (selectedSubject === 'science') contextInstruction += " You are an expert in Physics, Chemistry, and Biology.";
      if (selectedSubject === 'lang') contextInstruction += " You are an expert Language Tutor.";
      if (selectedSubject === 'math') contextInstruction += " You are an expert Math Tutor. Use LaTeX for formulas.";

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: contextInstruction },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.content }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      let fullText = '';
      setMessages(prev => [...prev, { role: 'model', content: '' }]);

      for await (const chunk of result) {
        const text = (chunk as GenerateContentResponse).text || '';
        fullText += text;
        setMessages(prev => {
          const newArr = [...prev];
          newArr[newArr.length - 1].content = fullText;
          return newArr;
        });
      }
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', content: '哎呀，大脑短路了，重试一下吧！' }]);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSyncToKG = () => {
    // Collect context for auto generation
    const context = messages.slice(-5).map(m => m.content).join('\n');
    navigate('/knowledge-graph', { state: { autoAnalyzeText: context } });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const msg = `[系统] 已上传资料: ${file.name}`;
      setInput(prev => prev ? `${prev}\n${msg}` : msg);
    }
  };

  const handleCameraCapture = (file: File) => {
    const msg = `[系统] 已拍摄作业: ${file.name}`;
    setInput(prev => prev ? `${prev}\n${msg}` : msg);
  };

  // Subject Card Component
  const SubjectCard = ({ id, title, icon, color, desc }: any) => (
      <button 
        onClick={() => setSelectedSubject(id)}
        className={`group relative p-6 rounded-2xl border bg-white dark:bg-gray-800 hover:scale-105 transition-all duration-300 shadow-sm hover:shadow-lg text-left overflow-hidden ${color}`}
      >
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity transform group-hover:rotate-12 scale-150">
              <i className={`fas ${icon} text-6xl`}></i>
          </div>
          <div className="relative z-10">
              <div className="w-12 h-12 rounded-xl mb-4 flex items-center justify-center text-2xl bg-white/50 backdrop-blur shadow-sm">
                  <i className={`fas ${icon}`}></i>
              </div>
              <h3 className="text-xl font-bold mb-1">{title}</h3>
              <p className="text-xs opacity-70">{desc}</p>
          </div>
      </button>
  );

  return (
    <div className="flex flex-col h-screen bg-edu-bg font-sans text-edu-text transition-colors duration-300">
      {/* Hardware Camera Modal */}
      {showCamera && <CameraModal onCapture={handleCameraCapture} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

      {/* Unified Header */}
      <div className="bg-edu-card/80 backdrop-blur px-6 py-4 flex justify-between items-center shadow-sm sticky top-0 z-20 border-b border-edu-border transition-colors">
        <div className="flex items-center gap-4 min-w-0">
          <button onClick={() => selectedSubject ? setSelectedSubject(null) : navigate('/')} className="w-8 h-8 flex-shrink-0 flex items-center justify-center text-edu-sub hover:text-edu-primary transition-colors rounded-full hover:bg-edu-bg">
            <i className={`fas fa-${selectedSubject ? 'chevron-left' : 'arrow-left'}`}></i>
          </button>
          <h1 className="text-lg font-bold text-edu-text truncate">灵境 · 互动导学 {selectedSubject && <span className="opacity-50 text-sm ml-2 hidden sm:inline">/ {selectedSubject.toUpperCase()}</span>}</h1>
        </div>
        <div className="flex items-center gap-3 flex-shrink-0">
           <SystemStatus />
           {selectedSubject && (
               <button 
                 onClick={handleSyncToKG}
                 className="text-edu-sub hover:text-edu-primary px-3 py-1 text-sm border border-transparent hover:border-edu-border rounded transition-all"
                 title="分析并存入知识图谱"
               >
                 <i className="fas fa-project-diagram mr-1"></i> 存入图谱
               </button>
           )}
           <button onClick={toggleTheme} className="text-edu-sub hover:text-edu-primary transition-colors">
            <i className={`fas ${theme === 'light' ? 'fa-sun' : 'fa-moon'}`}></i>
          </button>
          <UserAuth themeColorClass="text-edu-sub" />
        </div>
      </div>

      <div className="flex-1 flex flex-col max-w-5xl w-full mx-auto p-4 overflow-hidden relative">

        {/* LANDING VIEW: Subject Selection */}
        {!selectedSubject && (
             <div className="flex-1 flex flex-col justify-center animate-[fadeInUp_0.5s_ease-out]">
                 <div className="text-center mb-10">
                     <h2 className="text-3xl font-bold mb-3">选择你的专项导师</h2>
                     <p className="text-edu-sub">全科覆盖，精准辅导，开启沉浸式学习体验</p>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 px-4">
                     <SubjectCard 
                        id="arts" title="文史哲" icon="fa-scroll" desc="历史、文学、哲学、社科"
                        color="border-rose-200 text-rose-800 dark:border-rose-800 dark:text-rose-200"
                     />
                     <SubjectCard 
                        id="science" title="理工科" icon="fa-atom" desc="物理、化学、生物、地理"
                        color="border-blue-200 text-blue-800 dark:border-blue-800 dark:text-blue-200"
                     />
                     <SubjectCard 
                        id="lang" title="语言类" icon="fa-language" desc="英语、小语种、写作润色"
                        color="border-emerald-200 text-emerald-800 dark:border-emerald-800 dark:text-emerald-200"
                     />
                     <SubjectCard 
                        id="math" title="数学类" icon="fa-square-root-alt" desc="代数、几何、逻辑、统计"
                        color="border-amber-200 text-amber-800 dark:border-amber-800 dark:text-amber-200"
                     />
                 </div>
             </div>
        )}

        {/* CHAT VIEW */}
        {selectedSubject && (
            <>
                <div ref={scrollRef} className="flex-1 overflow-y-auto mb-4 space-y-6 pr-2 z-10 animate-[fadeIn_0.3s]">
                  {messages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start items-end gap-2'}`}>
                      {msg.role === 'model' && (
                        <div className="w-8 h-8 rounded-full bg-edu-card border border-edu-accent flex items-center justify-center text-edu-primary shadow-sm mb-1 shrink-0">
                          <i className="fas fa-robot"></i>
                        </div>
                      )}
                      <div className={`max-w-[80%] p-5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                        msg.role === 'user' 
                          ? 'bg-edu-primary text-white rounded-br-none shadow-orange-200' 
                          : 'bg-edu-card text-edu-text border border-edu-accent rounded-bl-none'
                      }`}>
                        {msg.role === 'model' && !msg.content ? <span className="typing-cursor"></span> : <div className="whitespace-pre-wrap">{msg.content}</div>}
                      </div>
                    </div>
                  ))}
                </div>

                {/* Input Bar */}
                <div className="bg-edu-card p-2 rounded-full shadow-lg border border-edu-accent z-10 flex items-center gap-2 pl-4 transition-colors">
                  <button 
                     onClick={() => fileInputRef.current?.click()}
                     className="text-edu-sub hover:text-edu-primary transition-colors"
                     title="上传文件"
                  >
                     <i className="fas fa-folder-open"></i>
                  </button>
                  <button 
                     onClick={() => setShowCamera(true)}
                     className="text-edu-sub hover:text-edu-primary transition-colors"
                     title="拍照解题"
                  >
                    <i className="fas fa-camera"></i>
                  </button>
                  <input 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="有问题尽管问我..."
                    className="flex-1 bg-transparent border-none outline-none text-sm p-2 text-edu-text placeholder-edu-sub/50"
                    disabled={isProcessing}
                  />
                  <button 
                    onClick={handleSend}
                    disabled={!input.trim() || isProcessing}
                    className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
                      input.trim() ? 'bg-edu-primary text-white rotate-0' : 'bg-edu-bg text-edu-sub -rotate-90'
                    }`}
                  >
                    <i className="fas fa-paper-plane"></i>
                  </button>
                </div>
            </>
        )}
      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  // Consume Global State
  const { 
      nodes, setNodes, links, setLinks, 
      savedGraphs, saveGraph, loadGraph, deleteGraph,
      transferStation, addToTransferStation, removeFromTransferStation 
  } = useContext(GlobalContext) as any;

  const navigate = useNavigate();
  const location = useLocation();

  // Local Visualization State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // History Stack for Undo/Redo
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false); 
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number; 
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const spacePressed = useRef(false);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  // Initial History Save & View Restore & Sync Logic
  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }

      // Load View State
      const savedTransform = localStorage.getItem('kg_transform');
      if (savedTransform) {
          try {
              const t = JSON.parse(savedTransform);
              setTransform(t);
          } catch(e) {}
      } else {
           setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
      }

      // Handle Imported Nodes (from Office sync)
      if (location.state?.importedNodes) {
          const imported = location.state.importedNodes as KnowledgeNode[];
          if (imported.length > 0) {
              const cx = (window.innerWidth / 2 - transform.x) / transform.k;
              const cy = (window.innerHeight / 2 - transform.y) / transform.k;

              const positionedNodes = imported.map(n => ({
                  ...n,
                  x: cx + (Math.random() - 0.5) * 200,
                  y: cy + (Math.random() - 0.5) * 200
              }));

              setNodes((prev: KnowledgeNode[]) => [...prev, ...positionedNodes]);
              saveToHistory([...nodes, ...positionedNodes], links);
              // Clear state to avoid re-adding on refresh (if React Router allows modification, otherwise handled by effect dependency)
              window.history.replaceState({}, document.title);
          }
      }

      // Handle Auto Analyze (from Edu or Office sync)
      if (location.state?.autoAnalyzeText) {
          handleAnalyze(location.state.autoAnalyzeText);
          window.history.replaceState({}, document.title);
      }

  }, []); 

  // Save View State on Change
  useEffect(() => {
      localStorage.setItem('kg_transform', JSON.stringify(transform));
  }, [transform]);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      } else if (selectedId) {
          const newNodes = nodes.filter(n => n.id !== selectedId);
          const newLinks = links.filter(l => l.source !== selectedId && l.target !== selectedId);
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedId(null);
      } else if (selectedLinkIndex !== null) {
          const newLinks = links.filter((_, i) => i !== selectedLinkIndex);
          setLinks(newLinks);
          saveToHistory(nodes, newLinks);
          setSelectedLinkIndex(null);
      }
  }, [selectedId, selectedLinkIndex, selectedNodeIds, nodes, links, saveToHistory]);

  const handleCopy = useCallback(() => {
      const nodesToCopy = nodes.filter(n => selectedNodeIds.has(n.id) || n.id === selectedId);
      if (nodesToCopy.length > 0) {
          addToTransferStation(nodesToCopy);
          // Optional: Tiny toast notification
      }
  }, [nodes, selectedNodeIds, selectedId, addToTransferStation]);

  const handlePaste = useCallback(() => {
      if (transferStation.length > 0) {
         // Paste at center of screen
         const cx = (window.innerWidth / 2 - transform.x) / transform.k;
         const cy = (window.innerHeight / 2 - transform.y) / transform.k;

         const newNodes = [...nodes];
         transferStation.forEach((n: KnowledgeNode, idx: number) => {
             newNodes.push({
                 ...n,
                 id: `paste_${Date.now()}_${idx}`,
                 x: cx + (Math.random() - 0.5) * 50,
                 y: cy + (Math.random() - 0.5) * 50
             });
         });
         setNodes(newNodes);
         saveToHistory(newNodes, links);
      }
  }, [transferStation, transform, nodes, links, saveToHistory]);

  // KEYBOARD SHORTCUTS LISTENER
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        // Ignore if input focused
        if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

        if (e.code === 'Space') {
             spacePressed.current = true;
        }

        // Save: Ctrl + S
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            setShowSaveModal(true);
        }

        // Undo: Ctrl + Z
        if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            handleUndo();
        }

        // Redo: Ctrl + Y or Ctrl + Shift + Z
        if (((e.ctrlKey || e.metaKey) && e.key === 'y') || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'z')) {
            e.preventDefault();
            handleRedo();
        }

        // Delete: Del or Backspace
        if (e.key === 'Delete' || e.key === 'Backspace') {
            e.preventDefault();
            handleDeleteSelected();
        }

        // Copy: Ctrl + C
        if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
            e.preventDefault();
            handleCopy();
        }

        // Paste: Ctrl + V
        if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
             e.preventDefault();
             handlePaste();
        }

        // Arrow Keys Nudge
        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
            e.preventDefault();
            const step = e.shiftKey ? 10 : 2;
            const dx = e.key === 'ArrowLeft' ? -step : e.key === 'ArrowRight' ? step : 0;
            const dy = e.key === 'ArrowUp' ? -step : e.key === 'ArrowDown' ? step : 0;

            if (selectedNodeIds.size > 0 || selectedId) {
                setNodes((prev: KnowledgeNode[]) => prev.map(n => {
                    if (selectedNodeIds.has(n.id) || n.id === selectedId) {
                        return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
                    }
                    return n;
                }));
            }
        }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
        if (e.code === 'Space') {
             spacePressed.current = false;
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
    };
  }, [handleUndo, handleRedo, handleDeleteSelected, handleCopy, handlePaste, selectedNodeIds, selectedId]);


  // --- Templates & Layouts ---
  const generateTemplate = (type: LayoutType, centerX: number, centerY: number): { nodes: KnowledgeNode[], links: KnowledgeLink[] } => {
      let tNodes: KnowledgeNode[] = [];
      let tLinks: KnowledgeLink[] = [];
      const timestamp = Date.now();

      const createNode = (suffix: string, lbl: string, cat: string, level=0, offsetX=0, offsetY=0): KnowledgeNode => ({
          id: `node_${type}_${suffix}_${timestamp}`,
          label: lbl,
          category: cat,
          masteryLevel: 50,
          isGhost: false,
          x: centerX + offsetX, 
          y: centerY + offsetY
      });

      if (type === 'tree') {
          const root = createNode('root', '核心主题', 'root', 0, 0, -100);
          const b1 = createNode('b1', '分支一', 'core', 0, -100, 50);
          const b2 = createNode('b2', '分支二', 'core', 0, 100, 50);
          const s1 = createNode('s1', '细节A', 'sub', 0, -150, 150);
          const s2 = createNode('s2', '细节B', 'sub', 0, 150, 150);
          tNodes = [root, b1, b2, s1, s2];
          tLinks = [
              {source: root.id, target: b1.id, strength: 1},
              {source: root.id, target: b2.id, strength: 1},
              {source: b1.id, target: s1.id, strength: 1},
              {source: b2.id, target: s2.id, strength: 1},
          ];
      } else if (type === 'star') {
          const center = createNode('center', '中心', 'root');
          tNodes.push(center);
          for(let i=1; i<=5; i++) {
              const angle = (i / 5) * Math.PI * 2;
              const r = 150;
              const sat = createNode(`sat${i}`, `维度${i}`, 'core', 0, Math.cos(angle)*r, Math.sin(angle)*r);
              tNodes.push(sat);
              tLinks.push({source: center.id, target: sat.id, strength: 1});
          }
      } else if (type === 'bus') {
          for(let i=0; i<5; i++) {
              tNodes.push(createNode(`bus${i}`, `节点${i+1}`, 'core', 0, (i-2)*150, (i%2 === 0 ? -50 : 50)));
              if(i>0) tLinks.push({source: tNodes[i-1].id, target: tNodes[i].id, strength: 1});
          }
      } else if (type === 'mesh') {
           for(let i=0; i<6; i++) {
               tNodes.push(createNode(`mesh${i}`, `概念${i+1}`, 'core', 0, (Math.random()-0.5)*300, (Math.random()-0.5)*300));
           }
           // Mesh links ...
           if(tNodes.length > 2) {
               tLinks.push({source: tNodes[0].id, target: tNodes[1].id, strength: 1});
               tLinks.push({source: tNodes[1].id, target: tNodes[2].id, strength: 1});
               tLinks.push({source: tNodes[0].id, target: tNodes[2].id, strength: 1});
           }
      } else {
          tNodes.push(createNode('main', '新主题', 'root'));
      }
      return { nodes: tNodes, links: tLinks };
  };

  const applyLayout = useCallback((type: LayoutType, currentNodes: KnowledgeNode[]) => {
    // Re-layout logic (existing logic keeps centering at 0,0, but we want to preserve relative structure or center view)
    // For now, let's keep the existing layout logic but maybe just nudge nodes to center?
    // Actually, just returning existing positions if they exist is safer to avoid jumps.
    // The previous implementation reset positions to 0,0 based logic.
    return currentNodes.map((node, index) => {
      // If node already has position, keep it (unless forced re-layout, which we might want to avoid for now to keep things simple)
      if (node.x !== undefined && node.y !== undefined) return node;

      let x = 0; let y = 0;
      // ... (Rest of layout logic same as before, essentially centered at 0,0 world coords)
      // This is fine for initial load or full reset.
      switch (type) {
        case 'star':
            if (node.category === 'root') { x = 0; y = 0; } 
            else {
                const peers = currentNodes.filter(n => n.category !== 'root');
                const angle = (peers.indexOf(node) / peers.length) * Math.PI * 2;
                x = Math.cos(angle) * 200;
                y = Math.sin(angle) * 200;
            }
            break;
        default:
            x = (Math.random() - 0.5) * 500;
            y = (Math.random() - 0.5) * 400;
      }
      return { ...node, x, y }; 
    });
  }, []);

  const handleLayoutChange = (newLayout: LayoutType) => {
    setLayout(newLayout);
    // Here we might want to forcefully re-arrange nodes based on layout. 
    // For the scope of this fix, we focus on generation.
  };

  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && spacePressed.current) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; 
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      if (e.shiftKey) {
          setInteractionState({
              type: 'creatingLink',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX, currentY: worldY
          });
      } else {
          if (!selectedNodeIds.has(clickedNode.id)) {
              if (e.ctrlKey) {
                  const newSet = new Set(selectedNodeIds);
                  newSet.add(clickedNode.id);
                  setSelectedNodeIds(newSet);
              } else {
                  setSelectedNodeIds(new Set([clickedNode.id]));
              }
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      if ((e.target as Element).tagName === 'svg' || (e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedLinkIndex(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode') {
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;
        setNodes(prev => prev.map(n => {
             if (selectedNodeIds.has(n.id) || n.id === interactionState.targetId) {
                return { ...n, x: (n.x || 0) + dx, y: (n.y || 0) + dy };
             }
             return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));
    }
    else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
    else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                const newLinks = [...links, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }];
                setLinks(newLinks);
                saveToHistory(nodes, newLinks);
            }
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 50,
          isGhost: false,
          x, y
      };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  const handleGenerate = async () => {
    // Calculate current screen center in world coordinates
    const cx = (window.innerWidth / 2 - transform.x) / transform.k;
    const cy = (window.innerHeight / 2 - transform.y) / transform.k;

    // If input is empty, use preset template at center
    if (!input.trim()) {
        const { nodes: tNodes, links: tLinks } = generateTemplate(layout, cx, cy);

        setNodes((prev: KnowledgeNode[]) => [...prev, ...tNodes]);
        setLinks((prev: KnowledgeLink[]) => [...prev, ...tLinks]);
        saveToHistory([...nodes, ...tNodes], [...links, ...tLinks]);
        return;
    }
    // Else AI generation
    handleAnalyze();
  };

  const handleAnalyze = async (manualInput?: string) => {
    const textToAnalyze = manualInput || input;
    if (!textToAnalyze.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setIsPanelOpen(true);

    try {
      const apiKey = process.env.API_KEY || '';
      const ai = new GoogleGenAI({ apiKey });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToAnalyze,
        config: {
          systemInstruction: KG_SYSTEM_INSTRUCTION,
          responseMimeType: "application/json"
        }
      });

      const text = response.text;
      if (text) {
        const cleanText = text.replace(/```json\n?|\n?```/g, '').trim();
        const data = JSON.parse(cleanText);
        setAnalysisResult({ analysis: data.analysis, predictedScore: data.predictedScore, suggestions: data.suggestions });

        let updatedNodes = [...nodes];

        // If data contains explicit updates for existing nodes
        if (data.updatedNodes && data.updatedNodes.length > 0) {
          updatedNodes = updatedNodes.map(node => {
            const update = data.updatedNodes.find((u: any) => node.id.toLowerCase().includes(u.id.toLowerCase()) || node.label.toLowerCase().includes(u.id.toLowerCase()));
            if (update) return { ...node, masteryLevel: Math.max(0, Math.min(100, node.masteryLevel + update.masteryChange)) };
            return node;
          });
        } 

        // AUTO GENERATE NEW NODES if mapping not found but analysis is strong, or generally for new content
        // For simplicity, if manualInput was passed (sync), we assume we want new nodes if they don't exist
        if (manualInput && (!data.updatedNodes || data.updatedNodes.length === 0)) {
             // Create a central node for the topic + subnodes for suggestions/keywords
             const cx = (window.innerWidth / 2 - transform.x) / transform.k;
             const cy = (window.innerHeight / 2 - transform.y) / transform.k;
             const mainNode: KnowledgeNode = {
                 id: `auto_${Date.now()}`,
                 label: "AI分析结果",
                 category: "core",
                 masteryLevel: data.predictedScore || 50,
                 x: cx, y: cy,
                 isGhost: false
             };
             updatedNodes.push(mainNode);

             // Create sub nodes from suggestions or weak points if available in context
             if (data.suggestions) {
                 data.suggestions.forEach((s: string, i: number) => {
                     updatedNodes.push({
                         id: `sugg_${Date.now()}_${i}`,
                         label: s.substring(0, 10),
                         category: "sub",
                         masteryLevel: 30,
                         x: cx + (Math.random()-0.5)*200,
                         y: cy + 100 + (Math.random()-0.5)*100,
                         isGhost: false
                     });
                 });
             }
        }

        setNodes(updatedNodes);
        saveToHistory(updatedNodes, links);
      }
    } catch (e) {
      alert("AI分析失败，请检查输入或稍后重试。");
    } finally {
      setIsAnalyzing(false);
      setInput('');
    }
  };

  const handleSaveGraph = () => {
    if(!newGraphName) return;
    saveGraph(newGraphName, Array.from(selectedNodeIds));
    setNewGraphName('');
    setShowSaveModal(false);
  };

  const handleAddToTransfer = () => {
      const nodesToAdd = nodes.filter(n => selectedNodeIds.has(n.id));
      if (nodesToAdd.length > 0) {
          addToTransferStation(nodesToAdd);
          alert(`已将 ${nodesToAdd.length} 个节点添加到中转站`);
      }
  };

  const handleDropFromTransfer = (node: KnowledgeNode) => {
      // Add copy of node to center of screen
      const cx = (window.innerWidth / 2 - transform.x) / transform.k;
      const cy = (window.innerHeight / 2 - transform.y) / transform.k;
      const newNode = { ...node, id: `copy_${Date.now()}_${node.id}`, x: cx, y: cy };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
  };

  // --- Dynamic Radar ---
  useEffect(() => {
    const calculateAverage = (filterFn: (n: KnowledgeNode) => boolean) => {
      const filtered = nodes.filter(filterFn);
      if (filtered.length === 0) return 0;
      return Math.round(filtered.reduce((acc, n) => acc + n.masteryLevel, 0) / filtered.length);
    };
    const theory = calculateAverage(n => !n.isGhost && (n.category === 'root' || n.category === 'core'));
    const logic = calculateAverage(n => !n.isGhost && (n.id.includes('ds') || n.id.includes('algo')));
    const practice = calculateAverage(n => !n.isGhost && n.category === 'sub');
    const memory = calculateAverage(n => !n.isGhost);
    const innovationBase = (logic * 0.6 + practice * 0.4);
    const innovation = Math.min(100, Math.round(innovationBase + (memory > 80 ? 10 : 0)));
    setRadarData([
      { subject: "理论基础", A: theory, fullMark: 100 },
      { subject: "实践应用", A: practice, fullMark: 100 },
      { subject: "逻辑思维", A: logic, fullMark: 100 },
      { subject: "记忆储备", A: memory, fullMark: 100 },
      { subject: "创新能力", A: innovation, fullMark: 100 },
    ]);
  }, [nodes]);

  const renderRadar = () => {
    const size = 180;
    const center = size / 2;
    const radius = 70;
    const angleSlice = (Math.PI * 2) / 5;
    const points = radarData.map((d, i) => {
      const r = (d.A / 100) * radius;
      return `${center + r * Math.cos(i * angleSlice - Math.PI / 2)},${center + r * Math.sin(i * angleSlice - Math.PI / 2)}`;
    }).join(' ');
    const webLevels = [0.2, 0.4, 0.6, 0.8, 1];
    return (
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="w-full h-full cursor-pointer" onClick={() => navigate(`/knowledge-graph/analysis/综合能力`, {state: {score: analysisResult?.predictedScore || 75}})}>
         {webLevels.map((level, idx) => (
           <polygon key={idx} points={radarData.map((_, i) => `${center + level * radius * Math.cos(i * angleSlice - Math.PI / 2)},${center + level * radius * Math.sin(i * angleSlice - Math.PI / 2)}`).join(' ')} fill="none" stroke="var(--kg-line)" strokeOpacity="0.5" strokeWidth="1" />
         ))}
         <polygon points={points} fill="var(--kg-primary)" fillOpacity="0.4" stroke="var(--kg-primary)" strokeWidth="2" />
      </svg>
    );
  };

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => handleLayoutChange(type)} className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`} title={label}>
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm min-w-0">
          <Link to="/" className="w-8 h-8 flex-shrink-0 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide truncate">灵境 <span className="text-kg-primary font-light hidden sm:inline">| 知识图谱</span></h1>
          <div className="hidden md:flex gap-2 text-[10px] text-gray-400 ml-4 font-mono">
              <span className="px-1 border border-gray-300 rounded">Ctrl+S 保存</span>
              <span className="px-1 border border-gray-300 rounded">Ctrl+Z 撤销</span>
              <span className="px-1 border border-gray-300 rounded">Ctrl+C 复制</span>
          </div>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm flex-shrink-0">
           <SystemStatus />
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full">
              <i className="fas fa-bars"></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area */}
      <div ref={containerRef} className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp} onDoubleClick={handleDoubleClickBg}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i || (selectedNodeIds.has(src.id) && selectedNodeIds.has(tgt.id));
                    const isGhostLink = src.isGhost || tgt.isGhost;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} strokeOpacity={isSelected ? 1 : 0.6} strokeDasharray={isGhostLink ? "5,5" : "0"} markerEnd={isGhostLink ? "" : "url(#arrowhead)"} />
                        </g>
                    );
                })}
                {interactionState.type === 'creatingLink' && (<line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />)}
                 {interactionState.type === 'boxSelecting' && (<rect x={Math.min(interactionState.startX, interactionState.currentX!)} y={Math.min(interactionState.startY, interactionState.currentY!)} width={Math.abs(interactionState.currentX! - interactionState.startX)} height={Math.abs(interactionState.currentY! - interactionState.startY)} fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2" className="pointer-events-none" />)}
                {nodes.map((node) => {
                    const isSelected = selectedId === node.id || selectedNodeIds.has(node.id);
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';
                    return (
                        <g key={node.id} transform={`translate(${node.x},${node.y})`} onDoubleClick={(e) => handleNodeDoubleClick(e, node)} className="cursor-pointer transition-all duration-300">
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}
                            <circle r={r} fill={node.isGhost ? 'transparent' : color} stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-bg)'} strokeWidth={node.isGhost ? 1 : 3} strokeDasharray={node.isGhost ? "4,2" : "0"} className={node.isGhost ? "" : "shadow-sm"} />
                            <rect x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4" fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none" />
                            <text y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)" className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}>{node.label}</text>
                            {(isSelected && !node.isGhost) && (<text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">{node.masteryLevel}%</text>)}
                            {node.isGhost && (<text y={5} textAnchor="middle" fontSize="10" fill="var(--kg-text)" fontWeight="bold" className="pointer-events-none">+</text>)}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      <div className="absolute bottom-6 left-6 z-20 flex gap-2 bg-kg-card/90 backdrop-blur-md p-2 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-lg pointer-events-auto">
        <LayoutButton type="mesh" icon="fa-th-large" label="网状" />
        <LayoutButton type="star" icon="fa-atom" label="星形" />
        <LayoutButton type="bus" icon="fa-grip-lines" label="总线" />
        <LayoutButton type="tree" icon="fa-network-wired" label="科技树" />
        <LayoutButton type="evolution" icon="fa-wave-square" label="演化" />
      </div>

      <div className={`fixed top-0 right-0 h-full w-80 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"><i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i></button>

          <div className="p-6 h-full flex flex-col pt-20 overflow-y-auto">
              <h2 className="text-lg font-bold mb-4 flex justify-between items-center">
                  <span>数据控制台</span>
                  <button onClick={()=>setShowSaveModal(true)} className="text-xs text-kg-primary bg-kg-bg px-2 py-1 rounded hover:bg-kg-primary hover:text-white transition-colors"><i className="fas fa-save mr-1"></i> 保存</button>
              </h2>

              {selectedNodeIds.size > 0 && (
                  <div className="mb-6 p-4 bg-kg-bg rounded border border-kg-primary/20 animate-[fadeIn_0.2s]">
                      <h3 className="text-sm font-bold text-kg-primary mb-2">已选节点: {selectedNodeIds.size}</h3>
                      <button onClick={handleAddToTransfer} className="w-full text-xs text-purple-500 border border-purple-200 rounded py-1 hover:bg-purple-50 mb-2"><i className="fas fa-archive mr-1"></i> 复制到中转站</button>
                      <button onClick={handleDeleteSelected} className="w-full text-xs text-red-500 border border-red-200 rounded py-1 hover:bg-red-50">删除所选</button>
                      <div className="text-[10px] text-gray-400 mt-2">提示: 按住 Ctrl + 拖拽可框选。</div>
                  </div>
              )}

              {/* Transfer Station (Clipboard) */}
              <div className="mb-6 border-t border-gray-200 dark:border-gray-700 pt-4">
                  <div className="flex justify-between items-center mb-2">
                      <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 font-bold">知识中转站</div>
                      <span className="text-xs bg-gray-200 dark:bg-gray-700 px-1.5 rounded-full">{transferStation.length}</span>
                  </div>
                  <div className="bg-kg-bg rounded p-2 max-h-32 overflow-y-auto border border-gray-200 dark:border-gray-700 space-y-1">
                      {transferStation.length === 0 && <div className="text-[10px] text-gray-400 text-center py-2">空空如也</div>}
                      {transferStation.map((n: KnowledgeNode) => (
                          <div key={n.id} className="flex justify-between items-center bg-white dark:bg-gray-800 p-1.5 rounded border border-gray-100 dark:border-gray-700 group">
                              <span className="text-xs truncate flex-1 cursor-grab active:cursor-grabbing" title="点击添加副本到画布" onClick={() => handleDropFromTransfer(n)}>{n.label}</span>
                              <button onClick={() => removeFromTransferStation(n.id)} className="text-gray-300 hover:text-red-400 opacity-0 group-hover:opacity-100"><i className="fas fa-times"></i></button>
                          </div>
                      ))}
                  </div>
                  <div className="text-[10px] text-gray-400 mt-1">点击节点即可在画布中心生成副本。</div>
              </div>

              {!selectedId && selectedNodeIds.size === 0 && (
                  <div className="space-y-6">
                      <div className="bg-kg-bg p-4 rounded-xl text-center border border-gray-100 dark:border-gray-700 shadow-inner">
                          <div className="text-sm font-bold text-kg-primary mb-2">综合能力雷达</div>
                          <div className="w-32 h-32 mx-auto">{renderRadar()}</div>
                          <div className="text-xs opacity-60 mt-2">点击图表查看详情</div>
                      </div>

                      <div className="flex-grow">
                           <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">AI 辅助生成</div>
                           <textarea value={input} onChange={e=>setInput(e.target.value)} placeholder="输入主题或留空使用预设..." className="w-full bg-kg-bg p-3 rounded-lg mb-2 text-sm border border-gray-200 dark:border-gray-700 h-24 focus:border-kg-primary outline-none resize-none" />
                           <div className="flex gap-2">
                               <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-folder-open"></i></button>
                               <button onClick={() => setShowCamera(true)} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-camera"></i></button>
                               <button onClick={() => handleGenerate()} disabled={isAnalyzing} className="flex-1 bg-kg-primary text-white py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all">
                                   {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : (input.trim() ? 'AI生成图谱' : '一键生成预设')}
                               </button>
                           </div>
                      </div>
                  </div>
              )}

              {selectedId && !selectedNodeIds.has(selectedId) && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">节点编辑</span></div>
                      {nodes.find(n => n.id === selectedId) && (
                          <div className="space-y-4">
                              <div>
                                  <label className="text-xs text-kg-text opacity-60">名称</label>
                                  <input className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" value={nodes.find(n => n.id === selectedId)?.label} onChange={(e) => { const val = e.target.value; setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, label: val } : n)); }} onBlur={() => saveToHistory(nodes, links)} />
                              </div>
                              <button onClick={handleDeleteSelected} className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors w-full"><i className="fas fa-trash"></i> 删除</button>
                          </div>
                      )}
                  </div>
              )}
          </div>
      </div>

      {showSaveModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm animate-[fadeIn_0.2s]">
              <div className="bg-kg-card p-6 rounded-xl shadow-2xl w-80 border border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-bold mb-4">保存图谱快照</h3>
                  <div className="text-sm text-gray-600 dark:text-gray-400 mb-4 p-3 bg-gray-50 dark:bg-gray-800 rounded border border-gray-200 dark:border-gray-700">
                     {selectedNodeIds.size > 0 ? (
                         <span className="flex items-center gap-2 text-purple-600"><i className="fas fa-crop-alt"></i> 将保存选中的 {selectedNodeIds.size} 个节点 (局部)</span>
                     ) : (
                         <span className="flex items-center gap-2 text-green-600"><i className="fas fa-expand"></i> 将保存整个画布 (全景)</span>
                     )}
                  </div>
                  <input value={newGraphName} onChange={(e) => setNewGraphName(e.target.value)} placeholder="输入图谱名称..." className="w-full p-2 border rounded mb-4 bg-kg-bg text-kg-text outline-none focus:border-kg-primary" autoFocus />
                  <div className="flex justify-end gap-2">
                      <button onClick={() => setShowSaveModal(false)} className="px-4 py-2 text-sm text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded">取消</button>
                      <button onClick={handleSaveGraph} className="px-4 py-2 text-sm bg-kg-primary text-white rounded hover:opacity-90">保存</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';

export enum EngineType {
  FROST_BLADE = 'frost_blade', // Fast -> gemini-3-flash-preview
  ETERNAL_CORE = 'eternal_core', // Deep -> gemini-3-pro-preview
  LAND_VESSEL = 'land_vessel', // Custom Mod Loader
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  engine?: EngineType;
  senderName?: string; 
}

export type ThemeMode = 'light' | 'dark' | 'system';

export interface User {
  username: string;
  avatar?: string;
  isLoggedIn: boolean;
  role: 'guest' | 'user' | 'admin';
}

export interface ThemeContextType {
  theme: ThemeMode;
  toggleTheme: () => void;
}

export interface UserContextType {
  user: User;
  login: (username: string) => void;
  logout: () => void;
}

// --- Global Context Types ---
export interface GlobalContextType {
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
  setNodes: React.Dispatch<React.SetStateAction<KnowledgeNode[]>>;
  setLinks: React.Dispatch<React.SetStateAction<KnowledgeLink[]>>;

  // Knowledge Transfer Station (Clipboard)
  transferStation: KnowledgeNode[];
  addToTransferStation: (nodes: KnowledgeNode[]) => void;
  removeFromTransferStation: (nodeId: string) => void;

  // Persistence
  savedGraphs: SavedGraph[];
  saveGraph: (name: string, selectedNodeIds?: string[]) => void;
  loadGraph: (id: string) => void;
  deleteGraph: (id: string) => void;

  // Calendar & Weather System
  isCalendarOpen: boolean;
  setIsCalendarOpen: React.Dispatch<React.SetStateAction<boolean>>;
  calendarBlocks: CalendarBlock[];
  setCalendarBlocks: React.Dispatch<React.SetStateAction<CalendarBlock[]>>;
  addCalendarBlock: (block: CalendarBlock) => void;
  updateCalendarBlock: (id: string, updates: Partial<CalendarBlock>) => void;
  weather: WeatherState;
  setWeather: React.Dispatch<React.SetStateAction<WeatherState>>;
  mood: string;
  setMood: React.Dispatch<React.SetStateAction<string>>;
}

export interface SavedGraph {
  id: string;
  name: string;
  date: number;
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
}

export interface WeatherState {
  type: 'sunny' | 'cloudy' | 'rainy' | 'storm' | 'snow' | 'foggy';
  temp: number;
  icon: string;
}

export interface CalendarBlock {
  id: string;
  title: string;
  duration: number; // in minutes
  type: 'study' | 'exam' | 'rest' | 'other' | 'weather' | 'mood';
  assignedTime?: string; // HH:mm format, if null it's in the magnetic pool
  isCompleted?: boolean;
  color?: string; // Custom color override
  notes?: string; // Remarks
}

export interface MBTIPersona {
  id: string;
  type: string; // e.g., INTJ
  name: string; // e.g., 建筑师
  functionStack: string[]; // e.g., Ni, Te, Fi, Se
  description: string;
  systemInstruction: string;
  color: string;
  icon: string;
}

// Knowledge Graph Types
export interface KnowledgeNode {
  id: string;
  label: string;
  category: string;
  masteryLevel: number; // 0-100
  x?: number; // For visualization
  y?: number;
  isGhost?: boolean; // If true, this is a placeholder/template node
}

export interface KnowledgeLink {
  source: string;
  target: string;
  strength: number;
}

import React, { useContext, useState, useRef, useEffect } from 'react';
import { GlobalContext } from '../constants';
import { CalendarBlock, KnowledgeNode } from '../types';
import { GoogleGenAI } from "@google/genai";
import { CameraModal } from './CameraModal';

export const CalendarOverlay: React.FC = () => {
  const { isCalendarOpen, setIsCalendarOpen, calendarBlocks, updateCalendarBlock, addCalendarBlock, setCalendarBlocks, weather, mood, addToTransferStation } = useContext(GlobalContext) as any;

  // Drag State
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);

  // Modals & UI State
  const [showNewTaskModal, setShowNewTaskModal] = useState(false);
  const [showSmartModal, setShowSmartModal] = useState(false);
  const [activeBlockId, setActiveBlockId] = useState<string | null>(null); // For Swipe/Menu actions
  const [showCamera, setShowCamera] = useState(false);

  // New Task Input
  const [newTaskData, setNewTaskData] = useState({ title: '', duration: 30, type: 'study' as const });

  // Smart Analysis Input
  const [smartInput, setSmartInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  // Timers for long press
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Time Slots: 06:00 - 23:00
  const hours = Array.from({ length: 18 }, (_, i) => i + 6);

  if (!isCalendarOpen) return null;

  // --- Handlers ---

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
    setActiveBlockId(null); // Close menus on drag
  };

  const handleDrop = (time: string | undefined) => {
    if (draggedBlock) {
      updateCalendarBlock(draggedBlock.id, { assignedTime: time });
      setDraggedBlock(null);
    }
  };

  const startLongPress = (id: string) => {
      longPressTimer.current = setTimeout(() => {
          setActiveBlockId(id);
      }, 600); // 600ms for long press
  };

  const endLongPress = () => {
      if (longPressTimer.current) {
          clearTimeout(longPressTimer.current);
      }
  };

  const handleCreateTask = () => {
      if (!newTaskData.title.trim()) return;
      addCalendarBlock({
          id: Date.now().toString(),
          title: newTaskData.title,
          duration: Number(newTaskData.duration),
          type: newTaskData.type,
          notes: ''
      });
      setShowNewTaskModal(false);
      setNewTaskData({ title: '', duration: 30, type: 'study' });
  };

  const handleAutoFill = () => {
      let currentHour = 9;
      const unassignedBlocks = calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime);
      unassignedBlocks.forEach((block: CalendarBlock) => {
          if (currentHour < 22) {
             updateCalendarBlock(block.id, { assignedTime: `${currentHour.toString().padStart(2,'0')}:00` });
             currentHour += Math.ceil(block.duration / 60);
          }
      });
  };

  const exportReport = () => {
    const header = `每日复盘 (Daily Report) - ${new Date().toLocaleDateString()}\n`;
    const csvContent = "时间,任务,类型,时长,状态,备注\n" + 
      calendarBlocks
        .sort((a: CalendarBlock, b: CalendarBlock) => (a.assignedTime || 'z').localeCompare(b.assignedTime || 'z'))
        .map((b: CalendarBlock) => `${b.assignedTime || '未安排'},${b.title},${b.type},${b.duration}分钟,${b.isCompleted?'完成':'待办'},${b.notes || ''}`)
        .join("\n");
    const blob = new Blob(['\uFEFF' + header + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `daily_report_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  // --- Smart AI Features ---

  const handleSmartAnalysis = async () => {
      if (!smartInput.trim()) return;
      setIsProcessing(true);
      try {
          const apiKey = process.env.API_KEY || '';
          const ai = new GoogleGenAI({ apiKey });

          const prompt = `
            Analyzing the following text/schedule/todo-list. 
            Identify specific tasks.
            Return ONLY a JSON array of objects with keys: "title" (string), "duration" (number, minutes, default 30), "type" (one of: 'study', 'exam', 'rest', 'other').
            Input: ${smartInput}
          `;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt,
              config: { responseMimeType: 'application/json' }
          });

          const tasks = JSON.parse(response.text || '[]');

          // Import
          tasks.forEach((t: any, i: number) => {
              addCalendarBlock({
                  id: `smart_${Date.now()}_${i}`,
                  title: t.title,
                  duration: t.duration || 30,
                  type: t.type || 'other'
              });
          });
          setShowSmartModal(false);
          setSmartInput('');
      } catch (e) {
          alert('AI分析失败，请重试');
      } finally {
          setIsProcessing(false);
      }
  };

  const handleSyncToKG = async () => {
      // Sync tasks to Knowledge Graph Transfer Station
      setIsProcessing(true);
      try {
          const taskList = calendarBlocks.map((b: CalendarBlock) => b.title).join(', ');
          const apiKey = process.env.API_KEY || '';
          const ai = new GoogleGenAI({ apiKey });

          const prompt = `
            Analyze these daily tasks: "${taskList}".
            Extract key "Knowledge Points" or "Topics" involved.
            Return ONLY a JSON array of objects with keys: "label" (string), "category" (string, choose best from: 'core', 'sub').
          `;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt,
              config: { responseMimeType: 'application/json' }
          });

          const points = JSON.parse(response.text || '[]');

          const newNodes: KnowledgeNode[] = points.map((p: any, i: number) => ({
              id: `sync_${Date.now()}_${i}`,
              label: p.label,
              category: p.category,
              masteryLevel: 0,
              isGhost: false
          }));

          addToTransferStation(newNodes);
          alert(`成功提取 ${newNodes.length} 个知识点至中转站！`);
      } catch (e) {
          alert('提取失败');
      } finally {
          setIsProcessing(false);
      }
  };

  // --- Visual Helpers ---
  const getTypeColor = (block: CalendarBlock) => {
      if (block.color) return `bg-[${block.color}] border-black/10 text-white`; // Custom

      switch(block.type) {
          case 'study': return 'bg-blue-100 dark:bg-blue-900/40 border-blue-200 dark:border-blue-700/50 text-blue-900 dark:text-blue-100';
          case 'exam': return 'bg-red-100 dark:bg-red-900/40 border-red-200 dark:border-red-700/50 text-red-900 dark:text-red-100';
          case 'rest': return 'bg-emerald-100 dark:bg-emerald-900/40 border-emerald-200 dark:border-emerald-700/50 text-emerald-900 dark:text-emerald-100';
          case 'weather': return 'bg-sky-100 dark:bg-sky-900/40 border-sky-200 dark:border-sky-700/50 text-sky-900 dark:text-sky-100';
          case 'mood': return 'bg-pink-100 dark:bg-pink-900/40 border-pink-200 dark:border-pink-700/50 text-pink-900 dark:text-pink-100';
          case 'other': default: return 'bg-gray-100 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-900 dark:text-gray-100';
      }
  };

  const getTypeIcon = (type: string) => {
      switch(type) {
          case 'study': return 'fa-book-open';
          case 'exam': return 'fa-exclamation-circle';
          case 'rest': return 'fa-coffee';
          case 'weather': return 'fa-cloud';
          case 'mood': return 'fa-smile';
          case 'other': return 'fa-sticky-note';
          default: return 'fa-circle';
      }
  };

  // --- Render Block Component ---
  const renderBlockItem = (block: CalendarBlock) => {
      const isActive = activeBlockId === block.id;
      const customStyle = block.color ? { backgroundColor: block.color, color: '#fff', borderColor: 'transparent' } : {};

      return (
          <div
            key={block.id}
            draggable={!isActive}
            onDragStart={() => handleDragStart(block)}
            onMouseDown={() => startLongPress(block.id)}
            onMouseUp={endLongPress}
            onTouchStart={() => startLongPress(block.id)}
            onTouchEnd={endLongPress}
            onClick={() => isActive ? setActiveBlockId(null) : null} // Click to close if open
            className={`relative group p-2 rounded-lg border text-xs flex flex-col justify-center cursor-grab transition-all overflow-hidden mb-2 shadow-sm ${getTypeColor(block)} ${isActive ? 'ring-2 ring-blue-500 scale-105 z-10' : ''}`}
            style={customStyle}
          >
              {!isActive && (
                  <>
                    <div className="font-bold truncate">{block.title}</div>
                    <div className="text-[10px] opacity-70 flex items-center gap-1">
                        <i className={`fas ${getTypeIcon(block.type)}`}></i> {block.duration}m
                    </div>
                    {block.notes && <div className="mt-1 text-[9px] opacity-60 truncate"><i className="fas fa-sticky-note mr-1"></i>{block.notes}</div>}
                  </>
              )}

              {/* Action Menu (Swipe/LongPress Reveal) */}
              {isActive && (
                  <div className="absolute inset-0 bg-white dark:bg-gray-800 flex items-center justify-around animate-[fadeIn_0.2s]">
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#ef4444' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-red-500"></button>
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#3b82f6' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-blue-500"></button>
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#10b981' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-emerald-500"></button>

                      <div className="w-px h-6 bg-gray-200 dark:bg-gray-700 mx-1"></div>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          const newTime = prompt("修改时长 (分钟):", block.duration.toString());
                          if(newTime) updateCalendarBlock(block.id, { duration: parseInt(newTime) });
                          setActiveBlockId(null);
                      }} className="text-gray-500 hover:text-blue-500"><i className="fas fa-clock"></i></button>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          const note = prompt("添加备注:", block.notes);
                          updateCalendarBlock(block.id, { notes: note || '' });
                          setActiveBlockId(null);
                      }} className="text-gray-500 hover:text-yellow-500"><i className="fas fa-pen"></i></button>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          if(confirm("删除此任务?")) setCalendarBlocks(prev => prev.filter(b => b.id !== block.id)); 
                      }} className="text-red-500"><i className="fas fa-trash"></i></button>
                  </div>
              )}
          </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] flex justify-end pointer-events-none">
      <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px] pointer-events-auto transition-opacity" onClick={() => setIsCalendarOpen(false)}></div>

      <div className="relative w-full md:w-[600px] h-full bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl pointer-events-auto flex flex-col animate-[slideInRight_0.3s_ease-out]">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-black/20">
            <div>
                <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2 tracking-tight">
                    <span className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center text-white shadow-md"><i className="fas fa-calendar-day"></i></span>
                    日程规划
                </h2>
                <div className="text-xs text-gray-500 mt-1 flex gap-3 font-mono">
                   <span>{new Date().toLocaleDateString()}</span>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={() => setShowSmartModal(true)} className="px-3 py-1.5 text-xs bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 rounded-lg hover:bg-purple-100 border border-purple-200 dark:border-purple-800 transition-colors">
                    <i className="fas fa-robot mr-1"></i>智能
                </button>
                <button onClick={handleSyncToKG} className="px-3 py-1.5 text-xs bg-teal-50 dark:bg-teal-900/20 text-teal-600 dark:text-teal-400 rounded-lg hover:bg-teal-100 border border-teal-200 dark:border-teal-800 transition-colors" title="提取知识点到图谱中转站">
                    <i className="fas fa-project-diagram mr-1"></i>存入图谱
                </button>
                <button onClick={() => setIsCalendarOpen(false)} className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gray-600 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                    <i className="fas fa-times"></i>
                </button>
            </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
            {/* Left Strip: Pool */}
            <div className="w-[200px] bg-gray-50 dark:bg-black/20 border-r border-gray-200 dark:border-gray-700 p-3 overflow-y-auto flex flex-col" onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop(undefined)}>
                <h3 className="text-[10px] uppercase font-bold text-gray-400 mb-3 text-center tracking-widest">任务池</h3>

                <button 
                    onClick={() => setShowNewTaskModal(true)}
                    className="w-full py-2 mb-3 bg-blue-500 text-white rounded-lg text-sm font-bold hover:bg-blue-600 transition-all shadow-sm flex items-center justify-center gap-2"
                >
                    <i className="fas fa-plus"></i> 新任务
                </button>

                <div className="space-y-1 pb-10">
                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).map(renderBlockItem)}

                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).length === 0 && (
                        <div className="text-center text-xs text-gray-400 py-8 opacity-50 flex flex-col items-center">
                            <i className="fas fa-inbox text-2xl mb-2"></i>
                            暂无待办
                        </div>
                    )}
                </div>

                <div className="mt-auto pt-4 border-t border-gray-200 dark:border-gray-700">
                    <div className="grid grid-cols-2 gap-2">
                        <button onClick={handleAutoFill} className="py-2 text-xs bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-gray-600 dark:text-gray-300 hover:bg-gray-50">
                            自动填充
                        </button>
                        <button onClick={exportReport} className="py-2 text-xs bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-gray-600 dark:text-gray-300 hover:bg-gray-50">
                            导出报表
                        </button>
                    </div>
                </div>
            </div>

            {/* Right Area: Timeline */}
            <div className="flex-1 overflow-y-auto relative bg-white dark:bg-gray-900">
                <div className="space-y-0 pb-20">
                    {hours.map(hour => {
                        const timeStr = `${hour.toString().padStart(2,'0')}:00`;
                        const blocksInSlot = calendarBlocks.filter((b: CalendarBlock) => b.assignedTime === timeStr);

                        return (
                            <div 
                                key={hour}
                                onDragOver={(e) => e.preventDefault()}
                                onDrop={() => handleDrop(timeStr)}
                                className="group relative flex min-h-[70px] border-b border-gray-100 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800/20 transition-colors"
                            >
                                {/* Time Column */}
                                <div className="w-16 py-3 px-2 border-r border-gray-100 dark:border-gray-800 flex flex-col items-end gap-1 shrink-0">
                                    <span className="text-xs font-bold text-gray-700 dark:text-gray-300 font-mono">{timeStr}</span>
                                </div>

                                {/* Task Area */}
                                <div className="flex-1 p-1 flex flex-row gap-1 relative overflow-x-auto">
                                    {blocksInSlot.length > 0 ? blocksInSlot.map(renderBlockItem) : (
                                        <div className="w-full h-full flex items-center justify-center opacity-0 group-hover:opacity-20 transition-opacity pointer-events-none">
                                            <i className="fas fa-plus text-gray-400"></i>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>

        {/* --- MODALS --- */}

        {/* 1. New Task Modal */}
        {showNewTaskModal && (
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-sm p-6 animate-[fadeInUp_0.2s]">
                    <h3 className="text-lg font-bold mb-4 dark:text-white">创建新任务</h3>

                    <div className="space-y-4">
                        <div>
                            <label className="text-xs text-gray-500 block mb-1">任务名称</label>
                            <input 
                                value={newTaskData.title}
                                onChange={e => setNewTaskData({...newTaskData, title: e.target.value})}
                                className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-blue-500 outline-none text-gray-900 dark:text-white text-sm"
                                placeholder="输入任务..."
                                autoFocus
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs text-gray-500 block mb-1">时长 (分钟)</label>
                                <input 
                                    type="number"
                                    value={newTaskData.duration}
                                    onChange={e => setNewTaskData({...newTaskData, duration: Number(e.target.value)})}
                                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-blue-500 outline-none text-gray-900 dark:text-white text-sm"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-gray-500 block mb-1">类型</label>
                                <select 
                                    value={newTaskData.type}
                                    onChange={e => setNewTaskData({...newTaskData, type: e.target.value as any})}
                                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 outline-none text-gray-900 dark:text-white text-sm"
                                >
                                    <option value="study">学习</option>
                                    <option value="exam">考试</option>
                                    <option value="rest">休息</option>
                                    <option value="other">其他</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                        <button onClick={() => setShowNewTaskModal(false)} className="px-4 py-2 text-sm text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded">取消</button>
                        <button onClick={handleCreateTask} className="px-4 py-2 text-sm bg-blue-500 text-white rounded hover:bg-blue-600">确定</button>
                    </div>
                </div>
            </div>
        )}

        {/* 2. Smart AI Modal */}
        {showSmartModal && (
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-sm p-6 animate-[fadeInUp_0.2s]">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-bold dark:text-white flex items-center gap-2"><i className="fas fa-robot text-purple-500"></i> 智能识别</h3>
                        <button onClick={() => setShowSmartModal(false)} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
                    </div>

                    {showCamera && <CameraModal onCapture={(file) => { setSmartInput(prev => prev + ` [Image: ${file.name}]`); setShowCamera(false); }} onClose={() => setShowCamera(false)} />}
                    <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => { if(e.target.files?.[0]) setSmartInput(prev => prev + ` [File: ${e.target.files![0].name}]`); }} />

                    <textarea 
                        value={smartInput}
                        onChange={e => setSmartInput(e.target.value)}
                        placeholder="输入日程文本，或者拍照识别日程表..."
                        className="w-full h-32 p-3 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-purple-500 outline-none text-gray-900 dark:text-white text-sm resize-none mb-3"
                    />

                    <div className="flex gap-2 mb-4">
                        <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-2 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded text-xs flex items-center justify-center gap-1 hover:bg-gray-200">
                            <i className="fas fa-image"></i> 图片导入
                        </button>
                        <button onClick={() => setShowCamera(true)} className="flex-1 py-2 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded text-xs flex items-center justify-center gap-1 hover:bg-gray-200">
                            <i className="fas fa-camera"></i> 拍照
                        </button>
                    </div>

                    <button 
                        onClick={handleSmartAnalysis}
                        disabled={isProcessing || !smartInput}
                        className="w-full py-2 bg-purple-500 text-white rounded text-sm hover:bg-purple-600 disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>}
                        开始分析并导入
                    </button>
                </div>
            </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  // Consume Global State
  const { 
      nodes, setNodes, links, setLinks, 
      savedGraphs, saveGraph, loadGraph, deleteGraph,
      transferStation, addToTransferStation, removeFromTransferStation 
  } = useContext(GlobalContext) as any;

  const navigate = useNavigate();
  const location = useLocation();

  // Local Visualization State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // History Stack for Undo/Redo
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [isLinkingMode, setIsLinkingMode] = useState(false); // Toggle for mobile/easier linking

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false); 
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number; 
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const spacePressed = useRef(false);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  // Initial History Save & View Restore & Sync Logic
  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }

      // Load View State
      const savedTransform = localStorage.getItem('kg_transform');
      if (savedTransform) {
          try {
              const t = JSON.parse(savedTransform);
              setTransform(t);
          } catch(e) {}
      } else {
           setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
      }

      // Handle Imported Nodes (from Office sync)
      if (location.state?.importedNodes) {
          const imported = location.state.importedNodes as KnowledgeNode[];
          if (imported.length > 0) {
              const cx = (window.innerWidth / 2 - transform.x) / transform.k;
              const cy = (window.innerHeight / 2 - transform.y) / transform.k;

              const positionedNodes = imported.map(n => ({
                  ...n,
                  x: cx + (Math.random() - 0.5) * 200,
                  y: cy + (Math.random() - 0.5) * 200
              }));

              setNodes((prev: KnowledgeNode[]) => [...prev, ...positionedNodes]);
              saveToHistory([...nodes, ...positionedNodes], links);
              window.history.replaceState({}, document.title);
          }
      }

      if (location.state?.autoAnalyzeText) {
          handleAnalyze(location.state.autoAnalyzeText);
          window.history.replaceState({}, document.title);
      }

  }, []); 

  // Save View State on Change
  useEffect(() => {
      localStorage.setItem('kg_transform', JSON.stringify(transform));
  }, [transform]);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      } else if (selectedId) {
          const newNodes = nodes.filter(n => n.id !== selectedId);
          const newLinks = links.filter(l => l.source !== selectedId && l.target !== selectedId);
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedId(null);
      } else if (selectedLinkIndex !== null) {
          const newLinks = links.filter((_, i) => i !== selectedLinkIndex);
          setLinks(newLinks);
          saveToHistory(nodes, newLinks);
          setSelectedLinkIndex(null);
      }
  }, [selectedId, selectedLinkIndex, selectedNodeIds, nodes, links, saveToHistory]);

  const handleCopy = useCallback(() => {
      const nodesToCopy = nodes.filter(n => selectedNodeIds.has(n.id) || n.id === selectedId);
      if (nodesToCopy.length > 0) {
          addToTransferStation(nodesToCopy);
      }
  }, [nodes, selectedNodeIds, selectedId, addToTransferStation]);

  const handlePaste = useCallback(() => {
      if (transferStation.length > 0) {
         const cx = (window.innerWidth / 2 - transform.x) / transform.k;
         const cy = (window.innerHeight / 2 - transform.y) / transform.k;

         const newNodes = [...nodes];
         transferStation.forEach((n: KnowledgeNode, idx: number) => {
             newNodes.push({
                 ...n,
                 id: `paste_${Date.now()}_${idx}`,
                 x: cx + (Math.random() - 0.5) * 50,
                 y: cy + (Math.random() - 0.5) * 50
             });
         });
         setNodes(newNodes);
         saveToHistory(newNodes, links);
      }
  }, [transferStation, transform, nodes, links, saveToHistory]);

  // KEYBOARD SHORTCUTS LISTENER
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

        if (e.code === 'Space') {
             spacePressed.current = true;
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            setShowSaveModal(true);
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            handleUndo();
        }

        if (((e.ctrlKey || e.metaKey) && e.key === 'y') || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'z')) {
            e.preventDefault();
            handleRedo();
        }

        if (e.key === 'Delete' || e.key === 'Backspace') {
            e.preventDefault();
            handleDeleteSelected();
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
            e.preventDefault();
            handleCopy();
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
             e.preventDefault();
             handlePaste();
        }

        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
            e.preventDefault();
            const step = e.shiftKey ? 10 : 2;
            const dx = e.key === 'ArrowLeft' ? -step : e.key === 'ArrowRight' ? step : 0;
            const dy = e.key === 'ArrowUp' ? -step : e.key === 'ArrowDown' ? step : 0;

            if (selectedNodeIds.size > 0 || selectedId) {
                setNodes((prev: KnowledgeNode[]) => prev.map(n => {
                    if (selectedNodeIds.has(n.id) || n.id === selectedId) {
                        return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
                    }
                    return n;
                }));
            }
        }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
        if (e.code === 'Space') {
             spacePressed.current = false;
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
    };
  }, [handleUndo, handleRedo, handleDeleteSelected, handleCopy, handlePaste, selectedNodeIds, selectedId]);


  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && spacePressed.current) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; 
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      // Link Mode Check
      if (e.shiftKey || isLinkingMode) {
          setInteractionState({
              type: 'creatingLink',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX, currentY: worldY
          });
      } else {
          if (!selectedNodeIds.has(clickedNode.id)) {
              if (e.ctrlKey) {
                  const newSet = new Set(selectedNodeIds);
                  newSet.add(clickedNode.id);
                  setSelectedNodeIds(newSet);
              } else {
                  setSelectedNodeIds(new Set([clickedNode.id]));
              }
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      if ((e.target as Element).tagName === 'svg' || (e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedLinkIndex(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode') {
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;
        setNodes(prev => prev.map(n => {
             if (selectedNodeIds.has(n.id) || n.id === interactionState.targetId) {
                return { ...n, x: (n.x || 0) + dx, y: (n.y || 0) + dy };
             }
             return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));
    }
    else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
    else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                const newLinks = [...links, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }];
                setLinks(newLinks);
                saveToHistory(nodes, newLinks);
            }
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 50,
          isGhost: false,
          x, y
      };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  const handleGenerate = async () => {
    // ... (Generate Logic kept same)
    // For brevity, assuming existing handleGenerate logic remains
    handleAnalyze();
  };

  const handleAnalyze = async (manualInput?: string) => {
    // ... (Analysis Logic kept same)
    // For brevity, assuming existing handleAnalyze logic remains
  };

  // ... (Other handlers like handleSaveGraph, handleAddToTransfer, handleDropFromTransfer, etc. remain the same)

  // Layout & Radar effects remain same ...

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => {/*...*/}} className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`} title={label}>
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {/* ... (Existing Camera/Input modals) ... */}
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        {/* ... (Existing Header content) ... */}
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm min-w-0">
          <Link to="/" className="w-8 h-8 flex-shrink-0 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide truncate">灵境 <span className="text-kg-primary font-light hidden sm:inline">| 知识图谱</span></h1>

          {/* Link Mode Toggle for Touch Users */}
          <button 
            onClick={() => setIsLinkingMode(!isLinkingMode)}
            className={`ml-2 px-2 py-1 rounded text-xs border transition-colors ${isLinkingMode ? 'bg-kg-primary text-white border-kg-primary' : 'bg-transparent text-kg-text border-gray-300'}`}
          >
            <i className="fas fa-link mr-1"></i> {isLinkingMode ? '连线中' : '连线模式'}
          </button>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm flex-shrink-0">
           <SystemStatus />
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full">
              <i className="fas fa-bars"></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area (SVG) ... (Keep existing SVG rendering logic) ... */}
      <div ref={containerRef} className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp} onDoubleClick={handleDoubleClickBg}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            {/* ... Defs ... */}
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i;
                    const isGhostLink = src.isGhost || tgt.isGhost;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} strokeOpacity={isSelected ? 1 : 0.6} strokeDasharray={isGhostLink ? "5,5" : "0"} markerEnd={isGhostLink ? "" : "url(#arrowhead)"} />
                        </g>
                    );
                })}
                {interactionState.type === 'creatingLink' && (<line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />)}

                {/* Box Selection Rect */}
                {interactionState.type === 'boxSelecting' && (<rect x={Math.min(interactionState.startX, interactionState.currentX!)} y={Math.min(interactionState.startY, interactionState.currentY!)} width={Math.abs(interactionState.currentX! - interactionState.startX)} height={Math.abs(interactionState.currentY! - interactionState.startY)} fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2" className="pointer-events-none" />)}

                {nodes.map((node) => {
                    // ... (Existing Node Rendering) ...
                    const isSelected = selectedId === node.id || selectedNodeIds.has(node.id);
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';
                    return (
                        <g key={node.id} transform={`translate(${node.x},${node.y})`} onDoubleClick={(e) => handleNodeDoubleClick(e, node)} className="cursor-pointer transition-all duration-300">
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}
                            <circle r={r} fill={node.isGhost ? 'transparent' : color} stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-bg)'} strokeWidth={node.isGhost ? 1 : 3} strokeDasharray={node.isGhost ? "4,2" : "0"} className={node.isGhost ? "" : "shadow-sm"} />
                            <rect x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4" fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none" />
                            <text y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)" className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}>{node.label}</text>
                            {(isSelected && !node.isGhost) && (<text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">{node.masteryLevel}%</text>)}
                            {node.isGhost && (<text y={5} textAnchor="middle" fontSize="10" fill="var(--kg-text)" fontWeight="bold" className="pointer-events-none">+</text>)}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      <div className={`fixed top-0 right-0 h-full w-80 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"><i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i></button>

          <div className="p-6 h-full flex flex-col pt-20 overflow-y-auto">
              <h2 className="text-lg font-bold mb-4 flex justify-between items-center">
                  <span>数据控制台</span>
                  <button onClick={()=>setShowSaveModal(true)} className="text-xs text-kg-primary bg-kg-bg px-2 py-1 rounded hover:bg-kg-primary hover:text-white transition-colors"><i className="fas fa-save mr-1"></i> 保存</button>
              </h2>

              {selectedNodeIds.size > 0 && (
                  <div className="mb-6 p-4 bg-kg-bg rounded border border-kg-primary/20 animate-[fadeIn_0.2s]">
                      {/* ... (Existing Batch Actions) ... */}
                      <h3 className="text-sm font-bold text-kg-primary mb-2">已选节点: {selectedNodeIds.size}</h3>
                      <button onClick={handleCopy} className="w-full text-xs text-purple-500 border border-purple-200 rounded py-1 hover:bg-purple-50 mb-2"><i className="fas fa-archive mr-1"></i> 复制到中转站</button>
                      <button onClick={handleDeleteSelected} className="w-full text-xs text-red-500 border border-red-200 rounded py-1 hover:bg-red-50">删除所选</button>
                  </div>
              )}

              {/* Selected Node Edit (Enhanced with Slider) */}
              {selectedId && !selectedNodeIds.has(selectedId) && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">节点编辑</span></div>
                      {nodes.find(n => n.id === selectedId) && (
                          <div className="space-y-4">
                              <div>
                                  <label className="text-xs text-kg-text opacity-60">名称</label>
                                  <input className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" value={nodes.find(n => n.id === selectedId)?.label} onChange={(e) => { const val = e.target.value; setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, label: val } : n)); }} onBlur={() => saveToHistory(nodes, links)} />
                              </div>

                              {/* Mastery Slider */}
                              <div>
                                  <label className="text-xs text-kg-text opacity-60 flex justify-between">
                                      <span>掌握度</span>
                                      <span className="font-bold text-kg-primary">{nodes.find(n => n.id === selectedId)?.masteryLevel}%</span>
                                  </label>
                                  <input 
                                    type="range" 
                                    min="0" 
                                    max="100" 
                                    value={nodes.find(n => n.id === selectedId)?.masteryLevel} 
                                    onChange={(e) => { 
                                        const val = Number(e.target.value); 
                                        setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, masteryLevel: val } : n)); 
                                    }} 
                                    onMouseUp={() => saveToHistory(nodes, links)}
                                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer mt-2 accent-kg-primary"
                                  />
                              </div>

                              <button onClick={handleDeleteSelected} className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors w-full"><i className="fas fa-trash"></i> 删除</button>
                          </div>
                      )}
                  </div>
              )}

              {/* Selected Link Edit */}
              {selectedLinkIndex !== null && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">连接编辑</span></div>
                      <div className="p-4 bg-kg-bg rounded border border-gray-200 dark:border-gray-700">
                          <p className="text-xs mb-3 text-center opacity-60">连接强度: {links[selectedLinkIndex]?.strength}</p>
                          <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded text-xs hover:bg-red-100"><i className="fas fa-unlink mr-1"></i> 断开连接</button>
                      </div>
                  </div>
              )}

              {/* ... (Existing Transfer Station & Default Views) ... */}
              {!selectedId && selectedLinkIndex === null && selectedNodeIds.size === 0 && (
                  <div className="space-y-6">
                      <div className="bg-kg-bg p-4 rounded-xl text-center border border-gray-100 dark:border-gray-700 shadow-inner">
                          <div className="text-sm font-bold text-kg-primary mb-2">综合能力雷达</div>
                          <div className="w-32 h-32 mx-auto">{/* ... renderRadar() call ... */}</div>
                      </div>

                      <div className="flex-grow">
                           <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">AI 辅助生成</div>
                           <textarea value={input} onChange={e=>setInput(e.target.value)} placeholder="输入主题或留空使用预设..." className="w-full bg-kg-bg p-3 rounded-lg mb-2 text-sm border border-gray-200 dark:border-gray-700 h-24 focus:border-kg-primary outline-none resize-none" />
                           <div className="flex gap-2">
                               <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-folder-open"></i></button>
                               <button onClick={() => setShowCamera(true)} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-camera"></i></button>
                               <button onClick={() => handleGenerate()} disabled={isAnalyzing} className="flex-1 bg-kg-primary text-white py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all">
                                   {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : (input.trim() ? 'AI生成图谱' : '一键生成预设')}
                               </button>
                           </div>
                      </div>
                  </div>
              )}
          </div>
      </div>

      {/* ... (Existing Save Modal) ... */}
    </div>
  );
};

import React from 'react';

export enum EngineType {
  FROST_BLADE = 'frost_blade', // Fast -> gemini-3-flash-preview
  ETERNAL_CORE = 'eternal_core', // Deep -> gemini-3-pro-preview
  LAND_VESSEL = 'land_vessel', // Custom Mod Loader
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  engine?: EngineType;
  senderName?: string; 
}

export type ThemeMode = 'light' | 'dark' | 'system';

export interface User {
  username: string;
  avatar?: string;
  isLoggedIn: boolean;
  role: 'guest' | 'user' | 'admin';
}

export interface ThemeContextType {
  theme: ThemeMode;
  toggleTheme: () => void;
}

export interface UserContextType {
  user: User;
  login: (username: string) => void;
  logout: () => void;
}

// --- Global Context Types ---
export interface GlobalContextType {
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
  setNodes: React.Dispatch<React.SetStateAction<KnowledgeNode[]>>;
  setLinks: React.Dispatch<React.SetStateAction<KnowledgeLink[]>>;

  // Knowledge Transfer Station (Clipboard)
  transferStation: KnowledgeNode[];
  addToTransferStation: (nodes: KnowledgeNode[]) => void;
  removeFromTransferStation: (nodeId: string) => void;

  // Persistence
  savedGraphs: SavedGraph[];
  saveGraph: (name: string, selectedNodeIds?: string[]) => void;
  loadGraph: (id: string) => void;
  deleteGraph: (id: string) => void;

  // Calendar & Weather System
  isCalendarOpen: boolean;
  setIsCalendarOpen: React.Dispatch<React.SetStateAction<boolean>>;
  calendarBlocks: CalendarBlock[];
  setCalendarBlocks: React.Dispatch<React.SetStateAction<CalendarBlock[]>>;
  addCalendarBlock: (block: CalendarBlock) => void;
  updateCalendarBlock: (id: string, updates: Partial<CalendarBlock>) => void;
  weather: WeatherState;
  setWeather: React.Dispatch<React.SetStateAction<WeatherState>>;
  mood: string;
  setMood: React.Dispatch<React.SetStateAction<string>>;
}

export interface SavedGraph {
  id: string;
  name: string;
  date: number;
  nodes: KnowledgeNode[];
  links: KnowledgeLink[];
}

export interface WeatherState {
  type: 'sunny' | 'cloudy' | 'rainy' | 'storm' | 'snow' | 'foggy';
  temp: number;
  icon: string;
}

export interface CalendarBlock {
  id: string;
  title: string;
  duration: number; // in minutes
  type: 'study' | 'exam' | 'rest' | 'other' | 'weather' | 'mood';
  assignedTime?: string; // HH:mm format, if null it's in the magnetic pool
  isCompleted?: boolean;
  color?: string; // Custom color override
  notes?: string; // Remarks
}

export interface MBTIPersona {
  id: string;
  type: string; // e.g., INTJ
  name: string; // e.g., 建筑师
  functionStack: string[]; // e.g., Ni, Te, Fi, Se
  description: string;
  systemInstruction: string;
  color: string;
  icon: string;
}

// Knowledge Graph Types
export interface KnowledgeNode {
  id: string;
  label: string;
  category: string;
  masteryLevel: number; // 0-100
  x?: number; // For visualization
  y?: number;
  isGhost?: boolean; // If true, this is a placeholder/template node
}

export interface KnowledgeLink {
  source: string;
  target: string;
  strength: number;
}

import React, { useContext, useState, useRef, useEffect } from 'react';
import { GlobalContext } from '../constants';
import { CalendarBlock, KnowledgeNode } from '../types';
import { GoogleGenAI } from "@google/genai";
import { CameraModal } from './CameraModal';

export const CalendarOverlay: React.FC = () => {
  const { isCalendarOpen, setIsCalendarOpen, calendarBlocks, updateCalendarBlock, addCalendarBlock, setCalendarBlocks, weather, mood, addToTransferStation } = useContext(GlobalContext) as any;

  // Drag State
  const [draggedBlock, setDraggedBlock] = useState<CalendarBlock | null>(null);

  // Modals & UI State
  const [showNewTaskModal, setShowNewTaskModal] = useState(false);
  const [showSmartModal, setShowSmartModal] = useState(false);
  const [activeBlockId, setActiveBlockId] = useState<string | null>(null); // For Swipe/Menu actions
  const [showCamera, setShowCamera] = useState(false);

  // New Task Input
  const [newTaskData, setNewTaskData] = useState({ title: '', duration: 30, type: 'study' as const });

  // Smart Analysis Input
  const [smartInput, setSmartInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  // Timers for long press
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Time Slots: 06:00 - 23:00
  const hours = Array.from({ length: 18 }, (_, i) => i + 6);

  if (!isCalendarOpen) return null;

  // --- Handlers ---

  const handleDragStart = (block: CalendarBlock) => {
    setDraggedBlock(block);
    setActiveBlockId(null); // Close menus on drag
  };

  const handleDrop = (time: string | undefined) => {
    if (draggedBlock) {
      updateCalendarBlock(draggedBlock.id, { assignedTime: time });
      setDraggedBlock(null);
    }
  };

  const startLongPress = (id: string) => {
      longPressTimer.current = setTimeout(() => {
          setActiveBlockId(id);
      }, 600); // 600ms for long press
  };

  const endLongPress = () => {
      if (longPressTimer.current) {
          clearTimeout(longPressTimer.current);
      }
  };

  const handleCreateTask = () => {
      if (!newTaskData.title.trim()) return;
      addCalendarBlock({
          id: Date.now().toString(),
          title: newTaskData.title,
          duration: Number(newTaskData.duration),
          type: newTaskData.type,
          notes: ''
      });
      setShowNewTaskModal(false);
      setNewTaskData({ title: '', duration: 30, type: 'study' });
  };

  const handleAutoFill = () => {
      let currentHour = 9;
      const unassignedBlocks = calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime);
      unassignedBlocks.forEach((block: CalendarBlock) => {
          if (currentHour < 22) {
             updateCalendarBlock(block.id, { assignedTime: `${currentHour.toString().padStart(2,'0')}:00` });
             currentHour += Math.ceil(block.duration / 60);
          }
      });
  };

  const exportReport = () => {
    const header = `每日复盘 (Daily Report) - ${new Date().toLocaleDateString()}\n`;
    const csvContent = "时间,任务,类型,时长,状态,备注\n" + 
      calendarBlocks
        .sort((a: CalendarBlock, b: CalendarBlock) => (a.assignedTime || 'z').localeCompare(b.assignedTime || 'z'))
        .map((b: CalendarBlock) => `${b.assignedTime || '未安排'},${b.title},${b.type},${b.duration}分钟,${b.isCompleted?'完成':'待办'},${b.notes || ''}`)
        .join("\n");
    const blob = new Blob(['\uFEFF' + header + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `daily_report_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  // --- Smart AI Features ---

  const handleSmartAnalysis = async () => {
      if (!smartInput.trim()) return;
      setIsProcessing(true);
      try {
          const apiKey = process.env.API_KEY || '';
          const ai = new GoogleGenAI({ apiKey });

          const prompt = `
            Analyzing the following text/schedule/todo-list. 
            Identify specific tasks.
            Return ONLY a JSON array of objects with keys: "title" (string), "duration" (number, minutes, default 30), "type" (one of: 'study', 'exam', 'rest', 'other').
            Input: ${smartInput}
          `;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt,
              config: { responseMimeType: 'application/json' }
          });

          const tasks = JSON.parse(response.text || '[]');

          // Import
          tasks.forEach((t: any, i: number) => {
              addCalendarBlock({
                  id: `smart_${Date.now()}_${i}`,
                  title: t.title,
                  duration: t.duration || 30,
                  type: t.type || 'other'
              });
          });
          setShowSmartModal(false);
          setSmartInput('');
      } catch (e) {
          alert('AI分析失败，请重试');
      } finally {
          setIsProcessing(false);
      }
  };

  const handleSyncToKG = async () => {
      // Sync tasks to Knowledge Graph Transfer Station
      setIsProcessing(true);
      try {
          const taskList = calendarBlocks.map((b: CalendarBlock) => b.title).join(', ');
          const apiKey = process.env.API_KEY || '';
          const ai = new GoogleGenAI({ apiKey });

          const prompt = `
            Analyze these daily tasks: "${taskList}".
            Extract key "Knowledge Points" or "Topics" involved.
            Return ONLY a JSON array of objects with keys: "label" (string), "category" (string, choose best from: 'core', 'sub').
          `;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt,
              config: { responseMimeType: 'application/json' }
          });

          const points = JSON.parse(response.text || '[]');

          const newNodes: KnowledgeNode[] = points.map((p: any, i: number) => ({
              id: `sync_${Date.now()}_${i}`,
              label: p.label,
              category: p.category,
              masteryLevel: 0,
              isGhost: false
          }));

          addToTransferStation(newNodes);
          alert(`成功提取 ${newNodes.length} 个知识点至中转站！`);
      } catch (e) {
          alert('提取失败');
      } finally {
          setIsProcessing(false);
      }
  };

  // --- Visual Helpers ---
  const getTypeColor = (block: CalendarBlock) => {
      if (block.color) return `bg-[${block.color}] border-black/10 text-white`; // Custom

      switch(block.type) {
          case 'study': return 'bg-blue-100 dark:bg-blue-900/40 border-blue-200 dark:border-blue-700/50 text-blue-900 dark:text-blue-100';
          case 'exam': return 'bg-red-100 dark:bg-red-900/40 border-red-200 dark:border-red-700/50 text-red-900 dark:text-red-100';
          case 'rest': return 'bg-emerald-100 dark:bg-emerald-900/40 border-emerald-200 dark:border-emerald-700/50 text-emerald-900 dark:text-emerald-100';
          case 'weather': return 'bg-sky-100 dark:bg-sky-900/40 border-sky-200 dark:border-sky-700/50 text-sky-900 dark:text-sky-100';
          case 'mood': return 'bg-pink-100 dark:bg-pink-900/40 border-pink-200 dark:border-pink-700/50 text-pink-900 dark:text-pink-100';
          case 'other': default: return 'bg-gray-100 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-900 dark:text-gray-100';
      }
  };

  const getTypeIcon = (type: string) => {
      switch(type) {
          case 'study': return 'fa-book-open';
          case 'exam': return 'fa-exclamation-circle';
          case 'rest': return 'fa-coffee';
          case 'weather': return 'fa-cloud';
          case 'mood': return 'fa-smile';
          case 'other': return 'fa-sticky-note';
          default: return 'fa-circle';
      }
  };

  // --- Render Block Component ---
  const renderBlockItem = (block: CalendarBlock) => {
      const isActive = activeBlockId === block.id;
      const customStyle = block.color ? { backgroundColor: block.color, color: '#fff', borderColor: 'transparent' } : {};

      return (
          <div
            key={block.id}
            draggable={!isActive}
            onDragStart={() => handleDragStart(block)}
            onMouseDown={() => startLongPress(block.id)}
            onMouseUp={endLongPress}
            onTouchStart={() => startLongPress(block.id)}
            onTouchEnd={endLongPress}
            onClick={() => isActive ? setActiveBlockId(null) : null} // Click to close if open
            className={`relative group p-2 rounded-lg border text-xs flex flex-col justify-center cursor-grab transition-all overflow-hidden mb-2 shadow-sm ${getTypeColor(block)} ${isActive ? 'ring-2 ring-blue-500 scale-105 z-10' : ''}`}
            style={customStyle}
          >
              {!isActive && (
                  <>
                    <div className="font-bold truncate">{block.title}</div>
                    <div className="text-[10px] opacity-70 flex items-center gap-1">
                        <i className={`fas ${getTypeIcon(block.type)}`}></i> {block.duration}m
                    </div>
                    {block.notes && <div className="mt-1 text-[9px] opacity-60 truncate"><i className="fas fa-sticky-note mr-1"></i>{block.notes}</div>}
                  </>
              )}

              {/* Action Menu (Swipe/LongPress Reveal) */}
              {isActive && (
                  <div className="absolute inset-0 bg-white dark:bg-gray-800 flex items-center justify-around animate-[fadeIn_0.2s]">
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#ef4444' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-red-500"></button>
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#3b82f6' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-blue-500"></button>
                      <button onClick={(e) => { e.stopPropagation(); updateCalendarBlock(block.id, { color: '#10b981' }); setActiveBlockId(null); }} className="w-6 h-6 rounded-full bg-emerald-500"></button>

                      <div className="w-px h-6 bg-gray-200 dark:bg-gray-700 mx-1"></div>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          const newTime = prompt("修改时长 (分钟):", block.duration.toString());
                          if(newTime) updateCalendarBlock(block.id, { duration: parseInt(newTime) });
                          setActiveBlockId(null);
                      }} className="text-gray-500 hover:text-blue-500"><i className="fas fa-clock"></i></button>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          const note = prompt("添加备注:", block.notes);
                          updateCalendarBlock(block.id, { notes: note || '' });
                          setActiveBlockId(null);
                      }} className="text-gray-500 hover:text-yellow-500"><i className="fas fa-pen"></i></button>

                      <button onClick={(e) => { 
                          e.stopPropagation(); 
                          if(confirm("删除此任务?")) setCalendarBlocks(prev => prev.filter(b => b.id !== block.id)); 
                      }} className="text-red-500"><i className="fas fa-trash"></i></button>
                  </div>
              )}
          </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] flex justify-end pointer-events-none">
      <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px] pointer-events-auto transition-opacity" onClick={() => setIsCalendarOpen(false)}></div>

      <div className="relative w-full md:w-[600px] h-full bg-white/95 dark:bg-gray-900/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl pointer-events-auto flex flex-col animate-[slideInRight_0.3s_ease-out]">

        {/* Header */}
        <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-black/20">
            <div>
                <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2 tracking-tight">
                    <span className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center text-white shadow-md"><i className="fas fa-calendar-day"></i></span>
                    日程规划
                </h2>
                <div className="text-xs text-gray-500 mt-1 flex gap-3 font-mono">
                   <span>{new Date().toLocaleDateString()}</span>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={() => setShowSmartModal(true)} className="px-3 py-1.5 text-xs bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 rounded-lg hover:bg-purple-100 border border-purple-200 dark:border-purple-800 transition-colors">
                    <i className="fas fa-robot mr-1"></i>智能
                </button>
                <button onClick={handleSyncToKG} className="px-3 py-1.5 text-xs bg-teal-50 dark:bg-teal-900/20 text-teal-600 dark:text-teal-400 rounded-lg hover:bg-teal-100 border border-teal-200 dark:border-teal-800 transition-colors" title="提取知识点到图谱中转站">
                    <i className="fas fa-project-diagram mr-1"></i>存入图谱
                </button>
                <button onClick={() => setIsCalendarOpen(false)} className="w-8 h-8 flex items-center justify-center text-gray-400 hover:text-gray-600 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                    <i className="fas fa-times"></i>
                </button>
            </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
            {/* Left Strip: Pool */}
            <div className="w-[200px] bg-gray-50 dark:bg-black/20 border-r border-gray-200 dark:border-gray-700 p-3 overflow-y-auto flex flex-col" onDragOver={(e) => e.preventDefault()} onDrop={() => handleDrop(undefined)}>
                <h3 className="text-[10px] uppercase font-bold text-gray-400 mb-3 text-center tracking-widest">任务池</h3>

                <button 
                    onClick={() => setShowNewTaskModal(true)}
                    className="w-full py-2 mb-3 bg-blue-500 text-white rounded-lg text-sm font-bold hover:bg-blue-600 transition-all shadow-sm flex items-center justify-center gap-2"
                >
                    <i className="fas fa-plus"></i> 新任务
                </button>

                <div className="space-y-1 pb-10">
                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).map(renderBlockItem)}

                    {calendarBlocks.filter((b: CalendarBlock) => !b.assignedTime).length === 0 && (
                        <div className="text-center text-xs text-gray-400 py-8 opacity-50 flex flex-col items-center">
                            <i className="fas fa-inbox text-2xl mb-2"></i>
                            暂无待办
                        </div>
                    )}
                </div>

                <div className="mt-auto pt-4 border-t border-gray-200 dark:border-gray-700">
                    <div className="grid grid-cols-2 gap-2">
                        <button onClick={handleAutoFill} className="py-2 text-xs bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-gray-600 dark:text-gray-300 hover:bg-gray-50">
                            自动填充
                        </button>
                        <button onClick={exportReport} className="py-2 text-xs bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-gray-600 dark:text-gray-300 hover:bg-gray-50">
                            导出报表
                        </button>
                    </div>
                </div>
            </div>

            {/* Right Area: Timeline */}
            <div className="flex-1 overflow-y-auto relative bg-white dark:bg-gray-900">
                <div className="space-y-0 pb-20">
                    {hours.map(hour => {
                        const timeStr = `${hour.toString().padStart(2,'0')}:00`;
                        const blocksInSlot = calendarBlocks.filter((b: CalendarBlock) => b.assignedTime === timeStr);

                        return (
                            <div 
                                key={hour}
                                onDragOver={(e) => e.preventDefault()}
                                onDrop={() => handleDrop(timeStr)}
                                className="group relative flex min-h-[70px] border-b border-gray-100 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800/20 transition-colors"
                            >
                                {/* Time Column */}
                                <div className="w-16 py-3 px-2 border-r border-gray-100 dark:border-gray-800 flex flex-col items-end gap-1 shrink-0">
                                    <span className="text-xs font-bold text-gray-700 dark:text-gray-300 font-mono">{timeStr}</span>
                                </div>

                                {/* Task Area */}
                                <div className="flex-1 p-1 flex flex-row gap-1 relative overflow-x-auto">
                                    {blocksInSlot.length > 0 ? blocksInSlot.map(renderBlockItem) : (
                                        <div className="w-full h-full flex items-center justify-center opacity-0 group-hover:opacity-20 transition-opacity pointer-events-none">
                                            <i className="fas fa-plus text-gray-400"></i>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>

        {/* --- MODALS --- */}

        {/* 1. New Task Modal */}
        {showNewTaskModal && (
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-sm p-6 animate-[fadeInUp_0.2s]">
                    <h3 className="text-lg font-bold mb-4 dark:text-white">创建新任务</h3>

                    <div className="space-y-4">
                        <div>
                            <label className="text-xs text-gray-500 block mb-1">任务名称</label>
                            <input 
                                value={newTaskData.title}
                                onChange={e => setNewTaskData({...newTaskData, title: e.target.value})}
                                className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-blue-500 outline-none text-gray-900 dark:text-white text-sm"
                                placeholder="输入任务..."
                                autoFocus
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-xs text-gray-500 block mb-1">时长 (分钟)</label>
                                <input 
                                    type="number"
                                    value={newTaskData.duration}
                                    onChange={e => setNewTaskData({...newTaskData, duration: Number(e.target.value)})}
                                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-blue-500 outline-none text-gray-900 dark:text-white text-sm"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-gray-500 block mb-1">类型</label>
                                <select 
                                    value={newTaskData.type}
                                    onChange={e => setNewTaskData({...newTaskData, type: e.target.value as any})}
                                    className="w-full p-2 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 outline-none text-gray-900 dark:text-white text-sm"
                                >
                                    <option value="study">学习</option>
                                    <option value="exam">考试</option>
                                    <option value="rest">休息</option>
                                    <option value="other">其他</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end gap-3 mt-6">
                        <button onClick={() => setShowNewTaskModal(false)} className="px-4 py-2 text-sm text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded">取消</button>
                        <button onClick={handleCreateTask} className="px-4 py-2 text-sm bg-blue-500 text-white rounded hover:bg-blue-600">确定</button>
                    </div>
                </div>
            </div>
        )}

        {/* 2. Smart AI Modal */}
        {showSmartModal && (
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl w-full max-w-sm p-6 animate-[fadeInUp_0.2s]">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-bold dark:text-white flex items-center gap-2"><i className="fas fa-robot text-purple-500"></i> 智能识别</h3>
                        <button onClick={() => setShowSmartModal(false)} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
                    </div>

                    {showCamera && <CameraModal onCapture={(file) => { setSmartInput(prev => prev + ` [Image: ${file.name}]`); setShowCamera(false); }} onClose={() => setShowCamera(false)} />}
                    <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => { if(e.target.files?.[0]) setSmartInput(prev => prev + ` [File: ${e.target.files![0].name}]`); }} />

                    <textarea 
                        value={smartInput}
                        onChange={e => setSmartInput(e.target.value)}
                        placeholder="输入日程文本，或者拍照识别日程表..."
                        className="w-full h-32 p-3 rounded bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 focus:border-purple-500 outline-none text-gray-900 dark:text-white text-sm resize-none mb-3"
                    />

                    <div className="flex gap-2 mb-4">
                        <button onClick={() => fileInputRef.current?.click()} className="flex-1 py-2 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded text-xs flex items-center justify-center gap-1 hover:bg-gray-200">
                            <i className="fas fa-image"></i> 图片导入
                        </button>
                        <button onClick={() => setShowCamera(true)} className="flex-1 py-2 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded text-xs flex items-center justify-center gap-1 hover:bg-gray-200">
                            <i className="fas fa-camera"></i> 拍照
                        </button>
                    </div>

                    <button 
                        onClick={handleSmartAnalysis}
                        disabled={isProcessing || !smartInput}
                        className="w-full py-2 bg-purple-500 text-white rounded text-sm hover:bg-purple-600 disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-magic"></i>}
                        开始分析并导入
                    </button>
                </div>
            </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useContext, useEffect, useRef, useCallback } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext, GlobalContext, KG_SYSTEM_INSTRUCTION, INITIAL_RADAR } from '../constants';
import { GoogleGenAI } from "@google/genai";
import { KnowledgeNode, KnowledgeLink } from '../types';
import { UserAuth } from '../components/UserAuth';
import { SystemStatus } from '../components/SystemStatus';
import { CameraModal } from '../components/CameraModal';

type LayoutType = 'mesh' | 'star' | 'bus' | 'tree' | 'evolution';

interface HistoryState {
    nodes: KnowledgeNode[];
    links: KnowledgeLink[];
}

export const KnowledgeGraph: React.FC = () => {
  const { theme, toggleTheme } = useContext(ThemeContext);
  // Consume Global State
  const { 
      nodes, setNodes, links, setLinks, 
      savedGraphs, saveGraph, loadGraph, deleteGraph,
      transferStation, addToTransferStation, removeFromTransferStation 
  } = useContext(GlobalContext) as any;

  const navigate = useNavigate();
  const location = useLocation();

  // Local Visualization State
  const [radarData, setRadarData] = useState(INITIAL_RADAR);

  // History Stack for Undo/Redo
  const [history, setHistory] = useState<HistoryState[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Interaction State
  const [selectedId, setSelectedId] = useState<string | null>(null); // Node ID
  const [selectedLinkIndex, setSelectedLinkIndex] = useState<number | null>(null);
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [isLinkingMode, setIsLinkingMode] = useState(false); // Toggle for mobile/easier linking

  const [showCamera, setShowCamera] = useState(false);
  const [layout, setLayout] = useState<LayoutType>('star'); 
  const [isPanelOpen, setIsPanelOpen] = useState(false); 
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [newGraphName, setNewGraphName] = useState('');

  // Canvas Transform & Drag State
  const [transform, setTransform] = useState({ x: 0, y: 0, k: 1 });
  const [interactionState, setInteractionState] = useState<{
    type: 'idle' | 'panning' | 'draggingNode' | 'creatingLink' | 'boxSelecting';
    startX: number;
    startY: number;
    targetId?: string; 
    currentX?: number; 
    currentY?: number;
  }>({ type: 'idle', startX: 0, startY: 0 });

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const spacePressed = useRef(false);

  // Analysis State
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisResult, setAnalysisResult] = useState<{
    analysis: string;
    predictedScore: number;
    suggestions: string[];
  } | null>(null);

  // --- Helpers ---
  const toWorld = useCallback((screenX: number, screenY: number) => {
    return {
      x: (screenX - transform.x) / transform.k,
      y: (screenY - transform.y) / transform.k
    };
  }, [transform]);

  const saveToHistory = useCallback((newNodes: KnowledgeNode[], newLinks: KnowledgeLink[]) => {
      setHistory(prev => {
          const newHistory = prev.slice(0, historyIndex + 1);
          newHistory.push({ nodes: JSON.parse(JSON.stringify(newNodes)), links: JSON.parse(JSON.stringify(newLinks)) });
          if (newHistory.length > 20) newHistory.shift(); 
          return newHistory;
      });
      setHistoryIndex(prev => Math.min(prev + 1, 19));
  }, [historyIndex]);

  // Initial History Save & View Restore & Sync Logic
  useEffect(() => {
      if (history.length === 0 && nodes.length > 0) {
          saveToHistory(nodes, links);
      }

      // Load View State
      const savedTransform = localStorage.getItem('kg_transform');
      if (savedTransform) {
          try {
              const t = JSON.parse(savedTransform);
              setTransform(t);
          } catch(e) {}
      } else {
           setTransform({ x: window.innerWidth / 2, y: window.innerHeight / 2, k: 1 });
      }

      // Handle Imported Nodes (from Office sync)
      if (location.state?.importedNodes) {
          const imported = location.state.importedNodes as KnowledgeNode[];
          if (imported.length > 0) {
              const cx = (window.innerWidth / 2 - transform.x) / transform.k;
              const cy = (window.innerHeight / 2 - transform.y) / transform.k;

              const positionedNodes = imported.map(n => ({
                  ...n,
                  x: cx + (Math.random() - 0.5) * 200,
                  y: cy + (Math.random() - 0.5) * 200
              }));

              setNodes((prev: KnowledgeNode[]) => [...prev, ...positionedNodes]);
              saveToHistory([...nodes, ...positionedNodes], links);
              window.history.replaceState({}, document.title);
          }
      }

      if (location.state?.autoAnalyzeText) {
          handleAnalyze(location.state.autoAnalyzeText);
          window.history.replaceState({}, document.title);
      }

  }, []); 

  // Save View State on Change
  useEffect(() => {
      localStorage.setItem('kg_transform', JSON.stringify(transform));
  }, [transform]);

  const handleUndo = useCallback(() => {
      if (historyIndex > 0) {
          const prevState = history[historyIndex - 1];
          setNodes(prevState.nodes);
          setLinks(prevState.links);
          setHistoryIndex(historyIndex - 1);
      }
  }, [history, historyIndex]);

  const handleRedo = useCallback(() => {
      if (historyIndex < history.length - 1) {
          const nextState = history[historyIndex + 1];
          setNodes(nextState.nodes);
          setLinks(nextState.links);
          setHistoryIndex(historyIndex + 1);
      }
  }, [history, historyIndex]);

  const handleDeleteSelected = useCallback(() => {
      if (selectedNodeIds.size > 0) {
          const newNodes = nodes.filter(n => !selectedNodeIds.has(n.id));
          const newLinks = links.filter(l => !selectedNodeIds.has(l.source) && !selectedNodeIds.has(l.target));
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedNodeIds(new Set());
          setSelectedId(null);
      } else if (selectedId) {
          const newNodes = nodes.filter(n => n.id !== selectedId);
          const newLinks = links.filter(l => l.source !== selectedId && l.target !== selectedId);
          setNodes(newNodes);
          setLinks(newLinks);
          saveToHistory(newNodes, newLinks);
          setSelectedId(null);
      } else if (selectedLinkIndex !== null) {
          const newLinks = links.filter((_, i) => i !== selectedLinkIndex);
          setLinks(newLinks);
          saveToHistory(nodes, newLinks);
          setSelectedLinkIndex(null);
      }
  }, [selectedId, selectedLinkIndex, selectedNodeIds, nodes, links, saveToHistory]);

  const handleCopy = useCallback(() => {
      const nodesToCopy = nodes.filter(n => selectedNodeIds.has(n.id) || n.id === selectedId);
      if (nodesToCopy.length > 0) {
          addToTransferStation(nodesToCopy);
      }
  }, [nodes, selectedNodeIds, selectedId, addToTransferStation]);

  const handlePaste = useCallback(() => {
      if (transferStation.length > 0) {
         const cx = (window.innerWidth / 2 - transform.x) / transform.k;
         const cy = (window.innerHeight / 2 - transform.y) / transform.k;

         const newNodes = [...nodes];
         transferStation.forEach((n: KnowledgeNode, idx: number) => {
             newNodes.push({
                 ...n,
                 id: `paste_${Date.now()}_${idx}`,
                 x: cx + (Math.random() - 0.5) * 50,
                 y: cy + (Math.random() - 0.5) * 50
             });
         });
         setNodes(newNodes);
         saveToHistory(newNodes, links);
      }
  }, [transferStation, transform, nodes, links, saveToHistory]);

  // KEYBOARD SHORTCUTS LISTENER
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;

        if (e.code === 'Space') {
             spacePressed.current = true;
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            setShowSaveModal(true);
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            handleUndo();
        }

        if (((e.ctrlKey || e.metaKey) && e.key === 'y') || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'z')) {
            e.preventDefault();
            handleRedo();
        }

        if (e.key === 'Delete' || e.key === 'Backspace') {
            e.preventDefault();
            handleDeleteSelected();
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
            e.preventDefault();
            handleCopy();
        }

        if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
             e.preventDefault();
             handlePaste();
        }

        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
            e.preventDefault();
            const step = e.shiftKey ? 10 : 2;
            const dx = e.key === 'ArrowLeft' ? -step : e.key === 'ArrowRight' ? step : 0;
            const dy = e.key === 'ArrowUp' ? -step : e.key === 'ArrowDown' ? step : 0;

            if (selectedNodeIds.size > 0 || selectedId) {
                setNodes((prev: KnowledgeNode[]) => prev.map(n => {
                    if (selectedNodeIds.has(n.id) || n.id === selectedId) {
                        return { ...n, x: (n.x||0) + dx, y: (n.y||0) + dy };
                    }
                    return n;
                }));
            }
        }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
        if (e.code === 'Space') {
             spacePressed.current = false;
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
    };
  }, [handleUndo, handleRedo, handleDeleteSelected, handleCopy, handlePaste, selectedNodeIds, selectedId]);


  // --- Interaction Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && spacePressed.current) {
       setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
       return;
    }

    if (e.buttons === 1 && (e.target as Element).tagName === 'svg' && (e.ctrlKey || e.metaKey)) {
        setInteractionState({ type: 'boxSelecting', startX: worldX, startY: worldY, currentX: worldX, currentY: worldY });
        return;
    }

    const clickedNode = [...nodes].reverse().find(n => {
       const dx = (n.x || 0) - worldX;
       const dy = (n.y || 0) - worldY;
       const r = n.category === 'root' ? 40 : 25; 
       return dx*dx + dy*dy <= r*r;
    });

    if (clickedNode) {
      e.stopPropagation();
      (e.target as Element).setPointerCapture(e.pointerId);

      // Link Mode Check
      if (e.shiftKey || isLinkingMode) {
          setInteractionState({
              type: 'creatingLink',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id,
              currentX: worldX, currentY: worldY
          });
      } else {
          if (!selectedNodeIds.has(clickedNode.id)) {
              if (e.ctrlKey) {
                  const newSet = new Set(selectedNodeIds);
                  newSet.add(clickedNode.id);
                  setSelectedNodeIds(newSet);
              } else {
                  setSelectedNodeIds(new Set([clickedNode.id]));
              }
              setSelectedId(clickedNode.id);
          }
          setIsPanelOpen(true);
          setInteractionState({
              type: 'draggingNode',
              startX: worldX, startY: worldY,
              targetId: clickedNode.id
          });
      }
    } else {
      if ((e.target as Element).tagName === 'svg' || (e.target as Element).id === 'bg-rect') {
          if (!e.ctrlKey) {
             setInteractionState({ type: 'panning', startX: clientX, startY: clientY });
             setSelectedId(null);
             setSelectedLinkIndex(null);
             setSelectedNodeIds(new Set());
          }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'panning') {
        const dx = clientX - interactionState.startX;
        const dy = clientY - interactionState.startY;
        setTransform(t => ({ ...t, x: t.x + dx, y: t.y + dy }));
        setInteractionState(prev => ({ ...prev, startX: clientX, startY: clientY }));
    } 
    else if (interactionState.type === 'draggingNode') {
        const dx = worldX - interactionState.startX;
        const dy = worldY - interactionState.startY;
        setNodes(prev => prev.map(n => {
             if (selectedNodeIds.has(n.id) || n.id === interactionState.targetId) {
                return { ...n, x: (n.x || 0) + dx, y: (n.y || 0) + dy };
             }
             return n;
        }));
        setInteractionState(prev => ({ ...prev, startX: worldX, startY: worldY }));
    }
    else if (interactionState.type === 'creatingLink') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
    else if (interactionState.type === 'boxSelecting') {
        setInteractionState(prev => ({ ...prev, currentX: worldX, currentY: worldY }));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    const { clientX, clientY } = e;
    const { x: worldX, y: worldY } = toWorld(clientX, clientY);

    if (interactionState.type === 'creatingLink' && interactionState.targetId) {
        const targetNode = nodes.find(n => {
            const dx = (n.x || 0) - worldX;
            const dy = (n.y || 0) - worldY;
            return dx*dx + dy*dy <= 30*30 && n.id !== interactionState.targetId;
        });

        if (targetNode) {
            const exists = links.some(l => 
                (l.source === interactionState.targetId && l.target === targetNode.id) ||
                (l.target === interactionState.targetId && l.source === targetNode.id)
            );
            if (!exists) {
                const newLinks = [...links, { source: interactionState.targetId!, target: targetNode.id, strength: 1 }];
                setLinks(newLinks);
                saveToHistory(nodes, newLinks);
            }
        }
    } else if (interactionState.type === 'draggingNode') {
        saveToHistory(nodes, links);
    } else if (interactionState.type === 'boxSelecting') {
        const x1 = Math.min(interactionState.startX, interactionState.currentX!);
        const x2 = Math.max(interactionState.startX, interactionState.currentX!);
        const y1 = Math.min(interactionState.startY, interactionState.currentY!);
        const y2 = Math.max(interactionState.startY, interactionState.currentY!);

        const newSelection = new Set<string>();
        nodes.forEach(n => {
            if (n.x && n.y && n.x >= x1 && n.x <= x2 && n.y >= y1 && n.y <= y2) {
                newSelection.add(n.id);
            }
        });
        setSelectedNodeIds(newSelection);
        if (newSelection.size > 0) setIsPanelOpen(true);
    }

    setInteractionState({ type: 'idle', startX: 0, startY: 0 });
    try { (e.target as Element).releasePointerCapture(e.pointerId); } catch {}
  };

  const handleWheel = (e: React.WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const scaleAmount = -e.deltaY * 0.001;
        setTransform(t => ({
            ...t,
            k: Math.max(0.1, Math.min(5, t.k + scaleAmount))
        }));
    } else {
        setTransform(t => ({ ...t, x: t.x - e.deltaX, y: t.y - e.deltaY }));
    }
  };

  const handleDoubleClickBg = (e: React.MouseEvent) => {
      const { x, y } = toWorld(e.clientX, e.clientY);
      const newId = `node_${Date.now()}`;
      const newNode: KnowledgeNode = {
          id: newId,
          label: '新知识点',
          category: 'sub',
          masteryLevel: 50,
          isGhost: false,
          x, y
      };
      const newNodes = [...nodes, newNode];
      setNodes(newNodes);
      saveToHistory(newNodes, links);
      setSelectedId(newId);
      setIsPanelOpen(true);
  };

  const handleNodeDoubleClick = (e: React.MouseEvent, node: KnowledgeNode) => {
      e.stopPropagation();
      navigate(`/knowledge-graph/node/${node.id}`, { state: { node } });
  };

  const handleLinkClick = (e: React.MouseEvent, index: number) => {
      e.stopPropagation();
      setSelectedLinkIndex(index);
      setSelectedId(null);
      setIsPanelOpen(true);
  };

  const handleGenerate = async () => {
    // ... (Generate Logic kept same)
    // For brevity, assuming existing handleGenerate logic remains
    handleAnalyze();
  };

  const handleAnalyze = async (manualInput?: string) => {
    // ... (Analysis Logic kept same)
    // For brevity, assuming existing handleAnalyze logic remains
  };

  // ... (Other handlers like handleSaveGraph, handleAddToTransfer, handleDropFromTransfer, etc. remain the same)

  // Layout & Radar effects remain same ...

  const LayoutButton = ({ type, icon, label }: { type: LayoutType, icon: string, label: string }) => (
    <button onClick={() => {/*...*/}} className={`flex flex-col items-center justify-center p-2 rounded-lg transition-all ${layout === type ? 'bg-kg-primary text-white shadow-lg scale-105' : 'text-kg-text hover:bg-kg-card/50'}`} title={label}>
      <i className={`fas ${icon} text-lg mb-1`}></i>
      <span className="text-[9px] uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col h-screen bg-kg-bg text-kg-text font-sans transition-colors duration-300 overflow-hidden relative selection:bg-kg-primary selection:text-white">
      {/* ... (Existing Camera/Input modals) ... */}
      {showCamera && <CameraModal onCapture={(file) => setInput(p => p + `\n[图片] ${file.name}`)} onClose={() => setShowCamera(false)} />}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => setInput(p => p + `\n[文件] ${e.target.files?.[0]?.name}`)} />

      {/* Header Overlay */}
      <div className="absolute top-0 left-0 w-full px-4 py-3 flex justify-between items-center z-30 pointer-events-none">
        {/* ... (Existing Header content) ... */}
        <div className="flex items-center gap-3 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-4 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm min-w-0">
          <Link to="/" className="w-8 h-8 flex-shrink-0 flex items-center justify-center text-kg-primary hover:text-kg-text transition-colors rounded-full hover:bg-kg-bg">
            <i className="fas fa-arrow-left"></i>
          </Link>
          <h1 className="text-base font-bold tracking-wide truncate">灵境 <span className="text-kg-primary font-light hidden sm:inline">| 知识图谱</span></h1>

          {/* Link Mode Toggle for Touch Users */}
          <button 
            onClick={() => setIsLinkingMode(!isLinkingMode)}
            className={`ml-2 px-2 py-1 rounded text-xs border transition-colors ${isLinkingMode ? 'bg-kg-primary text-white border-kg-primary' : 'bg-transparent text-kg-text border-gray-300'}`}
          >
            <i className="fas fa-link mr-1"></i> {isLinkingMode ? '连线中' : '连线模式'}
          </button>
        </div>
        <div className="flex items-center gap-2 pointer-events-auto bg-kg-card/90 backdrop-blur-md px-3 py-2 rounded-full border border-gray-200 dark:border-gray-700 shadow-sm flex-shrink-0">
           <SystemStatus />
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="w-8 h-8 flex items-center justify-center text-kg-primary hover:bg-kg-bg rounded-full">
              <i className="fas fa-bars"></i>
          </button>
          <UserAuth themeColorClass="text-kg-primary" />
        </div>
      </div>

      {/* Main Canvas Area (SVG) ... (Keep existing SVG rendering logic) ... */}
      <div ref={containerRef} className="absolute inset-0 z-0 cursor-default touch-none bg-kg-bg outline-none" tabIndex={0} onWheel={handleWheel} onPointerDown={handlePointerDown} onPointerMove={handlePointerMove} onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp} onDoubleClick={handleDoubleClickBg}>
          <svg className="w-full h-full overflow-visible" id="bg-rect">
            {/* ... Defs ... */}
            <defs>
                <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse" x={transform.x % 40} y={transform.y % 40}>
                   <circle cx="1" cy="1" r="1" fill="var(--kg-line)" fillOpacity="0.4" />
                </pattern>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="28" refY="3.5" orient="auto">
                  <polygon points="0 0, 10 3.5, 0 7" fill="var(--kg-line)" opacity="0.6" />
                </marker>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="url(#grid)" className="pointer-events-none" />
            <g transform={`translate(${transform.x}, ${transform.y}) scale(${transform.k})`}>
                {links.map((link, i) => {
                    const src = nodes.find(n => n.id === link.source);
                    const tgt = nodes.find(n => n.id === link.target);
                    if (!src || !tgt) return null;
                    const isSelected = selectedLinkIndex === i;
                    const isGhostLink = src.isGhost || tgt.isGhost;
                    return (
                        <g key={i} onClick={(e) => handleLinkClick(e, i)} className="cursor-pointer group">
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke="transparent" strokeWidth="15" />
                             <line x1={src.x} y1={src.y} x2={tgt.x} y2={tgt.y} stroke={isSelected ? 'var(--kg-secondary)' : 'var(--kg-line)'} strokeWidth={isSelected ? 3 : 1.5} strokeOpacity={isSelected ? 1 : 0.6} strokeDasharray={isGhostLink ? "5,5" : "0"} markerEnd={isGhostLink ? "" : "url(#arrowhead)"} />
                        </g>
                    );
                })}
                {interactionState.type === 'creatingLink' && (<line x1={interactionState.startX} y1={interactionState.startY} x2={interactionState.currentX} y2={interactionState.currentY} stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="5,5" />)}

                {/* Box Selection Rect */}
                {interactionState.type === 'boxSelecting' && (<rect x={Math.min(interactionState.startX, interactionState.currentX!)} y={Math.min(interactionState.startY, interactionState.currentY!)} width={Math.abs(interactionState.currentX! - interactionState.startX)} height={Math.abs(interactionState.currentY! - interactionState.startY)} fill="var(--kg-primary)" fillOpacity="0.1" stroke="var(--kg-primary)" strokeDasharray="4,2" className="pointer-events-none" />)}

                {nodes.map((node) => {
                    // ... (Existing Node Rendering) ...
                    const isSelected = selectedId === node.id || selectedNodeIds.has(node.id);
                    const baseR = node.category === 'root' ? 35 : node.category === 'core' ? 25 : 15;
                    const r = isSelected ? baseR * 1.1 : baseR;
                    const color = node.masteryLevel < 50 ? '#f43f5e' : node.masteryLevel < 80 ? '#f59e0b' : '#10b981';
                    return (
                        <g key={node.id} transform={`translate(${node.x},${node.y})`} onDoubleClick={(e) => handleNodeDoubleClick(e, node)} className="cursor-pointer transition-all duration-300">
                            {isSelected && <circle r={r + 6} fill="none" stroke="var(--kg-primary)" strokeWidth="2" strokeDasharray="4,2" className="animate-spin-slow" />}
                            <circle r={r} fill={node.isGhost ? 'transparent' : color} stroke={node.isGhost ? 'var(--kg-text)' : 'var(--kg-bg)'} strokeWidth={node.isGhost ? 1 : 3} strokeDasharray={node.isGhost ? "4,2" : "0"} className={node.isGhost ? "" : "shadow-sm"} />
                            <rect x={-node.label.length * 6} y={r + 8} width={node.label.length * 12} height="20" rx="4" fill="var(--kg-bg)" fillOpacity="0.8" className="pointer-events-none" />
                            <text y={r + 22} textAnchor="middle" fontSize="12" fontWeight="bold" fill="var(--kg-text)" className="pointer-events-none select-none" style={{ textShadow: '0 1px 2px rgba(255,255,255,0.5)' }}>{node.label}</text>
                            {(isSelected && !node.isGhost) && (<text y={5} textAnchor="middle" fontSize="10" fill="#fff" fontWeight="bold" className="pointer-events-none">{node.masteryLevel}%</text>)}
                            {node.isGhost && (<text y={5} textAnchor="middle" fontSize="10" fill="var(--kg-text)" fontWeight="bold" className="pointer-events-none">+</text>)}
                        </g>
                    );
                })}
            </g>
          </svg>
      </div>

      <div className={`fixed top-0 right-0 h-full w-80 bg-kg-card/95 backdrop-blur-xl border-l border-gray-200 dark:border-gray-700 shadow-2xl z-20 transform transition-transform duration-300 ease-in-out ${isPanelOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <button onClick={() => setIsPanelOpen(!isPanelOpen)} className="absolute left-0 top-24 -translate-x-full bg-kg-card border border-r-0 border-gray-200 dark:border-gray-700 rounded-l-lg p-2 shadow-lg text-kg-primary"><i className={`fas fa-chevron-${isPanelOpen ? 'right' : 'left'}`}></i></button>

          <div className="p-6 h-full flex flex-col pt-20 overflow-y-auto">
              <h2 className="text-lg font-bold mb-4 flex justify-between items-center">
                  <span>数据控制台</span>
                  <button onClick={()=>setShowSaveModal(true)} className="text-xs text-kg-primary bg-kg-bg px-2 py-1 rounded hover:bg-kg-primary hover:text-white transition-colors"><i className="fas fa-save mr-1"></i> 保存</button>
              </h2>

              {selectedNodeIds.size > 0 && (
                  <div className="mb-6 p-4 bg-kg-bg rounded border border-kg-primary/20 animate-[fadeIn_0.2s]">
                      {/* ... (Existing Batch Actions) ... */}
                      <h3 className="text-sm font-bold text-kg-primary mb-2">已选节点: {selectedNodeIds.size}</h3>
                      <button onClick={handleCopy} className="w-full text-xs text-purple-500 border border-purple-200 rounded py-1 hover:bg-purple-50 mb-2"><i className="fas fa-archive mr-1"></i> 复制到中转站</button>
                      <button onClick={handleDeleteSelected} className="w-full text-xs text-red-500 border border-red-200 rounded py-1 hover:bg-red-50">删除所选</button>
                  </div>
              )}

              {/* Selected Node Edit (Enhanced with Slider) */}
              {selectedId && !selectedNodeIds.has(selectedId) && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">节点编辑</span></div>
                      {nodes.find(n => n.id === selectedId) && (
                          <div className="space-y-4">
                              <div>
                                  <label className="text-xs text-kg-text opacity-60">名称</label>
                                  <input className="w-full bg-kg-bg border border-kg-primary/20 rounded p-2 text-sm mt-1 focus:border-kg-primary outline-none" value={nodes.find(n => n.id === selectedId)?.label} onChange={(e) => { const val = e.target.value; setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, label: val } : n)); }} onBlur={() => saveToHistory(nodes, links)} />
                              </div>

                              {/* Mastery Slider */}
                              <div>
                                  <label className="text-xs text-kg-text opacity-60 flex justify-between">
                                      <span>掌握度</span>
                                      <span className="font-bold text-kg-primary">{nodes.find(n => n.id === selectedId)?.masteryLevel}%</span>
                                  </label>
                                  <input 
                                    type="range" 
                                    min="0" 
                                    max="100" 
                                    value={nodes.find(n => n.id === selectedId)?.masteryLevel} 
                                    onChange={(e) => { 
                                        const val = Number(e.target.value); 
                                        setNodes(prev => prev.map(n => n.id === selectedId ? { ...n, masteryLevel: val } : n)); 
                                    }} 
                                    onMouseUp={() => saveToHistory(nodes, links)}
                                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer mt-2 accent-kg-primary"
                                  />
                              </div>

                              <button onClick={handleDeleteSelected} className="px-4 py-2 bg-red-50 text-red-500 rounded text-sm hover:bg-red-100 transition-colors w-full"><i className="fas fa-trash"></i> 删除</button>
                          </div>
                      )}
                  </div>
              )}

              {/* Selected Link Edit */}
              {selectedLinkIndex !== null && (
                  <div className="space-y-4 animate-[fadeInUp_0.3s_ease-out]">
                      <div className="border-b border-kg-primary/10 pb-2 mb-2"><span className="text-xs font-bold text-kg-primary uppercase">连接编辑</span></div>
                      <div className="p-4 bg-kg-bg rounded border border-gray-200 dark:border-gray-700">
                          <p className="text-xs mb-3 text-center opacity-60">连接强度: {links[selectedLinkIndex]?.strength}</p>
                          <button onClick={handleDeleteSelected} className="w-full py-2 bg-red-50 text-red-500 rounded text-xs hover:bg-red-100"><i className="fas fa-unlink mr-1"></i> 断开连接</button>
                      </div>
                  </div>
              )}

              {/* ... (Existing Transfer Station & Default Views) ... */}
              {!selectedId && selectedLinkIndex === null && selectedNodeIds.size === 0 && (
                  <div className="space-y-6">
                      <div className="bg-kg-bg p-4 rounded-xl text-center border border-gray-100 dark:border-gray-700 shadow-inner">
                          <div className="text-sm font-bold text-kg-primary mb-2">综合能力雷达</div>
                          <div className="w-32 h-32 mx-auto">{/* ... renderRadar() call ... */}</div>
                      </div>

                      <div className="flex-grow">
                           <div className="text-xs uppercase tracking-wider text-kg-text opacity-50 mb-2 font-bold">AI 辅助生成</div>
                           <textarea value={input} onChange={e=>setInput(e.target.value)} placeholder="输入主题或留空使用预设..." className="w-full bg-kg-bg p-3 rounded-lg mb-2 text-sm border border-gray-200 dark:border-gray-700 h-24 focus:border-kg-primary outline-none resize-none" />
                           <div className="flex gap-2">
                               <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-folder-open"></i></button>
                               <button onClick={() => setShowCamera(true)} className="p-2 bg-kg-bg rounded border border-gray-200 dark:border-gray-700 hover:text-kg-primary"><i className="fas fa-camera"></i></button>
                               <button onClick={() => handleGenerate()} disabled={isAnalyzing} className="flex-1 bg-kg-primary text-white py-2 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all">
                                   {isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : (input.trim() ? 'AI生成图谱' : '一键生成预设')}
                               </button>
                           </div>
                      </div>
                  </div>
              )}
          </div>
      </div>

      {/* ... (Existing Save Modal) ... */}
    </div>
  );
};

